insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(5758, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The kidneys are typically located at approximately which vertebral level?', '["T12 to L3", "L1 to L5", "T6 to T10", "S1 to S3"]'::jsonb, 0, 'The kidneys are retroperitoneal organs extending roughly from T12 to L3, with the right kidney lying slightly lower than the left.', 'Pre-Council', '🎓', true),
(5759, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Why does the right kidney typically lie slightly lower than the left kidney?', '["Because the liver occupies space above it", "Because the spleen displaces it downward", "Because the pancreas sits directly on it", "Because its renal artery is longer"]'::jsonb, 0, 'The bulk of the liver in the right upper quadrant pushes the right kidney into a slightly lower position than the left.', 'Pre-Council', '🎓', true),
(5760, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which layer of renal supportive tissue lies immediately external to the fibrous capsule of the kidney?', '["Perirenal (perinephric) fat", "Renal fascia (Gerota''s fascia)", "Pararenal (paranephric) fat", "Parietal peritoneum"]'::jsonb, 0, 'From innermost to outermost the kidney is surrounded by the fibrous capsule, perirenal fat, renal fascia, and finally pararenal fat.', 'Pre-Council', '🎓', true),
(5761, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'At the renal hilum, which structure is typically found in the most posterior position?', '["Renal pelvis and ureter", "Renal vein", "Renal artery", "Renal lymphatic vessels"]'::jsonb, 0, 'The usual anteroposterior order at the hilum is renal vein, then renal artery, then renal pelvis/ureter (mnemonic VAP/VAU).', 'Pre-Council', '🎓', true),
(5762, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The renal cortex characteristically contains which structure?', '["Renal corpuscles (glomeruli)", "Renal pyramids", "Minor calyces", "Renal papillae"]'::jsonb, 0, 'Glomeruli and convoluted tubules lie in the cortex, while pyramids, papillae, and calyces belong to the medulla and collecting system.', 'Pre-Council', '🎓', true),
(5763, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The apex of a renal pyramid, which projects into a minor calyx, is called the:', '["Renal papilla", "Renal column", "Renal hilum", "Renal sinus"]'::jsonb, 0, 'The papilla is the tip of a medullary pyramid where collecting ducts (ducts of Bellini) empty urine into a minor calyx.', 'Pre-Council', '🎓', true),
(5764, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The columns of Bertin are best described as:', '["Cortical tissue extending inward between adjacent renal pyramids", "Medullary tissue extending outward into the cortex", "Fibrous septa separating the kidney into two halves", "Vascular channels found only within the renal sinus"]'::jsonb, 0, 'Renal columns are inward extensions of cortical tissue that separate and support the renal pyramids.', 'Pre-Council', '🎓', true),
(5765, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A renal lobe is anatomically defined as:', '["A renal pyramid together with its overlying cortex", "A single nephron together with its vasa recta", "The fat-filled renal sinus", "The trigone of the renal pelvis"]'::jsonb, 0, 'Each renal lobe corresponds to one medullary pyramid plus the cortical tissue directly overlying it.', 'Pre-Council', '🎓', true),
(5766, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Urine passes through the renal collecting system in which correct sequence?', '["Minor calyx, major calyx, renal pelvis, ureter", "Major calyx, minor calyx, renal pelvis, ureter", "Renal pelvis, major calyx, minor calyx, ureter", "Minor calyx, renal pelvis, major calyx, ureter"]'::jsonb, 0, 'Urine drains from the papilla into a minor calyx, several minor calyces join to form a major calyx, major calyces converge into the renal pelvis, which narrows into the ureter.', 'Pre-Council', '🎓', true),
(5767, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The renal artery arises directly from which vessel, and at approximately what vertebral level?', '["The abdominal aorta, near L1-L2", "The abdominal aorta, near T12", "The common iliac artery, near L4", "The superior mesenteric artery, near L1"]'::jsonb, 0, 'Renal arteries branch directly off the abdominal aorta just below the origin of the superior mesenteric artery, at approximately L1-L2.', 'Pre-Council', '🎓', true),
(5768, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Within the kidney, arterial blood flows through which correct sequence of vessels before reaching the glomerulus?', '["Segmental, interlobar, arcuate, interlobular (cortical radiate), afferent arteriole", "Interlobar, segmental, interlobular, arcuate, afferent arteriole", "Arcuate, interlobar, segmental, interlobular, afferent arteriole", "Interlobular, arcuate, interlobar, segmental, afferent arteriole"]'::jsonb, 0, 'The intrarenal arterial tree branches in the order segmental to interlobar to arcuate to interlobular (cortical radiate) arteries, which give rise to the afferent arterioles.', 'Pre-Council', '🎓', true),
(5769, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Compared with the right renal vein, the left renal vein is:', '["Longer, and passes anterior to the abdominal aorta", "Shorter, and passes posterior to the aorta", "Identical in length and drains directly into the right atrium", "Absent, since the left kidney drains solely via the azygos vein"]'::jsonb, 0, 'The left renal vein is longer than the right, crosses anterior to the aorta, and receives the left gonadal and left suprarenal veins before entering the inferior vena cava.', 'Pre-Council', '🎓', true),
(5770, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Sympathetic innervation of the kidney arises predominantly from which spinal segments?', '["T10 to L1", "C3 to C5", "S2 to S4", "T1 to T4"]'::jsonb, 0, 'Renal sympathetic fibers originate mainly from the T10-L1 spinal segments and travel via the splanchnic nerves to the renal plexus.', 'Pre-Council', '🎓', true),
(5771, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Approximately how much does each normal adult kidney weigh?', '["About 120-170 g", "About 500 g", "About 20 g", "About 1 kg"]'::jsonb, 0, 'A normal adult kidney weighs roughly 120-170 g, is about 11 cm long, 6 cm wide, and 3 cm thick.', 'Pre-Council', '🎓', true),
(5772, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Structures anteriorly related to the right kidney typically include the:', '["Liver, second part of the duodenum, and hepatic flexure of the colon", "Spleen, stomach, and tail of the pancreas", "Urinary bladder and rectum", "Diaphragm and parietal pleura only"]'::jsonb, 0, 'The right kidney is related anteriorly to the liver, duodenum, and hepatic flexure; the left kidney relates instead to the spleen, stomach, and pancreas.', 'Pre-Council', '🎓', true),
(5773, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'As the ureter descends into the pelvis, it characteristically crosses anterior to the:', '["Bifurcation of the common iliac artery", "Inferior vena cava", "Superior mesenteric artery", "Psoas minor muscle"]'::jsonb, 0, 'The ureter crosses the pelvic brim by passing anterior to the bifurcation of the common iliac artery into external and internal branches.', 'Pre-Council', '🎓', true),
(5774, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The renal sinus is best described as:', '["A fat-filled space containing the renal pelvis, calyces, and renal vessels", "The outermost fibrous covering of the kidney", "A groove on the lateral border of the kidney", "A synonym for the renal cortex"]'::jsonb, 0, 'The renal sinus is an internal cavity, filled with fat, that houses the renal pelvis, major and minor calyces, and the renal blood vessels.', 'Pre-Council', '🎓', true),
(5775, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which layer of the ureter''s wall is chiefly responsible for the peristaltic contractions that propel urine toward the bladder?', '["Muscularis (smooth muscle layers)", "Mucosa (transitional epithelium)", "Adventitia", "Submucosa"]'::jsonb, 0, 'Smooth muscle in the muscularis layer of the ureter generates peristaltic waves that move urine from the renal pelvis to the bladder.', 'Pre-Council', '🎓', true),
(5776, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The adrenal (suprarenal) glands are positioned:', '["Atop the superior pole of each kidney, enclosed within the renal fascia", "Embedded within the renal cortex itself", "Inferior to the kidney, near the ureterovesical junction", "Within the renal sinus alongside the renal pelvis"]'::jsonb, 0, 'Each adrenal gland caps the superior pole of its corresponding kidney and shares the enclosing renal fascia, though it is a separate organ.', 'Pre-Council', '🎓', true),
(5777, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'During quiet respiration, the kidneys normally:', '["Move up and down approximately 2-3 cm with diaphragmatic excursion", "Remain completely immobile because of the renal fascia", "Rotate 90 degrees about their vertical axis", "Move only during forced expiration, never during inspiration"]'::jsonb, 0, 'Because the diaphragm is closely related to the superior poles, the kidneys normally descend and ascend a few centimeters with each respiratory cycle.', 'Pre-Council', '🎓', true),
(5778, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The kidneys are classified as retroperitoneal organs because they:', '["Lie behind the parietal peritoneum rather than within the peritoneal cavity", "Are suspended by a mesentery inside the peritoneal cavity", "Float freely within the peritoneal cavity", "Lie entirely anterior to the peritoneum, outside the abdomen"]'::jsonb, 0, 'Retroperitoneal organs, including the kidneys, are situated behind the parietal peritoneum rather than being suspended within the peritoneal cavity by a mesentery.', 'Pre-Council', '🎓', true),
(5779, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A duplicated or accessory renal artery, a fairly common anatomical variant, is most clinically significant during which procedure?', '["Living-donor nephrectomy or renal transplantation", "Percutaneous coronary intervention", "Lumbar puncture", "Thoracentesis"]'::jsonb, 0, 'Accessory renal arteries supply separate segments of the kidney and must be identified and preserved or reconstructed during transplant or renal vascular surgery.', 'Pre-Council', '🎓', true),
(5780, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Approximately how many nephrons are present in each normal adult kidney?', '["About 1 million", "About 10,000", "About 100 million", "About 50,000"]'::jsonb, 0, 'Each adult kidney contains roughly one million nephrons, the functional units responsible for urine formation.', 'Pre-Council', '🎓', true),
(5781, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The renal corpuscle is composed of the glomerulus together with the:', '["Bowman''s (glomerular) capsule", "Loop of Henle", "Proximal convoluted tubule", "Collecting duct"]'::jsonb, 0, 'The renal corpuscle consists of the glomerular capillary tuft enclosed within Bowman''s capsule, where initial filtration occurs.', 'Pre-Council', '🎓', true),
(5782, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Juxtamedullary nephrons differ from cortical nephrons chiefly in that they possess:', '["Long loops of Henle that extend deep into the medulla, important for concentrating urine", "Short loops of Henle confined entirely to the cortex", "No loop of Henle whatsoever", "Glomeruli located exclusively within the medulla"]'::jsonb, 0, 'Juxtamedullary nephrons, about 15% of all nephrons, have long loops of Henle that penetrate deep into the medulla and are essential for generating the medullary osmotic gradient.', 'Pre-Council', '🎓', true),
(5783, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Approximately what proportion of nephrons are cortical nephrons, as opposed to juxtamedullary nephrons?', '["About 85%", "About 15%", "About 50%", "Nearly 100%"]'::jsonb, 0, 'Roughly 85% of nephrons are cortical nephrons with short loops of Henle confined mostly to the cortex and outer medulla.', 'Pre-Council', '🎓', true),
(5784, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The visceral layer of Bowman''s capsule is composed of specialized cells called:', '["Podocytes", "Mesangial cells", "Principal cells", "Intercalated cells"]'::jsonb, 0, 'Podocytes form the visceral layer of Bowman''s capsule; their interdigitating foot processes wrap around glomerular capillaries.', 'Pre-Council', '🎓', true),
(5785, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The filtration slits between adjacent podocyte foot processes (pedicels) are bridged by a thin protein structure known as the:', '["Slit diaphragm", "Glomerular basement membrane", "Brush border", "Tight junction"]'::jsonb, 0, 'The slit diaphragm is a specialized protein structure spanning the filtration slits between podocyte foot processes, forming part of the filtration barrier.', 'Pre-Council', '🎓', true),
(5786, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The glomerular filtration barrier consists of, in order from blood to urinary space:', '["Fenestrated capillary endothelium, glomerular basement membrane, and podocyte filtration slits", "Simple squamous epithelium, tight junctions, and a brush border", "Mesangium, macula densa, and principal cells", "Podocyte foot processes and endothelium only, with no basement membrane"]'::jsonb, 0, 'Filtration occurs across three layers: the fenestrated endothelium, the glomerular basement membrane, and the podocyte filtration slits.', 'Pre-Council', '🎓', true),
(5787, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The strongly negative charge of the glomerular basement membrane, rich in heparan sulfate proteoglycans, functions mainly to:', '["Repel negatively charged plasma proteins such as albumin, limiting their filtration", "Attract positively charged solutes for active reabsorption", "Anchor the brush border of the proximal tubule", "Generate the osmotic gradient of the renal medulla"]'::jsonb, 0, 'Because most plasma proteins, including albumin, carry a net negative charge, the negatively charged basement membrane electrostatically restricts their filtration.', 'Pre-Council', '🎓', true),
(5788, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Mesangial cells located between glomerular capillary loops perform which function?', '["Provide structural support, phagocytose trapped debris, and can contract to influence the filtering surface area", "Secrete renin in response to reduced renal perfusion pressure", "Actively transport glucose out of the tubular filtrate", "Form the slit diaphragm together with podocytes"]'::jsonb, 0, 'Mesangial cells are contractile, phagocytic support cells within the glomerulus that help regulate the glomerular capillary surface area available for filtration.', 'Pre-Council', '🎓', true),
(5789, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cells of the juxtaglomerular apparatus are the primary source of renin?', '["Juxtaglomerular (granular) cells of the afferent arteriole", "Macula densa cells of the distal tubule", "Podocytes of Bowman''s capsule", "Principal cells of the collecting duct"]'::jsonb, 0, 'Renin is synthesized and released by specialized granular juxtaglomerular cells located in the wall of the afferent arteriole.', 'Pre-Council', '🎓', true),
(5790, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The macula densa, part of the juxtaglomerular apparatus, primarily functions to:', '["Sense NaCl concentration in the distal tubular fluid and mediate tubuloglomerular feedback", "Reabsorb the bulk of filtered glucose", "Secrete erythropoietin in response to hypoxia", "Generate the countercurrent gradient in the vasa recta"]'::jsonb, 0, 'Macula densa cells detect changes in luminal NaCl concentration at the end of the thick ascending limb and signal the afferent arteriole to adjust GFR (tubuloglomerular feedback).', 'Pre-Council', '🎓', true),
(5791, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The proximal convoluted tubule is lined by simple cuboidal epithelium with a prominent apical brush border, which functions to:', '["Increase surface area for bulk reabsorption of filtrate", "Secrete protective mucus into the tubular lumen", "Generate peristaltic contractions of the tubule", "Form tight junctions that render the segment impermeable to water"]'::jsonb, 0, 'The extensive microvillous brush border of proximal tubule cells greatly increases the luminal surface area available for reabsorbing filtered solutes and water.', 'Pre-Council', '🎓', true),
(5792, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Approximately what percentage of the glomerular filtrate is reabsorbed in the proximal convoluted tubule under normal conditions?', '["About 65%", "About 10%", "About 90%", "About 25%"]'::jsonb, 0, 'The proximal convoluted tubule reabsorbs roughly two-thirds (about 65%) of the filtered water, sodium, and other solutes.', 'Pre-Council', '🎓', true),
(5793, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The thin descending limb of the loop of Henle is characterized by:', '["High permeability to water but low permeability to solutes", "Low permeability to water combined with active NaCl reabsorption", "Aldosterone-sensitive sodium reabsorption", "Presence of principal and intercalated cells"]'::jsonb, 0, 'The descending limb is water-permeable but relatively solute-impermeable, allowing water to leave passively so the filtrate becomes progressively more concentrated as it descends.', 'Pre-Council', '🎓', true),
(5794, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The thick ascending limb of the loop of Henle actively reabsorbs sodium, potassium, and chloride via which transporter, the target of loop diuretics?', '["Na+-K+-2Cl- cotransporter (NKCC2)", "Na+-Cl- cotransporter (NCC)", "Epithelial sodium channel (ENaC)", "Sodium-glucose cotransporter (SGLT2)"]'::jsonb, 0, 'NKCC2 on the apical membrane of thick ascending limb cells reabsorbs sodium, potassium, and chloride and is the site of action of loop diuretics such as furosemide.', 'Pre-Council', '🎓', true),
(5795, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A defining physiological feature of the thick ascending limb of the loop of Henle is that it is:', '["Essentially impermeable to water while actively transporting solutes out of the lumen", "Freely permeable to water and impermeable to solutes", "The main site of ADH action in the nephron", "The main site of erythropoietin production"]'::jsonb, 0, 'The thick ascending limb actively pumps NaCl out of the tubular fluid but remains impermeable to water, diluting the luminal fluid and contributing solute to the medullary interstitium.', 'Pre-Council', '🎓', true),
(5796, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The distal convoluted tubule differs histologically from the proximal convoluted tubule in that it:', '["Lacks a prominent brush border and has a narrower lumen", "Has an even more prominent brush border", "Contains no mitochondria", "Is lined by transitional epithelium"]'::jsonb, 0, 'Distal convoluted tubule cells are simple cuboidal but lack the extensive brush border seen in the proximal tubule, and the lumen appears relatively narrow and clear on histology.', 'Pre-Council', '🎓', true),
(5797, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In the distal convoluted tubule, reabsorption of which ion is significantly increased under the influence of parathyroid hormone (PTH)?', '["Calcium", "Potassium", "Phosphate", "Urea"]'::jsonb, 0, 'PTH increases active calcium reabsorption in the distal convoluted tubule (via TRPV5 channels) while decreasing phosphate reabsorption in the proximal tubule.', 'Pre-Council', '🎓', true),
(5798, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Collecting duct principal cells primarily regulate reabsorption of which two substances?', '["Sodium and water", "Hydrogen ions and bicarbonate", "Glucose and amino acids", "Urea and creatinine exclusively"]'::jsonb, 0, 'Principal cells reabsorb sodium via ENaC channels (under aldosterone control) and water via aquaporin-2 channels (under ADH control).', 'Pre-Council', '🎓', true),
(5799, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Type A (alpha) intercalated cells of the collecting duct primarily function to:', '["Secrete hydrogen ions and reabsorb bicarbonate, becoming especially active during acidosis", "Secrete bicarbonate and reabsorb hydrogen ions", "Reabsorb sodium under aldosterone control", "Respond to ADH by inserting aquaporin-2 channels"]'::jsonb, 0, 'Type A intercalated cells pump H+ into the tubular lumen via an apical H+-ATPase and return newly generated bicarbonate to the blood, a process upregulated during acidosis.', 'Pre-Council', '🎓', true),
(5800, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Type B (beta) intercalated cells of the collecting duct become especially active during:', '["Metabolic alkalosis, secreting bicarbonate via the pendrin transporter", "Metabolic acidosis, secreting hydrogen ions", "Volume depletion, reabsorbing sodium", "Hypoxia, secreting erythropoietin"]'::jsonb, 0, 'Type B intercalated cells secrete bicarbonate into the tubular lumen via the pendrin exchanger, a response that increases during alkalosis to help lower plasma pH toward normal.', 'Pre-Council', '🎓', true),
(5801, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The efferent arteriole, in contrast to the afferent arteriole, is characterized by:', '["A smaller diameter, creating resistance that helps maintain glomerular capillary hydrostatic pressure", "A larger diameter and lower resistance than the afferent arteriole", "Direct, unbranched continuity with the renal vein", "Absence of smooth muscle in its wall"]'::jsonb, 0, 'The efferent arteriole is narrower than the afferent arteriole, and its resistance helps sustain the relatively high hydrostatic pressure needed for glomerular filtration.', 'Pre-Council', '🎓', true),
(5802, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The vasa recta are best described as:', '["Peritubular capillaries that run parallel to the loops of Henle of juxtamedullary nephrons, forming hairpin loops", "Lymphatic vessels that drain the renal cortex", "Arterioles supplying blood exclusively to the glomerulus", "Venous channels found only in the renal cortex"]'::jsonb, 0, 'Vasa recta are specialized peritubular capillaries that descend and ascend alongside the loops of Henle of juxtamedullary nephrons, helping preserve the medullary osmotic gradient.', 'Pre-Council', '🎓', true),
(5803, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A nurse reviewing a patient''s furosemide (a loop diuretic) therapy should understand that its site of action corresponds anatomically to the:', '["Thick ascending limb of the loop of Henle", "Proximal convoluted tubule", "Distal convoluted tubule", "Collecting duct principal cells"]'::jsonb, 0, 'Furosemide blocks the NKCC2 cotransporter located on cells of the thick ascending limb of the loop of Henle, producing a potent diuresis.', 'Pre-Council', '🎓', true),
(5804, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The urinary bladder is located:', '["In the pelvic cavity, posterior to the pubic symphysis", "In the abdominal cavity, superior to the kidneys", "Within the retroperitoneal space at the level of L1", "Anterior to the pubic symphysis, outside the pelvic cavity"]'::jsonb, 0, 'The empty bladder lies within the true pelvis, directly posterior to the pubic symphysis.', 'Pre-Council', '🎓', true),
(5805, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The smooth, triangular area on the posterior wall of the bladder, bounded by the two ureteric orifices and the internal urethral orifice, is the:', '["Trigone", "Fundus", "Detrusor", "Apex"]'::jsonb, 0, 'The trigone is a constant, smooth triangular region defined by the two ureteric orifices and the internal urethral orifice.', 'Pre-Council', '🎓', true),
(5806, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A distinguishing histological feature of the trigone compared with the rest of the bladder is that it:', '["Remains smooth and does not form rugae even when the bladder is empty", "Is the only region of the bladder that forms rugae", "Is lined by stratified squamous epithelium", "Lacks a muscular layer entirely"]'::jsonb, 0, 'Unlike the rest of the bladder mucosa, which folds into rugae when empty, the trigone remains smooth regardless of bladder filling.', 'Pre-Council', '🎓', true),
(5807, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The epithelium lining the urinary bladder, which allows it to stretch considerably without losing its barrier function, is:', '["Transitional epithelium (urothelium)", "Simple columnar epithelium", "Stratified squamous epithelium", "Pseudostratified ciliated epithelium"]'::jsonb, 0, 'Transitional epithelium (urothelium) can change shape from cuboidal to squamous-like as the bladder distends, while remaining an effective urine-impermeable barrier.', 'Pre-Council', '🎓', true),
(5808, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The smooth muscle forming the wall of the urinary bladder, responsible for contraction during voiding, is called the:', '["Detrusor muscle", "External urethral sphincter", "Levator ani muscle", "Trigone muscle"]'::jsonb, 0, 'The detrusor is a three-layered smooth muscle coat that contracts to expel urine during micturition.', 'Pre-Council', '🎓', true),
(5809, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The internal urethral sphincter at the bladder neck is composed of:', '["Smooth muscle under involuntary control", "Skeletal muscle under voluntary control", "Cardiac-type muscle", "Fibrocartilage"]'::jsonb, 0, 'The internal urethral sphincter is formed by smooth muscle and is not under direct voluntary control, unlike the external sphincter.', 'Pre-Council', '🎓', true),
(5810, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Voluntary control over the initiation and interruption of urination is exerted mainly through the:', '["External urethral sphincter, composed of skeletal muscle innervated by the pudendal nerve", "Internal urethral sphincter, innervated by the vagus nerve", "Detrusor muscle, innervated by the phrenic nerve", "Trigone, innervated by the hypogastric nerve"]'::jsonb, 0, 'The external urethral sphincter is skeletal muscle under somatic control via the pudendal nerve, allowing voluntary control of voiding.', 'Pre-Council', '🎓', true),
(5811, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Parasympathetic stimulation of the bladder via the pelvic splanchnic nerves (S2-S4) during micturition causes:', '["Detrusor muscle contraction and internal sphincter relaxation", "Detrusor muscle relaxation and internal sphincter contraction", "No measurable effect on bladder function", "Contraction of the external sphincter only"]'::jsonb, 0, 'Parasympathetic activation is the principal driver of the voiding reflex, contracting the detrusor while the internal sphincter relaxes to allow urine flow.', 'Pre-Council', '🎓', true),
(5812, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'During the storage (filling) phase, sympathetic stimulation via the hypogastric nerve (T11-L2) primarily causes:', '["Detrusor relaxation and contraction of the internal urethral sphincter", "Detrusor contraction and relaxation of the internal urethral sphincter", "An immediate involuntary voiding reflex", "Paralysis of the external urethral sphincter"]'::jsonb, 0, 'Sympathetic outflow promotes urine storage by relaxing the detrusor and maintaining tone in the internal urethral sphincter.', 'Pre-Council', '🎓', true),
(5813, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The normal functional capacity of the adult urinary bladder before a strong urge to void is felt is approximately:', '["400-600 mL, with the initial urge to void sensed around 150-250 mL", "50-100 mL, with urge sensed at 20 mL", "2-3 liters, with no urge felt until completely full", "10-20 mL, with urge sensed immediately upon any filling"]'::jsonb, 0, 'The adult bladder can typically hold 400-600 mL, though the first sensation of fullness is usually noticed once volume reaches roughly 150-250 mL.', 'Pre-Council', '🎓', true),
(5814, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The oblique course of the ureter as it passes through the bladder wall (ureterovesical junction) primarily serves to:', '["Act as a physiological valve that prevents vesicoureteral reflux of urine", "Increase the velocity of urine flow into the bladder", "Allow direct communication between ureter and urethra", "Anchor the bladder firmly to the pelvic floor"]'::jsonb, 0, 'The oblique intramural course of the ureter creates a flap-valve mechanism: as the bladder fills and contracts, the tunnel is compressed, preventing retrograde flow of urine toward the kidney.', 'Pre-Council', '🎓', true),
(5815, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which nerve provides somatic (voluntary) motor innervation to the external urethral sphincter?', '["Pudendal nerve", "Pelvic splanchnic nerve", "Hypogastric nerve", "Vagus nerve"]'::jsonb, 0, 'The pudendal nerve (S2-S4) supplies somatic motor fibers to the skeletal muscle of the external urethral sphincter, enabling voluntary control.', 'Pre-Council', '🎓', true),
(5816, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Rugae (mucosal folds) of the empty bladder are functionally significant because they:', '["Flatten out to permit distension as the bladder fills with urine", "Prevent any distension of the bladder wall from occurring", "Are found exclusively within the trigone", "Represent areas of muscular weakness prone to rupture"]'::jsonb, 0, 'Rugae allow the transitional epithelium and underlying wall to unfold and accommodate increasing volumes of urine as the bladder fills.', 'Pre-Council', '🎓', true),
(5817, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In males, the structures immediately posterior/inferior to the base of the bladder typically include the:', '["Prostate gland and seminal vesicles", "Ovaries and uterus", "Vagina", "Spleen"]'::jsonb, 0, 'In the male pelvis, the prostate lies directly inferior to the bladder neck, with the seminal vesicles located posteriorly.', 'Pre-Council', '🎓', true),
(5818, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In females, the structure most closely related posteriorly to the bladder is the:', '["Uterus and vagina", "Prostate gland", "Seminal vesicles", "Left kidney"]'::jsonb, 0, 'In the female pelvis, the bladder is related posteriorly to the uterus (with the vesicouterine pouch between them) and the vagina.', 'Pre-Council', '🎓', true),
(5819, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The apex of the urinary bladder is connected to the umbilicus by a fibrous remnant of the fetal urachus called the:', '["Median umbilical ligament", "Medial umbilical ligament", "Lateral umbilical ligament", "Ligamentum teres"]'::jsonb, 0, 'The median umbilical ligament is the obliterated urachus, a fibrous cord running from the bladder apex to the umbilicus.', 'Pre-Council', '🎓', true),
(5820, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Peritoneum covers which surface of the urinary bladder?', '["Only the superior surface", "The entire bladder, circumferentially", "Only the trigone", "None of the bladder, which is fully intraperitoneal"]'::jsonb, 0, 'The bladder is an extraperitoneal (subperitoneal) pelvic organ, with peritoneum draping only over its superior surface.', 'Pre-Council', '🎓', true),
(5821, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The micturition reflex is primarily integrated at which level of the central nervous system?', '["Sacral spinal cord (S2-S4), with higher voluntary control from the pons and cerebral cortex", "Cervical spinal cord (C3-C5) exclusively", "Thoracic spinal cord (T1-T4) exclusively", "Medulla oblongata exclusively"]'::jsonb, 0, 'The basic micturition reflex arc is organized in the sacral spinal cord, while the pontine micturition center and cerebral cortex provide voluntary facilitation or inhibition.', 'Pre-Council', '🎓', true),
(5822, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following is the primary nitrogenous waste product excreted by the kidney that reflects protein catabolism?', '["Urea", "Glucose", "Bilirubin", "Lactate"]'::jsonb, 0, 'Urea, produced in the liver from ammonia generated by amino acid deamination, is the principal nitrogenous waste product excreted by the kidneys.', 'Pre-Council', '🎓', true),
(5823, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Creatinine, commonly used clinically to estimate glomerular filtration rate, is derived from:', '["Muscle creatine and phosphocreatine metabolism", "Hepatic bile pigment breakdown", "Dietary carbohydrate metabolism", "Red blood cell turnover"]'::jsonb, 0, 'Creatinine is a breakdown product of creatine phosphate in muscle, produced at a fairly constant rate proportional to muscle mass, making it useful for estimating GFR.', 'Pre-Council', '🎓', true),
(5824, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The kidney contributes to blood pressure regulation primarily through which hormonal system?', '["Renin-angiotensin-aldosterone system (RAAS)", "Insulin-glucagon axis", "Thyroid hormone axis", "Growth hormone-IGF-1 axis"]'::jsonb, 0, 'Renin released by the juxtaglomerular apparatus initiates the RAAS cascade, which regulates vascular tone and sodium/water retention, thereby influencing blood pressure.', 'Pre-Council', '🎓', true),
(5825, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Erythropoietin, essential for red blood cell production, is produced mainly by which renal cells in response to hypoxia?', '["Peritubular interstitial fibroblast-like cells in the renal cortex", "Podocytes of the glomerulus", "Principal cells of the collecting duct", "Mesangial cells"]'::jsonb, 0, 'Specialized peritubular fibroblast-like interstitial cells in the renal cortex sense hypoxia and increase erythropoietin secretion.', 'Pre-Council', '🎓', true),
(5826, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Anemia commonly seen in patients with chronic kidney disease is primarily due to:', '["Decreased erythropoietin production", "Excessive iron loss in the urine", "Increased red blood cell destruction within the glomerulus", "Vitamin B12 malabsorption caused by renal failure"]'::jsonb, 0, 'As functioning renal mass declines in chronic kidney disease, erythropoietin production falls, leading to a normocytic, normochromic anemia.', 'Pre-Council', '🎓', true),
(5827, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The kidney activates vitamin D by converting 25-hydroxyvitamin D to its active form, 1,25-dihydroxyvitamin D (calcitriol), via which enzyme located mainly in the proximal tubule?', '["1-alpha-hydroxylase", "25-hydroxylase", "Renin", "Carbonic anhydrase"]'::jsonb, 0, 'Renal 1-alpha-hydroxylase converts hepatically produced 25-hydroxyvitamin D into the biologically active hormone calcitriol.', 'Pre-Council', '🎓', true),
(5828, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal osteodystrophy in chronic kidney disease results largely from impaired renal activation of vitamin D combined with:', '["Phosphate retention and secondary hyperparathyroidism", "Excess vitamin D production", "Hypocalcemia caused solely by dietary deficiency", "Increased calcitonin secretion"]'::jsonb, 0, 'Failing kidneys retain phosphate and produce less calcitriol, driving hypocalcemia and compensatory secondary hyperparathyroidism that weakens bone.', 'Pre-Council', '🎓', true),
(5829, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The normal glomerular filtration rate (GFR) in a healthy adult is approximately:', '["120-125 mL/min", "20-30 mL/min", "500 mL/min", "1000 mL/min"]'::jsonb, 0, 'Normal GFR in a healthy adult averages roughly 120-125 mL/min, corresponding to about 180 liters filtered per day.', 'Pre-Council', '🎓', true),
(5830, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal autoregulation of GFR across a wide range of mean arterial pressures (roughly 80-180 mmHg) is achieved mainly through which two mechanisms?', '["The myogenic mechanism and tubuloglomerular feedback", "Renin secretion and aldosterone release only", "ADH release and thirst", "Sympathetic stimulation alone"]'::jsonb, 0, 'Intrinsic renal autoregulation relies on the myogenic response of afferent arteriolar smooth muscle and on tubuloglomerular feedback signaled by the macula densa.', 'Pre-Council', '🎓', true),
(5831, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Urine formation results from three basic processes occurring along the nephron; these are:', '["Filtration, reabsorption, and secretion", "Filtration, dilution, and excretion", "Reabsorption, concentration, and dilution only", "Secretion, excretion, and osmosis only"]'::jsonb, 0, 'Urine is formed through glomerular filtration, tubular reabsorption of needed substances, and tubular secretion of additional wastes and ions.', 'Pre-Council', '🎓', true),
(5832, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Filtration fraction refers to:', '["The proportion of renal plasma flow that is filtered at the glomerulus (GFR divided by renal plasma flow)", "The proportion of filtered sodium that is reabsorbed", "The fraction of cardiac output received by the kidneys", "The ratio of urea to creatinine excreted in urine"]'::jsonb, 0, 'Filtration fraction (GFR/renal plasma flow) is normally about 20%, indicating roughly one-fifth of the plasma flowing through the glomerulus is filtered.', 'Pre-Council', '🎓', true),
(5833, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which statement best describes the kidney''s role in glucose homeostasis during prolonged fasting?', '["The renal cortex contributes to gluconeogenesis", "The kidney has no role whatsoever in glucose metabolism", "The kidney only stores glucose and never produces it", "The kidney actively destroys glucose to prevent hyperglycemia"]'::jsonb, 0, 'During prolonged fasting, the renal cortex (alongside the liver) becomes an important site of gluconeogenesis, helping maintain blood glucose.', 'Pre-Council', '🎓', true),
(5834, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a critically ill patient with hypovolemic shock, the kidney''s compensatory response typically includes:', '["Activation of RAAS, increased ADH secretion, and sympathetically mediated efferent arteriolar constriction to help preserve GFR", "Suppression of RAAS accompanied by increased urine output", "Immediate and complete cessation of renal blood flow", "Release of atrial natriuretic peptide to promote diuresis"]'::jsonb, 0, 'In hypovolemia the kidney activates RAAS and increases ADH and sympathetic tone, constricting the efferent arteriole preferentially to help maintain GFR despite reduced renal blood flow.', 'Pre-Council', '🎓', true),
(5835, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The primary route of potassium excretion from the body under normal physiological conditions is:', '["Renal excretion, largely regulated by aldosterone acting on the collecting duct", "Fecal excretion", "Sweat gland secretion", "Pulmonary excretion"]'::jsonb, 0, 'The kidneys, under aldosterone''s influence on principal cells, are the major regulators of daily potassium balance and excretion.', 'Pre-Council', '🎓', true),
(5836, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal clearance of a substance is best defined as:', '["The volume of plasma completely cleared of that substance per unit time", "The total mass of the substance excreted in urine per day", "The concentration of the substance measured in a urine sample", "The rate of glomerular filtration alone, regardless of the substance measured"]'::jsonb, 0, 'Clearance expresses renal handling of a substance as the theoretical volume of plasma from which that substance is completely removed per minute.', 'Pre-Council', '🎓', true),
(5837, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Why is renal drug clearance a critical consideration for ICU nurses caring for a patient with acute kidney injury?', '["Drugs normally eliminated by the kidney can accumulate and cause toxicity, requiring dose adjustment", "Renal function has essentially no effect on drug elimination", "All drugs are exclusively eliminated by the liver, never the kidney", "Acute kidney injury increases renal drug clearance, requiring higher doses"]'::jsonb, 0, 'Reduced GFR in acute kidney injury slows elimination of renally cleared drugs, so doses and intervals often must be adjusted to avoid toxic accumulation.', 'Pre-Council', '🎓', true),
(5838, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'According to the Starling forces governing glomerular filtration, an increase in glomerular capillary hydrostatic pressure will:', '["Increase GFR", "Decrease GFR", "Have no effect on GFR", "Stop filtration entirely"]'::jsonb, 0, 'Glomerular capillary hydrostatic pressure is the main force favoring filtration; increasing it raises net filtration pressure and therefore GFR.', 'Pre-Council', '🎓', true),
(5839, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best reflects the kidney''s role in overall acid-base homeostasis as one of its core functions?', '["Reabsorbing filtered bicarbonate and generating new bicarbonate to balance daily fixed-acid production", "Producing carbon dioxide for exhalation by the lungs", "Buffering blood pH solely through hemoglobin", "Regulating blood pH only through changes in respiratory rate"]'::jsonb, 0, 'As one of its core physiological functions, the kidney reclaims filtered bicarbonate and generates new bicarbonate to offset the daily nonvolatile acid load from metabolism.', 'Pre-Council', '🎓', true),
(5840, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Aminoglycoside antibiotics, commonly used in the ICU, are of particular concern because they are:', '["Nephrotoxic and require monitoring of renal function during therapy", "Exclusively metabolized by the liver with no impact on the kidney", "Renally protective agents", "Excreted entirely unchanged in feces, bypassing the kidney"]'::jsonb, 0, 'Aminoglycosides are excreted renally and are well known for their nephrotoxic potential, requiring drug-level and renal function monitoring.', 'Pre-Council', '🎓', true),
(5841, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A key non-excretory endocrine function of the kidney, aside from erythropoietin and renin secretion, is:', '["Activation of vitamin D to its biologically active form, calcitriol", "Production of insulin", "Synthesis of thyroxine", "Secretion of cortisol"]'::jsonb, 0, 'The kidney performs the final activation step of vitamin D metabolism, converting 25-hydroxyvitamin D to calcitriol.', 'Pre-Council', '🎓', true),
(5842, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The kidneys receive approximately what percentage of resting cardiac output, reflecting their high filtration demand?', '["About 20-25%", "About 2-5%", "About 50%", "About 70%"]'::jsonb, 0, 'Despite being a small fraction of total body weight, the kidneys receive a disproportionately large 20-25% of resting cardiac output.', 'Pre-Council', '🎓', true),
(5843, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Regulation of extracellular fluid osmolality by the kidney is achieved primarily by adjusting:', '["Water reabsorption in the collecting duct under ADH control", "Glucose reabsorption in the proximal tubule", "Erythropoietin secretion", "Renal artery vasodilation alone"]'::jsonb, 0, 'ADH-controlled water permeability of the collecting duct allows the kidney to excrete concentrated or dilute urine as needed to keep plasma osmolality within a narrow range.', 'Pre-Council', '🎓', true),
(5844, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best describes the kidney''s role in maintaining calcium and phosphate balance?', '["It regulates renal excretion/reabsorption of calcium and phosphate and activates vitamin D, working with PTH", "It has no role in calcium or phosphate balance, which is controlled solely by the gut", "It only excretes calcium and never phosphate", "It stores calcium within the renal medulla for later release"]'::jsonb, 0, 'The kidney regulates urinary calcium and phosphate handling, and its activation of vitamin D works together with parathyroid hormone to maintain mineral homeostasis.', 'Pre-Council', '🎓', true),
(5845, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The countercurrent multiplier system responsible for concentrating urine is established primarily by the:', '["Loop of Henle", "Proximal convoluted tubule", "Renal artery and vein", "Ureter"]'::jsonb, 0, 'The hairpin arrangement of the descending and ascending limbs of the loop of Henle, with opposite flow directions, creates the countercurrent multiplier that generates the medullary osmotic gradient.', 'Pre-Council', '🎓', true),
(5846, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In the descending limb of the loop of Henle, tubular fluid becomes progressively more concentrated as it descends because this segment is:', '["Highly permeable to water but relatively impermeable to solutes such as NaCl", "Impermeable to water but actively transports NaCl out", "Impermeable to both water and solutes", "Equally permeable to both water and solutes, producing no net change"]'::jsonb, 0, 'Because the descending limb permits water to move out passively into the hypertonic interstitium while retaining solute, the luminal fluid becomes progressively more concentrated.', 'Pre-Council', '🎓', true),
(5847, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'As tubular fluid ascends the thick ascending limb of the loop of Henle, it becomes progressively more dilute because this segment:', '["Actively transports NaCl out of the lumen while remaining impermeable to water", "Is freely permeable to water", "Actively reabsorbs water via aquaporin channels", "Secretes additional solute into the lumen"]'::jsonb, 0, 'The thick ascending limb pumps NaCl out via NKCC2 but is water-impermeable, so the fluid remaining in the lumen becomes increasingly dilute as it ascends.', 'Pre-Council', '🎓', true),
(5848, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The osmolality of the renal interstitium increases from the cortex toward the tip of the inner medulla, reaching approximately what value in a maximally concentrating human kidney?', '["About 1200 mOsm/kg", "About 300 mOsm/kg", "About 600 mOsm/kg at the papilla", "About 2500 mOsm/kg"]'::jsonb, 0, 'The interstitial osmolality rises from about 300 mOsm/kg in the cortex to as high as roughly 1200 mOsm/kg at the papillary tip of the inner medulla.', 'Pre-Council', '🎓', true),
(5849, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The vasa recta preserve the medullary osmotic gradient established by the loop of Henle through a process best described as:', '["Countercurrent exchange, passively equilibrating with the interstitium along their hairpin course", "Active countercurrent multiplication identical to that of the loop of Henle", "Complete impermeability to both water and solutes", "Rapid, straight blood flow that continuously washes out the gradient"]'::jsonb, 0, 'The vasa recta form hairpin loops that passively exchange water and solutes with the interstitium, allowing them to deliver oxygen and remove reabsorbed water without dissipating the osmotic gradient.', 'Pre-Council', '🎓', true),
(5850, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Antidiuretic hormone (ADH, vasopressin) is synthesized in the hypothalamus and released into the circulation from the:', '["Posterior pituitary gland", "Anterior pituitary gland", "Adrenal medulla", "Thyroid gland"]'::jsonb, 0, 'ADH is synthesized in the hypothalamic supraoptic and paraventricular nuclei, transported down axons, and released from the posterior pituitary.', 'Pre-Council', '🎓', true),
(5851, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The primary stimulus for ADH release detected by hypothalamic osmoreceptors is:', '["Increased plasma osmolality", "Decreased plasma osmolality", "Increased plasma glucose alone", "Decreased plasma potassium"]'::jsonb, 0, 'A rise in plasma osmolality is sensed by osmoreceptors near the OVLT, stimulating ADH release to promote water reabsorption and dilute the plasma back toward normal.', 'Pre-Council', '🎓', true),
(5852, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'ADH increases water permeability of the collecting duct by binding to V2 receptors on principal cells and promoting insertion of which channel into the apical membrane?', '["Aquaporin-2", "Aquaporin-1", "ENaC", "NKCC2"]'::jsonb, 0, 'V2 receptor activation by ADH triggers a signaling cascade that inserts aquaporin-2 water channels into the apical membrane of principal cells, increasing water reabsorption.', 'Pre-Council', '🎓', true),
(5853, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with central diabetes insipidus presents with which classic urinary findings?', '["Large volumes of dilute urine (polyuria) with low urine osmolality", "Small volumes of highly concentrated urine", "Normal urine output with high specific gravity", "Hematuria accompanied by proteinuria"]'::jsonb, 0, 'Central diabetes insipidus results from insufficient ADH secretion, so the collecting duct cannot reabsorb water adequately, producing dilute polyuria despite rising plasma osmolality.', 'Pre-Council', '🎓', true),
(5854, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Syndrome of inappropriate antidiuretic hormone secretion (SIADH) typically produces:', '["Dilutional hyponatremia with inappropriately concentrated urine", "Hypernatremia with dilute urine", "Normal serum sodium accompanied by polyuria", "Hyperkalemia with anuria"]'::jsonb, 0, 'Excess ADH in SIADH causes excessive water retention, diluting serum sodium while the urine remains inappropriately concentrated relative to plasma osmolality.', 'Pre-Council', '🎓', true),
(5855, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which nephron population is essential for generating the steep medullary osmotic gradient needed to maximally concentrate urine?', '["Juxtamedullary nephrons, with their long loops of Henle", "Cortical nephrons, with their short loops of Henle", "Nephrons that lack a loop of Henle entirely", "Nephrons whose glomeruli lie within the medulla"]'::jsonb, 0, 'Juxtamedullary nephrons, whose long loops of Henle extend deep into the medulla, are primarily responsible for establishing the steep osmotic gradient required for maximal urine concentration.', 'Pre-Council', '🎓', true),
(5856, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Urea recycling between the inner medullary collecting duct and the loop of Henle contributes to:', '["Additional medullary hypertonicity that supports maximal urine concentration", "Dilution of the medullary interstitium", "Active secretion of potassium into the tubular lumen", "Generation of new bicarbonate"]'::jsonb, 0, 'Urea trapped and recycled within the inner medulla under ADH''s influence adds substantially to the total medullary interstitial osmolality, aiding maximal urine concentration.', 'Pre-Council', '🎓', true),
(5857, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Osmoreceptors that detect changes in plasma osmolality and trigger ADH release and thirst are located primarily in the:', '["Hypothalamus, near the organum vasculosum of the lamina terminalis (OVLT)", "Medulla oblongata", "Posterior pituitary gland itself", "Juxtaglomerular apparatus of the kidney"]'::jsonb, 0, 'Osmoreceptor neurons clustered near the OVLT in the hypothalamus, a region lacking a complete blood-brain barrier, continuously monitor plasma osmolality.', 'Pre-Council', '🎓', true),
(5858, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Besides an increase in plasma osmolality, which of the following also stimulates thirst and ADH release?', '["A significant decrease in circulating blood volume, sensed by baroreceptors", "A rise in blood glucose in isolation", "A decrease in plasma osmolality", "Increased urine output from diuretic therapy has no effect on ADH"]'::jsonb, 0, 'Substantial hypovolemia, detected by cardiac and arterial baroreceptors, stimulates ADH release and thirst even independent of osmolality changes.', 'Pre-Council', '🎓', true),
(5859, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The "single effect" that drives countercurrent multiplication in the loop of Henle refers to:', '["Active NaCl transport out of the thick ascending limb", "Passive water movement out of the collecting duct", "Osmotic diuresis caused by unreabsorbed glucose", "Vasodilation of the vasa recta"]'::jsonb, 0, 'The repeated, small horizontal osmotic gradient created at each level by active NaCl transport out of the ascending limb (the "single effect") is multiplied along the length of the loop to create the overall vertical medullary gradient.', 'Pre-Council', '🎓', true),
(5860, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Loop diuretics such as furosemide impair the kidney''s maximal urine-concentrating ability because they:', '["Inhibit the NKCC2 transporter in the thick ascending limb, disrupting the medullary osmotic gradient", "Block ADH receptors directly", "Increase aquaporin-2 insertion in the collecting duct", "Stimulate excessive renin release exclusively"]'::jsonb, 0, 'By blocking NKCC2, loop diuretics prevent the ascending limb from generating the medullary osmotic gradient, blunting the kidney''s ability to concentrate urine.', 'Pre-Council', '🎓', true),
(5861, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The maximally dilute urine a healthy human kidney can produce has an osmolality of approximately:', '["As low as 50 mOsm/kg", "About 300 mOsm/kg, isosmotic with plasma only", "Never below 600 mOsm/kg", "About 1200 mOsm/kg"]'::jsonb, 0, 'When ADH is suppressed, the collecting duct remains impermeable to water, allowing excretion of very dilute urine with osmolality as low as about 50 mOsm/kg.', 'Pre-Council', '🎓', true),
(5862, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Atrial natriuretic peptide (ANP), released from stretched atrial myocytes during volume overload, promotes fluid balance by:', '["Promoting natriuresis and diuresis while inhibiting renin, aldosterone, and ADH", "Stimulating aldosterone release to further retain sodium", "Increasing ADH secretion to conserve additional water", "Causing systemic vasoconstriction to raise blood pressure"]'::jsonb, 0, 'ANP counteracts volume overload by promoting sodium and water excretion and suppressing the renin-angiotensin-aldosterone system and ADH.', 'Pre-Council', '🎓', true),
(5863, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Aldosterone acts on principal cells of the collecting duct to:', '["Increase sodium reabsorption and potassium secretion via ENaC channels", "Increase water reabsorption independent of sodium transport", "Decrease sodium reabsorption throughout the nephron", "Directly inhibit ADH secretion from the posterior pituitary"]'::jsonb, 0, 'Aldosterone upregulates ENaC channels and the basolateral Na+/K+-ATPase in principal cells, increasing sodium reabsorption coupled with potassium secretion.', 'Pre-Council', '🎓', true),
(5864, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A critically ill patient in hypovolemic shock produces small volumes of highly concentrated urine. This finding reflects:', '["An intact renal concentrating (countercurrent) mechanism responding appropriately to increased ADH and RAAS activation", "Renal tubular necrosis with complete loss of concentrating ability", "A primary structural defect in the loop of Henle", "SIADH occurring independently of the patient''s volume status"]'::jsonb, 0, 'Concentrated, low-volume urine in hypovolemia demonstrates that the countercurrent mechanism and ADH/RAAS-mediated water conservation are functioning appropriately to preserve intravascular volume.', 'Pre-Council', '🎓', true),
(5865, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Osmotic diuretics such as mannitol increase urine output primarily by:', '["Increasing tubular fluid osmolality, which limits passive water reabsorption, especially in the descending loop of Henle", "Blocking the NKCC2 transporter directly", "Inhibiting aldosterone receptors in the collecting duct", "Directly antagonizing ADH at V2 receptors"]'::jsonb, 0, 'Mannitol is filtered but poorly reabsorbed, raising tubular fluid osmolality and osmotically retaining water within the lumen, most notably reducing water reabsorption in the descending limb.', 'Pre-Council', '🎓', true),
(5866, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Free water clearance is a clinical concept used to assess the kidney''s ability to:', '["Excrete solute-free water and thereby appropriately dilute or concentrate the urine", "Filter creatinine alone", "Excrete the daily fixed acid load", "Reabsorb filtered glucose"]'::jsonb, 0, 'Free water clearance reflects how effectively the kidney can separate solute from water, indicating its dilving or concentrating capacity relative to plasma.', 'Pre-Council', '🎓', true),
(5867, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The countercurrent exchange mechanism of the vasa recta minimizes "washout" of the medullary gradient mainly because:', '["Blood flow through the vasa recta is relatively slow and follows a hairpin loop that permits passive solute and water exchange with the interstitium", "Vasa recta blood flow is extremely rapid, efficiently sweeping solute away", "Vasa recta are completely impermeable to both solutes and water", "Vasa recta actively pump sodium into the interstitium exactly like the ascending limb"]'::jsonb, 0, 'The slow, hairpin-shaped blood flow of the vasa recta allows solutes to diffuse back and forth passively with the interstitium, so the medullary gradient is conserved rather than washed out.', 'Pre-Council', '🎓', true),
(5868, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with severe insensible fluid losses from high fever who produces a small volume of urine with high specific gravity best demonstrates:', '["Appropriate physiological water conservation via ADH-mediated concentration of urine", "Acute tubular necrosis", "Diabetes insipidus", "A state of overhydration"]'::jsonb, 0, 'Reduced urine volume with elevated specific gravity in the setting of insensible losses reflects a normally functioning concentrating mechanism responding to rising ADH levels.', 'Pre-Council', '🎓', true),
(5869, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The kidney contributes to long-term acid-base regulation mainly by:', '["Reabsorbing filtered bicarbonate and generating new bicarbonate to replace that consumed buffering daily metabolic acid production", "Exhaling carbon dioxide", "Producing lactic acid", "Storing excess hydrogen ions in bone only"]'::jsonb, 0, 'The kidney''s central acid-base role is to reclaim filtered bicarbonate and generate new bicarbonate through titratable acid excretion and ammoniagenesis, replacing bicarbonate consumed daily buffering metabolic acids.', 'Pre-Council', '🎓', true),
(5870, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The majority of filtered bicarbonate is reabsorbed in which segment of the nephron?', '["Proximal convoluted tubule (roughly 80-90%)", "Thin descending limb of the loop of Henle", "Distal convoluted tubule", "Collecting duct"]'::jsonb, 0, 'About 80-90% of filtered bicarbonate is reabsorbed in the proximal convoluted tubule, with the remainder handled by more distal segments.', 'Pre-Council', '🎓', true),
(5871, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Reabsorption of filtered bicarbonate in the proximal tubule depends critically on the enzyme:', '["Carbonic anhydrase", "Renin", "Aldosterone synthase", "1-alpha-hydroxylase"]'::jsonb, 0, 'Carbonic anhydrase, present both intracellularly and on the brush border, catalyzes the interconversion of CO2, water, and carbonic acid needed for bicarbonate reabsorption.', 'Pre-Council', '🎓', true),
(5872, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Hydrogen ion secretion into the proximal tubular lumen occurs mainly via which transporter?', '["Na+/H+ antiporter (NHE3)", "Na+-K+-2Cl- cotransporter", "Na+-Cl- cotransporter", "Aquaporin-1"]'::jsonb, 0, 'The apical Na+/H+ exchanger NHE3 secretes hydrogen ions into the proximal tubular lumen while reabsorbing sodium, driving most bicarbonate reclamation.', 'Pre-Council', '🎓', true),
(5873, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Type A (alpha) intercalated cells of the collecting duct secrete hydrogen ions via which apical transporter?', '["H+-ATPase (proton pump)", "Na+/H+ antiporter", "Pendrin", "Aquaporin-2"]'::jsonb, 0, 'Type A intercalated cells actively pump hydrogen ions into the tubular lumen using an apical H+-ATPase, the major mechanism for distal urinary acidification.', 'Pre-Council', '🎓', true),
(5874, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In type A intercalated cells, bicarbonate generated intracellularly is returned to the blood via which basolateral transporter?', '["Cl-/HCO3- exchanger (AE1)", "Na+/H+ antiporter", "H+-ATPase", "ENaC"]'::jsonb, 0, 'Bicarbonate produced within type A intercalated cells exits across the basolateral membrane via the AE1 chloride-bicarbonate exchanger, returning it to the circulation.', 'Pre-Council', '🎓', true),
(5875, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Type B (beta) intercalated cells secrete bicarbonate into the tubular lumen via which transporter, becoming more active during alkalosis?', '["Pendrin (Cl-/HCO3- exchanger)", "H+-ATPase", "NHE3", "NKCC2"]'::jsonb, 0, 'Pendrin, located on the apical membrane of type B intercalated cells, secretes bicarbonate in exchange for chloride, a response upregulated during metabolic alkalosis.', 'Pre-Council', '🎓', true),
(5876, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Titratable acidity refers to renal buffering of secreted hydrogen ions mainly by which urinary buffer?', '["Phosphate (HPO4^2- converting to H2PO4-)", "Bicarbonate", "Hemoglobin", "Albumin"]'::jsonb, 0, 'Filtered phosphate acts as the principal titratable urinary buffer, accepting secreted hydrogen ions and allowing acid excretion without dangerously lowering urine pH.', 'Pre-Council', '🎓', true),
(5877, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal ammoniagenesis, in which glutamine is metabolized in the proximal tubule to produce ammonium (NH4+), is particularly important because it:', '["Allows excretion of a large, adjustable acid load, especially during metabolic acidosis", "Produces carbon dioxide for respiratory elimination", "Directly reabsorbs filtered glucose", "Has no role in acid-base balance and functions only in nitrogen excretion"]'::jsonb, 0, 'Ammoniagenesis is the kidney''s most adaptable mechanism for excreting excess acid, increasing substantially during sustained metabolic acidosis to enhance hydrogen ion elimination.', 'Pre-Council', '🎓', true),
(5878, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Compared with respiratory compensation for a primary metabolic acid-base disturbance, renal compensation is characteristically:', '["Slower, taking hours to days to become fully effective", "Faster, occurring within minutes", "Instantaneous", "Absent in essentially all acid-base disorders"]'::jsonb, 0, 'Renal compensatory changes in bicarbonate handling require hours to days, in contrast to respiratory compensation which begins within minutes.', 'Pre-Council', '🎓', true),
(5879, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal compensation for chronic respiratory acidosis involves:', '["Increased hydrogen ion excretion and increased bicarbonate reabsorption/generation, raising serum bicarbonate", "Decreased bicarbonate reabsorption", "Increased bicarbonate excretion", "No renal response whatsoever"]'::jsonb, 0, 'In chronic respiratory acidosis, the kidney compensates by excreting more hydrogen ion and generating additional bicarbonate, raising serum bicarbonate to partially offset the low pH.', 'Pre-Council', '🎓', true),
(5880, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal compensation for chronic respiratory alkalosis involves:', '["Decreased renal bicarbonate reabsorption, increasing bicarbonate excretion to lower serum bicarbonate", "Increased bicarbonate reabsorption", "Increased ammoniagenesis", "Increased hydrogen ion secretion"]'::jsonb, 0, 'In chronic respiratory alkalosis, the kidney reduces bicarbonate reabsorption, allowing more bicarbonate to be excreted and lowering plasma bicarbonate toward normal.', 'Pre-Council', '🎓', true),
(5881, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The normal reference range for arterial blood pH is:', '["7.35-7.45", "7.20-7.30", "7.45-7.55", "6.95-7.15"]'::jsonb, 0, 'Normal arterial pH is maintained within a narrow range of 7.35 to 7.45 through combined respiratory and renal regulation.', 'Pre-Council', '🎓', true),
(5882, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a patient with diabetic ketoacidosis (a primary metabolic acidosis), the expected respiratory compensation is:', '["Hyperventilation (Kussmaul respirations) to lower PaCO2", "Hypoventilation to raise PaCO2", "No change in respiratory rate or pattern", "Breath-holding to raise pH directly"]'::jsonb, 0, 'Metabolic acidosis stimulates the respiratory center to increase rate and depth of breathing (Kussmaul respirations), lowering PaCO2 to partially compensate.', 'Pre-Council', '🎓', true),
(5883, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a patient with metabolic alkalosis from prolonged vomiting, the expected respiratory compensation is:', '["Mild hypoventilation to raise PaCO2 and partially offset the elevated pH", "Hyperventilation to lower PaCO2 further", "Immediate respiratory arrest", "No respiratory response is physiologically possible"]'::jsonb, 0, 'Metabolic alkalosis mildly suppresses respiratory drive, allowing PaCO2 to rise slightly, which helps counteract the elevated pH, though this compensation is limited by the hypoxic drive to breathe.', 'Pre-Council', '🎓', true),
(5884, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal tubular acidosis (RTA) type 1 (distal RTA) results from an inability to:', '["Adequately secrete hydrogen ions in the distal nephron, impairing urinary acidification", "Reabsorb filtered bicarbonate in the proximal tubule", "Reabsorb sodium anywhere along the nephron", "Concentrate urine via the loop of Henle"]'::jsonb, 0, 'Distal (type 1) RTA is caused by impaired distal hydrogen ion secretion, so the kidney cannot maximally acidify the urine, leading to systemic metabolic acidosis.', 'Pre-Council', '🎓', true),
(5885, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Renal tubular acidosis (RTA) type 2 (proximal RTA) is characterized primarily by:', '["Impaired bicarbonate reabsorption in the proximal convoluted tubule, leading to bicarbonate wasting", "Impaired distal hydrogen ion secretion", "Excess mineralocorticoid activity", "Hyperkalemia due to aldosterone resistance"]'::jsonb, 0, 'Proximal (type 2) RTA results from a defect in proximal tubular bicarbonate reabsorption, causing significant urinary bicarbonate loss and metabolic acidosis.', 'Pre-Council', '🎓', true),
(5886, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Type 4 renal tubular acidosis is most commonly associated with:', '["Aldosterone deficiency or resistance, producing hyperkalemia along with mild metabolic acidosis", "Excess aldosterone activity", "Pure isolated proximal bicarbonate wasting", "Primary respiratory failure"]'::jsonb, 0, 'Type 4 RTA arises from hypoaldosteronism or aldosterone resistance (e.g., in diabetic nephropathy), causing hyperkalemia that itself impairs ammoniagenesis and produces mild acidosis.', 'Pre-Council', '🎓', true),
(5887, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Hyperaldosteronism tends to produce which acid-base and electrolyte pattern?', '["Metabolic alkalosis with hypokalemia, due to increased distal hydrogen and potassium secretion", "Metabolic acidosis with hyperkalemia", "Respiratory alkalosis with hyponatremia", "No effect on acid-base balance"]'::jsonb, 0, 'Excess aldosterone increases distal sodium reabsorption coupled with hydrogen and potassium secretion, producing metabolic alkalosis together with hypokalemia.', 'Pre-Council', '🎓', true),
(5888, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In chronic kidney disease, metabolic acidosis commonly develops because of:', '["Reduced functioning nephron mass leading to decreased ammoniagenesis and retention of fixed acids", "Excessive renal bicarbonate reabsorption", "Hyperventilation from pulmonary compensation overwhelming the kidney", "Increased erythropoietin production"]'::jsonb, 0, 'As nephron mass declines in chronic kidney disease, the capacity for ammoniagenesis and acid excretion falls, causing retention of fixed (nonvolatile) acids and metabolic acidosis.', 'Pre-Council', '🎓', true),
(5889, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient on prolonged loop diuretic therapy who becomes volume depleted may develop "contraction alkalosis" partly because:', '["Volume depletion increases distal sodium delivery and aldosterone activity, enhancing distal hydrogen ion secretion", "Loop diuretics directly inhibit carbonic anhydrase in the proximal tubule", "Loop diuretics primarily cause bicarbonate wasting in the proximal tubule", "Volume depletion suppresses aldosterone secretion"]'::jsonb, 0, 'Diuretic-induced volume contraction activates the renin-angiotensin-aldosterone system, and increased aldosterone together with greater distal sodium delivery enhances distal hydrogen ion secretion, generating alkalosis.', 'Pre-Council', '🎓', true),
(5890, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Acetazolamide, a carbonic anhydrase inhibitor sometimes used in the ICU, produces mild metabolic acidosis primarily by:', '["Causing bicarbonaturia through inhibition of proximal tubular bicarbonate reabsorption", "Directly increasing hydrogen ion secretion in the collecting duct", "Blocking aldosterone receptors", "Stimulating ammoniagenesis"]'::jsonb, 0, 'By inhibiting carbonic anhydrase in the proximal tubule, acetazolamide impairs bicarbonate reabsorption, causing bicarbonate loss in the urine and a resulting mild metabolic acidosis.', 'Pre-Council', '🎓', true),
(5891, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Hypokalemia tends to promote metabolic alkalosis in part because it:', '["Promotes an intracellular shift of hydrogen ions and enhances renal hydrogen ion secretion and ammoniagenesis", "Directly raises plasma bicarbonate through increased dietary intake", "Suppresses aldosterone secretion", "Increases respiratory rate, lowering PaCO2 and directly raising pH"]'::jsonb, 0, 'In hypokalemia, hydrogen ions shift into cells to help maintain electroneutrality, and the kidney increases hydrogen ion secretion and ammoniagenesis, both of which favor development of metabolic alkalosis.', 'Pre-Council', '🎓', true),
(5892, 'Renal System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'According to the Henderson-Hasselbalch relationship, arterial pH is determined by the ratio of:', '["Bicarbonate concentration to dissolved carbon dioxide (reflected by PaCO2)", "Sodium concentration to potassium concentration", "Hemoglobin concentration to hematocrit", "Glucose concentration to lactate concentration"]'::jsonb, 0, 'The Henderson-Hasselbalch equation shows that arterial pH depends on the ratio of bicarbonate (renally regulated) to dissolved CO2 (respiratorily regulated), pH = pKa + log([HCO3-]/[0.03 x PaCO2]).', 'Pre-Council', '🎓', true),
(5893, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which layer of the epidermis contains actively dividing keratinocyte stem cells responsible for continuous renewal of the epidermis?', '["Stratum basale", "Stratum corneum", "Stratum granulosum", "Stratum lucidum"]'::jsonb, 0, 'The stratum basale (germinativum) is the deepest epidermal layer and contains mitotically active basal keratinocytes that continuously replace the epidermis.', 'Pre-Council', '🎓', true),
(5894, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which epidermal layer is found only in thick (glabrous) skin, such as the palms and soles?', '["Stratum lucidum", "Stratum spinosum", "Stratum granulosum", "Stratum basale"]'::jsonb, 0, 'The stratum lucidum is a thin, clear layer of flattened, dead cells present only in thick skin of the palms and soles.', 'Pre-Council', '🎓', true),
(5895, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The outermost layer of the epidermis, composed of many layers of dead, fully keratinized cells, is the:', '["Stratum corneum", "Stratum granulosum", "Stratum spinosum", "Stratum basale"]'::jsonb, 0, 'The stratum corneum is the outermost layer, made of anucleate, keratin-filled corneocytes that form the skin''s main physical and waterproof barrier.', 'Pre-Council', '🎓', true),
(5896, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which layer of the dermis provides the greatest tensile strength and elasticity due to dense irregular connective tissue with thick collagen and elastin bundles?', '["Reticular layer", "Papillary layer", "Stratum corneum", "Hypodermis"]'::jsonb, 0, 'The reticular dermis lies deep to the papillary layer and contains thick, interwoven collagen and elastin fibers that give skin its strength and elastic recoil.', 'Pre-Council', '🎓', true),
(5897, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which epidermal cell type is primarily responsible for antigen presentation as part of cutaneous immune surveillance?', '["Langerhans cells", "Melanocytes", "Keratinocytes", "Merkel cells"]'::jsonb, 0, 'Langerhans cells are bone marrow-derived dendritic antigen-presenting cells residing in the epidermis, mainly the stratum spinosum, that initiate immune responses to skin antigens.', 'Pre-Council', '🎓', true),
(5898, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Melanocytes, which produce the pigment melanin, are located predominantly in which epidermal layer?', '["Stratum basale", "Stratum corneum", "Stratum lucidum", "Stratum granulosum"]'::jsonb, 0, 'Melanocytes reside in the stratum basale, where they synthesize melanin and transfer it to surrounding keratinocytes via dendritic processes.', 'Pre-Council', '🎓', true),
(5899, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Merkel cells, which mediate light touch sensation via Merkel discs, are found in which epidermal layer?', '["Stratum basale", "Stratum corneum", "Papillary dermis", "Reticular dermis"]'::jsonb, 0, 'Merkel cells are located in the stratum basale, often near hair follicles and fingertips, where they associate with sensory nerve terminals to detect light touch.', 'Pre-Council', '🎓', true),
(5900, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which sensory receptor detects deep pressure and vibration and is located in the deep dermis and subcutaneous tissue?', '["Pacinian corpuscle", "Meissner corpuscle", "Merkel disc", "Free nerve ending"]'::jsonb, 0, 'Pacinian corpuscles are large, lamellated receptors located deep in the dermis and hypodermis that respond to deep pressure and vibration.', 'Pre-Council', '🎓', true),
(5901, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which sensory receptor, located in the papillary dermis, is responsible for light discriminative touch?', '["Meissner corpuscle", "Pacinian corpuscle", "Ruffini ending", "Krause end bulb"]'::jsonb, 0, 'Meissner corpuscles lie within dermal papillae, close to the epidermis, and are specialized for detecting light touch and fine texture discrimination.', 'Pre-Council', '🎓', true),
(5902, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The subcutaneous layer (hypodermis) primarily functions to provide:', '["Thermal insulation and energy storage via adipose tissue", "Keratin production", "Melanin synthesis", "Sebum production"]'::jsonb, 0, 'The hypodermis is composed largely of adipose (fat) tissue that insulates the body, cushions underlying structures, and serves as an energy reserve.', 'Pre-Council', '🎓', true),
(5903, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following is NOT a recognized physiological function of the skin?', '["Synthesis of insulin", "Thermoregulation", "Vitamin D synthesis", "Sensory perception"]'::jsonb, 0, 'Insulin is produced by pancreatic beta cells, not the skin. The skin performs thermoregulation, vitamin D synthesis, sensation, protection, and excretion.', 'Pre-Council', '🎓', true),
(5904, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The first step in cutaneous vitamin D synthesis is UVB-mediated conversion of which precursor?', '["7-dehydrocholesterol", "Cholecalciferol", "25-hydroxyvitamin D", "Ergocalciferol"]'::jsonb, 0, 'UVB radiation converts 7-dehydrocholesterol in the epidermis into previtamin D3, which is then thermally isomerized to cholecalciferol (vitamin D3).', 'Pre-Council', '🎓', true),
(5905, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'After UVB converts 7-dehydrocholesterol to cholecalciferol in the skin, the next hydroxylation step occurs in the:', '["Liver (25-hydroxylation)", "Kidney (25-hydroxylation)", "Skin itself", "Pancreas"]'::jsonb, 0, 'Cholecalciferol is transported to the liver, where it is hydroxylated to 25-hydroxyvitamin D; the kidney later performs the final 1-alpha-hydroxylation to active calcitriol.', 'Pre-Council', '🎓', true),
(5906, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Sebaceous glands typically:', '["Release sebum by holocrine secretion into hair follicles", "Are absent from the face", "Secrete sweat for thermoregulation", "Are concentrated on the palms and soles"]'::jsonb, 0, 'Sebaceous glands are holocrine glands, meaning whole disintegrated cells form the secretion (sebum), which is usually released into an associated hair follicle to lubricate skin and hair.', 'Pre-Council', '🎓', true),
(5907, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which type of sweat gland is distributed over most of the body surface and is primarily responsible for thermoregulatory sweating?', '["Eccrine glands", "Apocrine glands", "Sebaceous glands", "Ceruminous glands"]'::jsonb, 0, 'Eccrine sweat glands are widely distributed over the body, secrete a watery, hypotonic fluid directly onto the skin surface, and are the principal glands for evaporative heat loss.', 'Pre-Council', '🎓', true),
(5908, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Apocrine sweat glands become functionally active at which life stage and are concentrated in which body regions?', '["Puberty; axillae and groin", "Infancy; palms and soles", "Childhood; scalp", "Old age; face"]'::jsonb, 0, 'Apocrine glands remain dormant until puberty, when hormonal changes activate them; they are concentrated in the axillae, groin, and areolae and produce a thicker, odor-associated secretion.', 'Pre-Council', '🎓', true),
(5909, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The arrector pili muscle, whose contraction produces ''goosebumps'' and elevates the hair shaft, is innervated by the:', '["Sympathetic nervous system", "Parasympathetic nervous system", "Somatic motor neurons", "Enteric nervous system"]'::jsonb, 0, 'Arrector pili muscles are smooth muscle but receive sympathetic (adrenergic) innervation, contracting in response to cold or emotional stimuli.', 'Pre-Council', '🎓', true),
(5910, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The portion of the hair responsible for growth, containing rapidly dividing matrix cells surrounding the dermal papilla, is the:', '["Hair bulb", "Hair shaft", "Cuticle", "Medulla"]'::jsonb, 0, 'The hair bulb at the base of the follicle contains the matrix, a region of actively proliferating cells that produce the hair shaft as they push upward and keratinize.', 'Pre-Council', '🎓', true),
(5911, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The nail structure primarily responsible for producing new nail plate cells is the:', '["Nail matrix", "Nail bed", "Lunula", "Eponychium"]'::jsonb, 0, 'The nail matrix, located beneath the proximal nail fold, contains germinal epithelium that proliferates to generate the nail plate.', 'Pre-Council', '🎓', true),
(5912, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The whitish, crescent-shaped area visible at the base of the nail plate is called the:', '["Lunula", "Cuticle", "Free edge", "Hyponychium"]'::jsonb, 0, 'The lunula is the visible portion of the distal nail matrix, appearing pale because the underlying vascular bed is obscured by a thicker layer of matrix cells.', 'Pre-Council', '🎓', true),
(5913, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The normally acidic pH of the skin surface (approximately 4.5-5.5), known as the ''acid mantle,'' primarily functions to:', '["Inhibit bacterial and fungal colonization", "Facilitate vitamin D synthesis", "Promote wound healing directly", "Regulate core body temperature"]'::jsonb, 0, 'The acid mantle, formed by sebum, sweat, and skin surface lipids, creates an unfavorable environment for many pathogenic microorganisms, contributing to the skin''s antimicrobial defense.', 'Pre-Council', '🎓', true),
(5914, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a critically ill immobile patient, prolonged unrelieved pressure over a bony prominence causes tissue injury primarily because it:', '["Exceeds capillary closing pressure, producing local ischemia and hypoxia", "Increases local tissue pH", "Causes localized hyperthermia", "Stimulates excessive collagen synthesis"]'::jsonb, 0, 'When external pressure exceeds capillary closing pressure (roughly 32 mmHg), capillaries collapse, blood flow is occluded, and the resulting ischemia and hypoxia lead to tissue necrosis if unrelieved.', 'Pre-Council', '🎓', true),
(5915, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Shear force, a key contributor to pressure injury development in bedbound patients, refers to:', '["Sliding of deep tissue layers against superficial layers, distorting and occluding blood vessels", "Direct perpendicular pressure on the skin surface", "Excessive moisture accumulating on the skin", "Friction between skin and bed linen"]'::jsonb, 0, 'Shear occurs when the skeleton and deep fascia move (e.g., as the head of the bed is raised) while the skin remains fixed against linens, stretching and kinking underlying blood vessels and worsening ischemia.', 'Pre-Council', '🎓', true),
(5916, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A pressure injury involving full-thickness skin loss with visible subcutaneous fat, but no exposed bone, tendon, or muscle, corresponds structurally to damage extending through the:', '["Epidermis and dermis into the subcutaneous tissue", "Epidermis only", "Dermis only, sparing subcutaneous tissue", "Deep fascia and muscle"]'::jsonb, 0, 'This description corresponds to a Stage/Category 3 pressure injury, in which destruction extends through the full thickness of the epidermis and dermis into, but not through, the subcutaneous fat.', 'Pre-Council', '🎓', true),
(5917, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Moisture-associated skin damage (e.g., from incontinence or excessive perspiration) predisposes critically ill patients to skin breakdown primarily by:', '["Macerating and weakening the stratum corneum barrier", "Increasing melanin production", "Causing generalized cutaneous vasoconstriction", "Thickening the epidermis"]'::jsonb, 0, 'Prolonged moisture exposure softens and macerates the stratum corneum, reducing its structural integrity and making the skin more vulnerable to friction, shear, and pressure damage.', 'Pre-Council', '🎓', true),
(5918, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which statement about cutaneous thermoregulation is correct?', '["Cutaneous vasodilation increases heat loss by radiation and convection", "Cutaneous vasodilation decreases blood flow to the dermis", "Sweating ceases entirely during febrile states", "Arrector pili contraction increases heat loss"]'::jsonb, 0, 'When body temperature rises, cutaneous arterioles dilate, increasing dermal blood flow and allowing heat to be lost to the environment via radiation and convection; sweating adds evaporative cooling.', 'Pre-Council', '🎓', true),
(5919, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Age-related skin changes that increase pressure injury risk in elderly critically ill patients include:', '["Thinning of the epidermis and decreased dermal collagen and elastin", "Thickening of the stratum corneum", "Increased subcutaneous fat padding", "Increased sebaceous gland activity"]'::jsonb, 0, 'Aging is associated with epidermal thinning, reduced dermal collagen/elastin, flattening of the dermal-epidermal junction, and loss of subcutaneous padding, all of which increase vulnerability to pressure and shear injury.', 'Pre-Council', '🎓', true),
(5920, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which epidermal layer shows keratinocytes flattening and accumulating keratohyalin granules, a stage central to keratinization?', '["Stratum granulosum", "Stratum basale", "Stratum spinosum", "Stratum corneum"]'::jsonb, 0, 'In the stratum granulosum, keratinocytes flatten and produce keratohyalin granules containing profilaggrin, which aggregates keratin filaments as cells transition toward the dead, keratinized corneum.', 'Pre-Council', '🎓', true),
(5921, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Desmosomal connections between keratinocytes are most prominent, giving the tissue a ''prickly'' microscopic appearance, in which epidermal layer?', '["Stratum spinosum", "Stratum basale", "Stratum granulosum", "Stratum corneum"]'::jsonb, 0, 'The stratum spinosum (''spiny layer'') is named for the numerous desmosomes visible as spine-like intercellular bridges connecting adjacent keratinocytes, providing mechanical cohesion.', 'Pre-Council', '🎓', true),
(5922, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The skin''s role as a barrier limiting transepidermal water loss is due mainly to:', '["The lipid-rich, keratinized stratum corneum", "Dermal blood vessels", "Melanin pigment", "Sweat gland secretory activity"]'::jsonb, 0, 'The stratum corneum''s tightly packed corneocytes embedded in a lipid matrix (a ''brick and mortar'' arrangement) form the principal barrier limiting evaporative water loss through the skin.', 'Pre-Council', '🎓', true),
(5923, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a critically ill patient with hypoalbuminemia and generalized tissue edema, skin integrity is compromised primarily because edema:', '["Increases the diffusion distance for oxygen and nutrients to reach skin cells", "Decreases melanin production", "Increases sebaceous gland secretion", "Accelerates epidermal regeneration"]'::jsonb, 0, 'Interstitial edema increases the distance oxygen and nutrients must diffuse from capillaries to tissue cells, impairing cellular metabolism and predisposing edematous skin to breakdown.', 'Pre-Council', '🎓', true),
(5924, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Eccrine sweat is best characterized as:', '["A hypotonic, primarily water-and-electrolyte secretion controlled by sympathetic cholinergic fibers", "A thick, milky secretion rich in proteins and lipids", "A secretion active only from puberty onward", "A secretion released via a holocrine mechanism"]'::jsonb, 0, 'Eccrine glands secrete a dilute, hypotonic fluid mainly composed of water, sodium, and chloride, and are unusual in being sympathetically innervated by cholinergic (not adrenergic) fibers.', 'Pre-Council', '🎓', true),
(5925, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The layer of the GI tract wall containing the myenteric (Auerbach''s) plexus, primarily responsible for regulating motility, is the:', '["Muscularis externa, between the circular and longitudinal muscle layers", "Mucosa", "Submucosa", "Serosa"]'::jsonb, 0, 'The myenteric plexus lies between the circular and longitudinal smooth muscle layers of the muscularis externa and predominantly controls gut motility.', 'Pre-Council', '🎓', true),
(5926, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The submucosal (Meissner''s) plexus is primarily responsible for regulating:', '["Local blood flow and secretory activity of the mucosa", "Gross peristaltic motility of the muscularis externa", "Hepatic bile production", "Pancreatic endocrine secretion"]'::jsonb, 0, 'The submucosal plexus lies within the submucosa and chiefly controls local mucosal secretion, absorption, and blood flow, complementing the myenteric plexus''s control of motility.', 'Pre-Council', '🎓', true),
(5927, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which layer of the GI wall contains the muscularis mucosae, a thin sheet of smooth muscle producing local folding movements of the mucosa?', '["Mucosa", "Submucosa", "Muscularis externa", "Serosa"]'::jsonb, 0, 'The muscularis mucosae is the deepest component of the mucosa itself, a thin muscle layer that produces local movements independent of the larger muscularis externa.', 'Pre-Council', '🎓', true),
(5928, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The outermost layer of most intraperitoneal GI organs, formed by visceral peritoneum, is the:', '["Serosa", "Adventitia", "Submucosa", "Mucosa"]'::jsonb, 0, 'The serosa is a layer of visceral peritoneum (mesothelium plus loose connective tissue) covering intraperitoneal organs such as the stomach and jejunum.', 'Pre-Council', '🎓', true),
(5929, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Unlike most of the GI tract, the esophagus lacks a peritoneal covering and is instead surrounded externally by:', '["Adventitia", "Serosa", "Mesentery", "Visceral peritoneum"]'::jsonb, 0, 'The esophagus lies outside the peritoneal cavity and is covered by adventitia, fibrous connective tissue that blends with surrounding mediastinal structures, rather than serosa.', 'Pre-Council', '🎓', true),
(5930, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The upper third of the esophageal muscularis is composed of ___ muscle, transitioning to ___ muscle in the lower two-thirds.', '["Skeletal; smooth", "Smooth; skeletal", "Cardiac; smooth", "Smooth; cardiac"]'::jsonb, 0, 'The esophagus begins with skeletal (voluntary) muscle in its upper third, allowing voluntary initiation of swallowing, and transitions to smooth (involuntary) muscle in its lower two-thirds.', 'Pre-Council', '🎓', true),
(5931, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The lower esophageal (cardiac) sphincter functions primarily to:', '["Prevent reflux of gastric contents into the esophagus", "Regulate the rate of gastric emptying", "Control the flow of saliva into the pharynx", "Regulate pancreatic exocrine secretion"]'::jsonb, 0, 'The lower esophageal sphincter maintains tonic contraction between swallows to prevent retrograde flow of acidic gastric contents into the esophagus.', 'Pre-Council', '🎓', true),
(5932, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which region of the stomach lies most superiorly, forming a dome that typically contains swallowed air?', '["Fundus", "Cardia", "Body", "Pylorus"]'::jsonb, 0, 'The fundus is the rounded, superior portion of the stomach located above the level of the cardiac orifice and commonly contains a gastric air bubble.', 'Pre-Council', '🎓', true),
(5933, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The stomach region continuous with the duodenum, encircled by the pyloric sphincter, is the:', '["Pylorus", "Fundus", "Cardia", "Body"]'::jsonb, 0, 'The pylorus is the funnel-shaped terminal portion of the stomach that connects to the duodenum, regulated by the pyloric sphincter.', 'Pre-Council', '🎓', true),
(5934, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Gastric rugae are:', '["Longitudinal folds of gastric mucosa and submucosa that flatten as the stomach distends", "Permanent circular folds found only in the duodenum", "Folds found exclusively in the large intestine", "Finger-like projections of the small intestinal mucosa"]'::jsonb, 0, 'Rugae are temporary longitudinal folds of the empty stomach''s mucosa and submucosa that allow for expansion and flatten out as the stomach fills with food.', 'Pre-Council', '🎓', true),
(5935, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The first and shortest segment of the small intestine, largely retroperitoneal and receiving bile and pancreatic secretions, is the:', '["Duodenum", "Jejunum", "Ileum", "Cecum"]'::jsonb, 0, 'The duodenum, roughly 25 cm long, is mostly retroperitoneal and receives the combined bile and pancreatic ducts at the hepatopancreatic ampulla.', 'Pre-Council', '🎓', true),
(5936, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The hepatopancreatic ampulla (ampulla of Vater) is the site where:', '["The common bile duct and main pancreatic duct join before entering the duodenum", "The stomach empties into the duodenum", "The ileum joins the cecum", "The jejunum begins"]'::jsonb, 0, 'The hepatopancreatic ampulla is a dilated chamber formed by the union of the common bile duct and the main pancreatic duct, which then empties into the duodenum through the major duodenal papilla, regulated by the sphincter of Oddi.', 'Pre-Council', '🎓', true),
(5937, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Peyer''s patches, aggregates of lymphoid tissue important for mucosal immunity, are most concentrated in the:', '["Ileum", "Duodenum", "Jejunum", "Cecum"]'::jsonb, 0, 'Peyer''s patches are prominent lymphoid nodule aggregates within the lamina propria and submucosa of the ileum, monitoring intestinal antigens and pathogens.', 'Pre-Council', '🎓', true),
(5938, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The vitamin B12-intrinsic factor complex is absorbed specifically in the:', '["Terminal ileum", "Duodenum", "Jejunum", "Stomach"]'::jsonb, 0, 'Specific receptors for the intrinsic factor-B12 complex (cubilin) are located only in the terminal ileum, making this the exclusive site of B12 absorption.', 'Pre-Council', '🎓', true),
(5939, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The valve regulating the flow of contents from the small intestine into the large intestine and preventing reflux is the:', '["Ileocecal valve", "Pyloric sphincter", "Cardiac sphincter", "Internal anal sphincter"]'::jsonb, 0, 'The ileocecal valve controls passage of chyme from the ileum into the cecum and prevents backflow of colonic contents into the small intestine.', 'Pre-Council', '🎓', true),
(5940, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Haustra, the pouch-like segments visible along the colon, are formed largely due to the action of:', '["The teniae coli, three longitudinal bands of smooth muscle", "The circular muscle layer alone", "Villi projecting from the mucosa", "The greater omentum"]'::jsonb, 0, 'The teniae coli are three longitudinal muscle bands that are shorter than the colon itself, causing the colon wall to pucker into haustral pouches.', 'Pre-Council', '🎓', true),
(5941, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which structures increase the absorptive surface area of the small intestine at three progressively smaller structural levels?', '["Circular folds (plicae circulares), villi, and microvilli", "Haustra, teniae coli, and rugae", "Rugae, gastric pits, and crypts", "Omentum, mesentery, and peritoneum"]'::jsonb, 0, 'The small intestine amplifies surface area hierarchically: plicae circulares (macroscopic folds), villi (finger-like mucosal projections), and microvilli (brush border on individual enterocytes).', 'Pre-Council', '🎓', true),
(5942, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Each intestinal villus contains a central lymphatic capillary called a:', '["Lacteal", "Lymph node", "Peyer''s patch", "Crypt of Lieberkuhn"]'::jsonb, 0, 'The lacteal is a blind-ended lymphatic capillary within the core of each villus that absorbs chylomicrons and other lipid-transport particles.', 'Pre-Council', '🎓', true),
(5943, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The intestinal glands (crypts of Lieberkuhn) are located:', '["At the base of the villi, extending down into the lamina propria", "Within the submucosa exclusively", "Within the muscularis externa", "Only in the stomach"]'::jsonb, 0, 'Crypts of Lieberkuhn are tubular glands found between the bases of villi, extending into the lamina propria, and contain stem cells, Paneth cells, and secretory cells.', 'Pre-Council', '🎓', true),
(5944, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The greater omentum is a fold of peritoneum that:', '["Drapes over the abdominal organs from the greater curvature of the stomach, providing fat storage and immune protection", "Suspends the jejunum and ileum from the posterior abdominal wall", "Anchors the liver to the diaphragm", "Connects the stomach to the spleen only"]'::jsonb, 0, 'The greater omentum hangs from the greater curvature of the stomach and transverse colon, draping over abdominal viscera; it stores fat and contains immune cells that can wall off infection.', 'Pre-Council', '🎓', true),
(5945, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The mesentery proper suspends which portion of the GI tract from the posterior abdominal wall?', '["Jejunum and ileum", "Stomach", "Duodenum", "Transverse colon"]'::jsonb, 0, 'The mesentery proper is the fan-shaped peritoneal fold that anchors the mobile jejunum and ileum to the posterior abdominal wall while carrying their blood and lymphatic vessels.', 'Pre-Council', '🎓', true),
(5946, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Arterial blood supply to embryological foregut derivatives (stomach, proximal duodenum, liver, pancreas) arises from the:', '["Celiac trunk", "Superior mesenteric artery", "Inferior mesenteric artery", "Hepatic portal vein"]'::jsonb, 0, 'The celiac trunk (celiac artery) is the primary arterial supply to foregut-derived structures, giving rise to the left gastric, common hepatic, and splenic arteries.', 'Pre-Council', '🎓', true),
(5947, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The midgut, extending from the distal duodenum to roughly the proximal two-thirds of the transverse colon, is supplied by the:', '["Superior mesenteric artery", "Celiac trunk", "Inferior mesenteric artery", "Splenic artery"]'::jsonb, 0, 'The superior mesenteric artery supplies midgut derivatives, including the distal duodenum, jejunum, ileum, cecum, appendix, ascending colon, and proximal transverse colon.', 'Pre-Council', '🎓', true),
(5948, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The hindgut structures, including the distal transverse colon, descending colon, sigmoid colon, and upper rectum, are supplied by the:', '["Inferior mesenteric artery", "Superior mesenteric artery", "Celiac trunk", "Internal iliac artery alone"]'::jsonb, 0, 'The inferior mesenteric artery supplies hindgut derivatives, extending from the distal transverse colon through the upper rectum.', 'Pre-Council', '🎓', true),
(5949, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Venous blood from most of the GI tract drains via the hepatic portal vein primarily to the:', '["Liver, for metabolic processing before entering systemic circulation", "Inferior vena cava directly, bypassing the liver", "Lungs, for gas exchange", "Kidneys, for filtration"]'::jsonb, 0, 'The hepatic portal vein carries nutrient-rich blood from the stomach, intestines, pancreas, and spleen to the liver, where absorbed substances are processed before reaching systemic circulation.', 'Pre-Council', '🎓', true),
(5950, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The upper esophageal (pharyngoesophageal) sphincter is composed mainly of the:', '["Cricopharyngeus muscle", "Lower esophageal sphincter fibers", "Diaphragmatic crura", "Pyloric muscle"]'::jsonb, 0, 'The upper esophageal sphincter is formed primarily by the cricopharyngeus, a skeletal muscle that remains tonically contracted except during swallowing, belching, or vomiting.', 'Pre-Council', '🎓', true),
(5951, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which gastric mucosal cells secrete mucus that protects the stomach lining from autodigestion by acid and pepsin?', '["Surface mucous cells", "Parietal cells", "Chief cells", "G cells"]'::jsonb, 0, 'Surface mucous cells line the gastric pits and secrete a thick, alkaline mucus layer that protects the underlying epithelium from the highly acidic gastric lumen.', 'Pre-Council', '🎓', true),
(5952, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The appendix is attached to which part of the large intestine?', '["Cecum", "Ascending colon", "Sigmoid colon", "Rectum"]'::jsonb, 0, 'The vermiform appendix is a blind-ended tube arising from the posteromedial wall of the cecum, near the ileocecal valve.', 'Pre-Council', '🎓', true),
(5953, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The stomach is unique among GI organs in having a third layer of smooth muscle in its muscularis externa; the three layers are the:', '["Oblique, circular, and longitudinal layers", "Circular and longitudinal layers only", "Oblique and circular layers only", "Longitudinal and transverse layers"]'::jsonb, 0, 'Most of the GI tract has two muscle layers (inner circular, outer longitudinal), but the stomach has an additional innermost oblique layer that aids in the churning and mixing of food.', 'Pre-Council', '🎓', true),
(5954, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The internal anal sphincter, a ring of smooth (involuntary) muscle, is continuous proximally with the:', '["Circular muscle layer of the rectum", "External anal sphincter (skeletal muscle)", "Levator ani muscle", "Puborectalis muscle only"]'::jsonb, 0, 'The internal anal sphincter is simply a thickened continuation of the circular smooth muscle layer of the rectal wall and is under involuntary autonomic control.', 'Pre-Council', '🎓', true),
(5955, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a mechanically ventilated ICU patient receiving enteral nutrition, gastric residual volume is assessed via nasogastric tube primarily to evaluate:', '["Gastric motility and the risk of feeding intolerance or aspiration", "Liver synthetic function", "Exocrine pancreatic enzyme output", "Colonic transit time"]'::jsonb, 0, 'Gastric residual volume gives a bedside estimate of gastric emptying; persistently high residuals suggest delayed gastric motility and an increased risk of regurgitation and aspiration.', 'Pre-Council', '🎓', true),
(5956, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The teniae coli are absent from which part of the large intestine, where the longitudinal muscle instead forms a complete circumferential layer?', '["Rectum", "Ascending colon", "Transverse colon", "Sigmoid colon"]'::jsonb, 0, 'The three teniae coli fuse and spread out to form a complete, continuous longitudinal muscle layer around the rectum, which is why haustra are absent there.', 'Pre-Council', '🎓', true),
(5957, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which anatomical landmark marks the transition from columnar epithelium of the rectum/upper anal canal to stratified squamous epithelium of the lower anal canal?', '["Pectinate (dentate) line", "Ileocecal valve", "Linea alba", "Anorectal ring"]'::jsonb, 0, 'The pectinate (dentate) line marks the junction between the endodermally derived upper anal canal (columnar epithelium) and the ectodermally derived lower anal canal (stratified squamous epithelium), also marking a change in nerve and blood supply.', 'Pre-Council', '🎓', true),
(5958, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The parotid gland, the largest of the major salivary glands, produces saliva that is predominantly:', '["Serous, rich in salivary amylase", "Mucous", "Equally mixed serous and mucous", "Purely mucus with no enzyme content"]'::jsonb, 0, 'The parotid gland is a purely serous gland, producing a watery secretion high in salivary amylase (ptyalin) that begins starch digestion.', 'Pre-Council', '🎓', true),
(5959, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Compared with the parotid gland, the submandibular and sublingual glands produce:', '["Mixed seromucous secretions (submandibular mainly serous, sublingual mainly mucous)", "Purely serous secretions like the parotid", "Secretions with no digestive enzymes at all", "Only electrolyte-rich fluid without mucus"]'::jsonb, 0, 'The submandibular gland is a mixed gland with a serous predominance, while the sublingual gland is mixed with a mucous predominance, both differing from the purely serous parotid gland.', 'Pre-Council', '🎓', true),
(5960, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Salivary amylase (ptyalin) begins the digestion of:', '["Starch, cleaving it into smaller polysaccharides and maltose", "Dietary proteins", "Dietary fats", "Nucleic acids"]'::jsonb, 0, 'Salivary amylase hydrolyzes alpha-1,4 glycosidic bonds in starch, initiating carbohydrate digestion in the mouth before it is later completed by pancreatic amylase.', 'Pre-Council', '🎓', true),
(5961, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which component of saliva provides antibacterial protection by breaking down bacterial cell walls?', '["Lysozyme", "Ptyalin", "Lingual lipase", "Mucin"]'::jsonb, 0, 'Lysozyme is an antibacterial enzyme in saliva that hydrolyzes peptidoglycan in bacterial cell walls, contributing to oral defense against infection.', 'Pre-Council', '🎓', true),
(5962, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Average daily saliva production in a healthy adult is approximately:', '["1 to 1.5 liters", "100 to 200 mL", "5 to 6 liters", "300 to 500 mL"]'::jsonb, 0, 'The salivary glands normally produce roughly 1 to 1.5 liters of saliva per day, which lubricates the mouth, begins digestion, and protects oral tissues.', 'Pre-Council', '🎓', true),
(5963, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Parietal (oxyntic) cells of the gastric glands secrete:', '["Hydrochloric acid and intrinsic factor", "Pepsinogen and mucus", "Gastrin and histamine", "Bicarbonate only"]'::jsonb, 0, 'Parietal cells are unique among gastric gland cells in secreting both hydrochloric acid, via the H+/K+-ATPase proton pump, and intrinsic factor.', 'Pre-Council', '🎓', true),
(5964, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Chief (zymogenic) cells of the gastric glands secrete:', '["Pepsinogen and gastric lipase", "Hydrochloric acid", "Intrinsic factor", "Gastrin"]'::jsonb, 0, 'Chief cells secrete pepsinogen, the inactive precursor of pepsin, along with small amounts of gastric lipase, in response to vagal and hormonal stimulation.', 'Pre-Council', '🎓', true),
(5965, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Intrinsic factor, secreted by gastric parietal cells, is essential for absorption of which nutrient?', '["Vitamin B12, absorbed in the terminal ileum", "Iron, absorbed in the duodenum", "Calcium, absorbed in the jejunum", "Vitamin K, absorbed in the colon"]'::jsonb, 0, 'Intrinsic factor binds dietary vitamin B12, protecting it during transit and enabling its receptor-mediated absorption in the terminal ileum; loss of parietal cells (e.g., pernicious anemia) causes B12 deficiency.', 'Pre-Council', '🎓', true),
(5966, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'G cells, which secrete the hormone gastrin, are located predominantly in the:', '["Pyloric antrum", "Fundus", "Cardia", "Duodenum exclusively"]'::jsonb, 0, 'G cells are enteroendocrine cells concentrated in the gastric pyloric antrum (with smaller numbers in the duodenum) that secrete gastrin in response to distension, peptides, and vagal stimulation.', 'Pre-Council', '🎓', true),
(5967, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The primary physiological action of gastrin is to:', '["Stimulate parietal cell secretion of hydrochloric acid", "Inhibit gastric acid secretion", "Stimulate pancreatic bicarbonate secretion", "Stimulate bile release from the gallbladder"]'::jsonb, 0, 'Gastrin is the principal hormonal stimulus for gastric acid secretion, acting directly on parietal cells and indirectly by stimulating histamine release from ECL cells.', 'Pre-Council', '🎓', true),
(5968, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Histamine released from enterochromaffin-like (ECL) cells acts on parietal cells via which receptor to stimulate acid secretion, a target of common ICU stress-ulcer prophylaxis drugs?', '["H2 receptors", "H1 receptors", "Muscarinic M3 receptors", "CCK receptors"]'::jsonb, 0, 'Histamine binds parietal cell H2 receptors to potentiate acid secretion; H2-receptor antagonists (e.g., ranitidine, famotidine) exploit this pathway for stress ulcer prophylaxis.', 'Pre-Council', '🎓', true),
(5969, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Proton pump inhibitors used for stress ulcer prophylaxis in critically ill patients act by:', '["Irreversibly inhibiting the H+/K+-ATPase on the parietal cell luminal membrane", "Blocking histamine H2 receptors", "Chemically neutralizing existing gastric acid", "Inhibiting gastrin release from G cells"]'::jsonb, 0, 'Proton pump inhibitors covalently and irreversibly bind the H+/K+-ATPase (proton pump) in the parietal cell canalicular membrane, blocking the final common pathway of acid secretion.', 'Pre-Council', '🎓', true),
(5970, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Total daily gastric juice secretion in a healthy adult is approximately:', '["1.5 to 2.5 liters", "100 to 300 mL", "5 to 7 liters", "500 to 800 mL"]'::jsonb, 0, 'The stomach normally secretes roughly 1.5 to 2.5 liters of gastric juice per day, containing acid, pepsinogen, mucus, and intrinsic factor.', 'Pre-Council', '🎓', true),
(5971, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The normal pH range of stimulated gastric juice is approximately:', '["1.0 to 3.5", "5.0 to 6.5", "7.0 to 8.0", "4.0 to 5.0"]'::jsonb, 0, 'Gastric juice is highly acidic, typically in the range of pH 1 to 3.5, which activates pepsinogen and helps sterilize ingested food.', 'Pre-Council', '🎓', true),
(5972, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which hormone, released from duodenal I cells in response to fatty acids and amino acids in chyme, stimulates gallbladder contraction and pancreatic enzyme secretion?', '["Cholecystokinin (CCK)", "Secretin", "Gastrin", "Motilin"]'::jsonb, 0, 'Cholecystokinin is released from I cells of the duodenal mucosa in response to fat and protein digestion products; it stimulates gallbladder contraction, sphincter of Oddi relaxation, and pancreatic enzyme secretion.', 'Pre-Council', '🎓', true),
(5973, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Secretin, released from duodenal S cells in response to acidic chyme, primarily stimulates:', '["Pancreatic duct cells to secrete a bicarbonate-rich fluid", "Pancreatic acinar cells to secrete digestive enzymes", "Gallbladder contraction", "Gastric acid secretion"]'::jsonb, 0, 'Secretin is the primary stimulus for pancreatic ductal bicarbonate secretion, which neutralizes acidic chyme entering the duodenum and creates an optimal pH for pancreatic enzyme activity.', 'Pre-Council', '🎓', true),
(5974, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Beyond stimulating pancreatic bicarbonate secretion, secretin also has which effect relevant to gastric physiology?', '["It inhibits gastric acid secretion and gastric emptying", "It stimulates gastrin release", "It increases gastric motility", "It stimulates salivary gland secretion"]'::jsonb, 0, 'Secretin exerts an inhibitory ''enterogastrone'' effect, reducing gastric acid secretion and slowing gastric emptying to protect the duodenal mucosa from excess acid.', 'Pre-Council', '🎓', true),
(5975, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Pancreatic acinar cells secrete which of the following?', '["Digestive enzymes such as amylase, lipase, and trypsinogen", "A bicarbonate-rich fluid only", "Insulin and glucagon", "Bile salts"]'::jsonb, 0, 'Acinar cells constitute the exocrine functional units of the pancreas, synthesizing and secreting the full range of digestive enzymes and proenzymes.', 'Pre-Council', '🎓', true),
(5976, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Pancreatic duct (ductal and centroacinar) cells secrete a fluid rich in:', '["Bicarbonate, which neutralizes acidic chyme entering the duodenum", "Digestive enzymes", "Bile pigments", "Intrinsic factor"]'::jsonb, 0, 'Ductal cells secrete an alkaline, bicarbonate-rich fluid, stimulated primarily by secretin, that raises duodenal pH to levels favorable for pancreatic enzyme function.', 'Pre-Council', '🎓', true),
(5977, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Trypsinogen, secreted by pancreatic acinar cells, is activated to active trypsin in the duodenum by:', '["Enterokinase (enteropeptidase), a brush border enzyme", "Pepsin", "Bile salts", "Gastric acid"]'::jsonb, 0, 'Enterokinase, embedded in the duodenal brush border, cleaves trypsinogen to form active trypsin, which then autocatalytically activates additional trypsinogen and other pancreatic proenzymes.', 'Pre-Council', '🎓', true),
(5978, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Once trypsin is formed in the duodenum, it activates other pancreatic proenzymes, including:', '["Chymotrypsinogen and procarboxypeptidase", "Pepsinogen", "Salivary amylase", "Intrinsic factor"]'::jsonb, 0, 'Active trypsin cleaves and activates chymotrypsinogen to chymotrypsin and procarboxypeptidase to carboxypeptidase, amplifying the proteolytic cascade in the small intestine.', 'Pre-Council', '🎓', true),
(5979, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Beta cells of the pancreatic islets of Langerhans secrete:', '["Insulin", "Glucagon", "Somatostatin", "Pancreatic polypeptide exclusively"]'::jsonb, 0, 'Beta cells, the most numerous islet cell type, secrete insulin in response to rising blood glucose, promoting cellular glucose uptake and storage.', 'Pre-Council', '🎓', true),
(5980, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Alpha cells of the pancreatic islets secrete:', '["Glucagon", "Insulin", "Somatostatin", "Gastrin"]'::jsonb, 0, 'Alpha cells secrete glucagon in response to falling blood glucose, stimulating hepatic glycogenolysis and gluconeogenesis to raise blood glucose levels.', 'Pre-Council', '🎓', true),
(5981, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Bile is produced continuously by:', '["Hepatocytes in the liver", "The gallbladder", "The exocrine pancreas", "The duodenal mucosa"]'::jsonb, 0, 'Hepatocytes continuously synthesize and secrete bile into the biliary canaliculi; the gallbladder only stores and concentrates it between meals.', 'Pre-Council', '🎓', true),
(5982, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Between meals, bile produced by the liver is primarily:', '["Stored and concentrated in the gallbladder", "Excreted directly into the duodenum", "Broken down in the stomach", "Stored within the pancreas"]'::jsonb, 0, 'In the interdigestive period, the sphincter of Oddi remains largely closed, diverting hepatic bile into the gallbladder, where water and electrolytes are reabsorbed to concentrate it.', 'Pre-Council', '🎓', true),
(5983, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Bile salts aid fat digestion primarily by:', '["Emulsifying large fat globules into smaller droplets, increasing surface area for lipase action", "Chemically hydrolyzing triglycerides into fatty acids", "Activating pancreatic amylase", "Neutralizing gastric acid"]'::jsonb, 0, 'Bile salts are amphipathic molecules that emulsify dietary fat into small droplets, dramatically increasing the surface area available for pancreatic lipase to hydrolyze triglycerides.', 'Pre-Council', '🎓', true),
(5984, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Major components of bile include all of the following EXCEPT:', '["Digestive enzymes", "Bile salts", "Bilirubin", "Cholesterol and lecithin"]'::jsonb, 0, 'Bile contains bile salts, bilirubin, cholesterol, lecithin, water, and electrolytes, but it contains no digestive enzymes; its role in digestion is purely mechanical (emulsification).', 'Pre-Council', '🎓', true),
(5985, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Brunner''s glands, located in the submucosa of the duodenum, secrete an alkaline mucus that primarily functions to:', '["Protect the duodenal mucosa from acidic gastric chyme", "Digest dietary starch", "Absorb dietary fats", "Produce intrinsic factor"]'::jsonb, 0, 'Brunner''s glands secrete a viscous, alkaline mucus that buffers acidic chyme entering the duodenum from the stomach, protecting the duodenal mucosa from acid-peptic injury.', 'Pre-Council', '🎓', true),
(5986, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Goblet cells, distributed throughout the intestinal epithelium, secrete:', '["Mucus for lubrication and protection of the mucosal surface", "Digestive enzymes", "Bicarbonate ions", "Intrinsic factor"]'::jsonb, 0, 'Goblet cells are specialized unicellular glands that secrete mucin, forming a protective mucus layer over the intestinal epithelium that lubricates and shields the mucosa.', 'Pre-Council', '🎓', true),
(5987, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Mucous neck cells found within gastric glands secrete:', '["A thin, soluble mucus", "Hydrochloric acid", "Pepsinogen", "Gastrin"]'::jsonb, 0, 'Mucous neck cells, located in the neck region of gastric glands, secrete a thinner, more soluble mucus distinct from the thick protective mucus of surface mucous cells.', 'Pre-Council', '🎓', true),
(5988, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Motilin, a hormone secreted during the fasting state, is primarily responsible for:', '["Initiating the migrating motor complex, promoting interdigestive gastric and small bowel motility", "Stimulating gallbladder contraction after meals", "Inhibiting gastric acid secretion", "Stimulating insulin release"]'::jsonb, 0, 'Motilin is released cyclically from the small intestine during fasting and triggers the migrating motor complex, which sweeps residual contents and bacteria toward the colon between meals.', 'Pre-Council', '🎓', true),
(5989, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a critically ill patient receiving continuous enteral feeding via nasogastric tube, blunting of the migrating motor complex may contribute to:', '["Delayed gastric emptying and increased risk of feeding intolerance", "Increased gastric acid secretion only", "Enhanced nutrient absorption", "Increased bile flow"]'::jsonb, 0, 'Continuous feeding suppresses the cyclic fasting motility pattern (migrating motor complex), which can slow gastric emptying and predispose critically ill patients to feeding intolerance and higher gastric residual volumes.', 'Pre-Council', '🎓', true),
(5990, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Somatostatin, secreted by delta cells of the pancreatic islets and D cells of the GI mucosa, generally functions to:', '["Inhibit the secretion of numerous GI hormones and exocrine secretions", "Stimulate gastric acid secretion", "Stimulate insulin release", "Stimulate bile flow"]'::jsonb, 0, 'Somatostatin acts as a broad inhibitory regulator, suppressing gastrin, insulin, glucagon, and secretin release as well as gastric acid and pancreatic exocrine secretion.', 'Pre-Council', '🎓', true),
(5991, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Vasoactive intestinal peptide (VIP) generally:', '["Relaxes GI smooth muscle and stimulates intestinal secretion of water and electrolytes", "Stimulates gastric acid secretion", "Stimulates gallbladder contraction", "Inhibits pancreatic secretion"]'::jsonb, 0, 'VIP relaxes gastrointestinal smooth muscle (including sphincters) and promotes intestinal water and electrolyte secretion; its excess production, as in VIPoma, causes severe secretory diarrhea.', 'Pre-Council', '🎓', true),
(5992, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Gastric acid secretion occurs in three phases. The phase triggered by the sight, smell, and thought of food, mediated via the vagus nerve, is the:', '["Cephalic phase", "Gastric phase", "Intestinal phase", "Reflex phase"]'::jsonb, 0, 'The cephalic phase is initiated by sensory and cognitive stimuli associated with food and is mediated through vagal efferents acting on G cells and parietal cells, even before food reaches the stomach.', 'Pre-Council', '🎓', true),
(5993, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The gastric phase of acid secretion is primarily triggered by:', '["Distension of the stomach and the presence of peptides/amino acids stimulating gastrin release", "Acid in the duodenum", "Fat in the duodenum", "Thought of food"]'::jsonb, 0, 'The gastric phase accounts for the largest proportion of acid secretion and is driven by gastric distension and luminal peptides/amino acids that stimulate G cells to release gastrin.', 'Pre-Council', '🎓', true),
(5994, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The intestinal phase of gastric secretion regulation involves:', '["Initial stimulation by duodenal distension and amino acids, followed by inhibitory feedback as chyme becomes acidic and fatty", "Only stimulation of acid secretion, with no inhibitory component", "No hormonal involvement whatsoever", "Exclusive control by vagal stimulation"]'::jsonb, 0, 'The intestinal phase begins with mild stimulatory input from duodenal distension and amino acids but is followed by inhibitory feedback (via secretin, CCK, and the enterogastric reflex) as acidic, fatty chyme accumulates in the duodenum.', 'Pre-Council', '🎓', true),
(5995, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which enzyme, secreted in small amounts by lingual and gastric glands, begins minor digestion of triglycerides before chyme reaches the duodenum?', '["Lingual and gastric lipase", "Pancreatic amylase", "Trypsin", "Bile"]'::jsonb, 0, 'Lingual lipase (from glands under the tongue) and gastric lipase provide a minor, acid-stable contribution to fat digestion that begins in the mouth and stomach, ahead of the major pancreatic lipase phase in the duodenum.', 'Pre-Council', '🎓', true),
(5996, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Pepsinogen is converted to active pepsin by:', '["Exposure to hydrochloric acid, with further autocatalytic activation by existing pepsin", "Bile salts", "Enterokinase", "Secretin"]'::jsonb, 0, 'Gastric acid cleaves pepsinogen to expose the active pepsin enzyme, which then autocatalytically activates further pepsinogen molecules, rapidly amplifying proteolytic activity in the stomach.', 'Pre-Council', '🎓', true),
(5997, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a patient on long-term proton pump inhibitor therapy, which absorptive process may be impaired due to reduced gastric acidity?', '["Absorption of vitamin B12 and non-heme iron, which require an acidic environment for release/reduction", "Absorption of fat-soluble vitamins", "Absorption of glucose", "Absorption of bile salts"]'::jsonb, 0, 'Gastric acid is needed to release vitamin B12 from dietary protein and to reduce ferric (Fe3+) iron to the more absorbable ferrous (Fe2+) form; chronic acid suppression can impair both processes over time.', 'Pre-Council', '🎓', true),
(5998, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Dietary starch digestion is largely completed in the small intestine by the action of:', '["Pancreatic amylase, which breaks starch into maltose, maltotriose, and alpha-dextrins", "Salivary amylase alone", "Pepsin", "Bile salts"]'::jsonb, 0, 'Pancreatic amylase, secreted into the duodenum, continues and largely completes the breakdown of starch into smaller oligosaccharides, which are then further digested by brush border enzymes.', 'Pre-Council', '🎓', true),
(5999, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Brush border enzymes such as maltase, sucrase, and lactase complete carbohydrate digestion by breaking disaccharides down into:', '["Monosaccharides (glucose, galactose, fructose)", "Dipeptides", "Fatty acids", "Micelles"]'::jsonb, 0, 'Brush border disaccharidases hydrolyze disaccharides into their constituent monosaccharides, the final form in which carbohydrates are absorbed across the enterocyte membrane.', 'Pre-Council', '🎓', true),
(6000, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Glucose and galactose are absorbed across the apical (luminal) membrane of enterocytes via which transporter?', '["SGLT1, a sodium-dependent glucose cotransporter", "GLUT5", "GLUT2", "Simple diffusion"]'::jsonb, 0, 'SGLT1 uses the sodium gradient established by the basolateral Na+/K+-ATPase to actively cotransport glucose or galactose with sodium into the enterocyte, a form of secondary active transport.', 'Pre-Council', '🎓', true),
(6001, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Fructose is absorbed across the apical membrane of enterocytes primarily via:', '["GLUT5, by facilitated diffusion", "SGLT1", "Direct ATP-dependent active transport", "Paracellular diffusion only"]'::jsonb, 0, 'Unlike glucose and galactose, fructose is absorbed by the facilitated transporter GLUT5, which does not require sodium cotransport.', 'Pre-Council', '🎓', true),
(6002, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Absorbed monosaccharides exit the basolateral membrane of the enterocyte into the bloodstream primarily via:', '["GLUT2", "SGLT1", "GLUT5 exclusively", "Chylomicron formation"]'::jsonb, 0, 'GLUT2 is the principal basolateral transporter that allows glucose, galactose, and fructose to exit the enterocyte into the portal capillary blood by facilitated diffusion.', 'Pre-Council', '🎓', true),
(6003, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Protein digestion begins in the stomach through the action of:', '["Pepsin, which cleaves proteins into large polypeptides", "Trypsin", "Salivary amylase", "Pancreatic proteases"]'::jsonb, 0, 'Pepsin, activated from pepsinogen by gastric acid, begins protein digestion in the stomach by cleaving proteins into smaller polypeptides, though most protein digestion occurs later in the small intestine.', 'Pre-Council', '🎓', true),
(6004, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In the small intestine, pancreatic proteases such as trypsin and chymotrypsin are classified as:', '["Endopeptidases, cleaving internal peptide bonds within protein chains", "Exopeptidases only", "Brush border enzymes", "Lipases"]'::jsonb, 0, 'Trypsin and chymotrypsin are endopeptidases that cleave peptide bonds within the interior of protein chains, generating smaller peptide fragments for further digestion.', 'Pre-Council', '🎓', true),
(6005, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Carboxypeptidase, a pancreatic exopeptidase, digests proteins by:', '["Removing amino acids sequentially from the carboxyl-terminal end of peptide chains", "Cleaving internal peptide bonds", "Removing amino acids from the amino-terminal end", "Hydrolyzing ester bonds in triglycerides"]'::jsonb, 0, 'Carboxypeptidase is an exopeptidase that cleaves single amino acids off the carboxyl-terminal end of peptides, complementing the internal cleavage performed by endopeptidases.', 'Pre-Council', '🎓', true),
(6006, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Absorbed amino acids and small peptides enter enterocytes primarily via:', '["Sodium-dependent amino acid transporters and the peptide transporter PepT1 for di- and tripeptides", "Simple diffusion only", "Chylomicron formation", "SGLT1"]'::jsonb, 0, 'Amino acids are absorbed via multiple sodium-dependent cotransport systems, while di- and tripeptides are absorbed intact via the proton-coupled transporter PepT1 and hydrolyzed intracellularly.', 'Pre-Council', '🎓', true),
(6007, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The majority of dietary fat digestion occurs via which enzyme in the duodenum, which requires the cofactor colipase for activity?', '["Pancreatic lipase", "Pepsin", "Trypsin", "Salivary amylase"]'::jsonb, 0, 'Pancreatic lipase, aided by colipase (which anchors it to the fat droplet surface and displaces bile salts that would otherwise inhibit it), is the principal enzyme responsible for triglyceride digestion.', 'Pre-Council', '🎓', true),
(6008, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Emulsification of dietary fat by bile salts is a mechanical process that:', '["Increases the surface area of fat globules available for enzymatic hydrolysis", "Chemically breaks ester bonds within triglycerides", "Converts triglycerides directly into micelles without enzymatic action", "Directly activates pancreatic lipase"]'::jsonb, 0, 'Emulsification breaks large fat globules into many smaller droplets, greatly increasing the surface area exposed to pancreatic lipase without itself breaking any chemical bonds.', 'Pre-Council', '🎓', true),
(6009, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'After pancreatic lipase hydrolyzes triglycerides into monoglycerides and free fatty acids, these products combine with bile salts to form:', '["Micelles, which transport lipids to the enterocyte brush border for absorption", "Chylomicrons", "VLDL particles", "Lacteals"]'::jsonb, 0, 'Micelles are small aggregates of bile salts, monoglycerides, and fatty acids that solubilize lipid digestion products and ferry them through the aqueous intestinal lumen to the enterocyte surface.', 'Pre-Council', '🎓', true),
(6010, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Within the enterocyte, absorbed monoglycerides and fatty acids are re-esterified into triglycerides and packaged with cholesterol and apolipoproteins into:', '["Chylomicrons", "Micelles", "Bile salts", "Glycogen granules"]'::jsonb, 0, 'Enterocytes resynthesize triglycerides from absorbed fatty acids and monoglycerides, then package them with cholesterol, phospholipids, and apolipoprotein B-48 into chylomicrons for transport.', 'Pre-Council', '🎓', true),
(6011, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Chylomicrons formed in enterocytes are transported into the:', '["Lacteals (lymphatic capillaries) of the villi, entering systemic circulation via the thoracic duct", "Hepatic portal vein directly, like amino acids and glucose", "Hepatic artery", "Common bile duct"]'::jsonb, 0, 'Chylomicrons are too large to enter blood capillaries directly; they are absorbed into the lacteals and travel through the lymphatic system to the thoracic duct, which empties into the left subclavian vein, bypassing the portal circulation.', 'Pre-Council', '🎓', true),
(6012, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Compared with carbohydrates and proteins, absorbed dietary lipids are unique in being transported primarily via:', '["The lymphatic system rather than the hepatic portal vein", "The hepatic portal vein exclusively", "The hepatic artery", "Direct diffusion into systemic capillaries"]'::jsonb, 0, 'Unlike monosaccharides and amino acids, which enter portal blood directly, most absorbed lipid (as chylomicrons) is routed through the lymphatics before reaching systemic circulation.', 'Pre-Council', '🎓', true),
(6013, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Fat-soluble vitamins (A, D, E, K) are absorbed:', '["Along with dietary fat, incorporated into micelles, dependent on adequate bile salts and pancreatic lipase", "Independently of dietary fat, via active transport", "Only in the stomach", "Via the same transporter used for vitamin B12"]'::jsonb, 0, 'Fat-soluble vitamin absorption parallels that of dietary lipids, requiring micelle formation and therefore adequate bile salt secretion and pancreatic lipase activity; deficiency of either can impair absorption of these vitamins.', 'Pre-Council', '🎓', true),
(6014, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a critically ill patient with biliary obstruction or severe exocrine pancreatic insufficiency, which class of nutrients is most likely to show impaired absorption, leading to steatorrhea?', '["Dietary fats and fat-soluble vitamins", "Carbohydrates", "Water-soluble vitamins", "Simple sugars"]'::jsonb, 0, 'Without adequate bile salts (emulsification) or pancreatic lipase (hydrolysis), fat digestion and absorption are impaired, resulting in fat malabsorption, steatorrhea, and secondary fat-soluble vitamin deficiency.', 'Pre-Council', '🎓', true),
(6015, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Water absorption in the GI tract occurs mainly by which mechanism, following the absorption of solutes such as sodium?', '["Osmosis, secondary to active transport of sodium and other solutes", "Active transport requiring a dedicated water pump", "Facilitated diffusion via GLUT2", "Pinocytosis only"]'::jsonb, 0, 'Water absorption is passive, following osmotic gradients created by the active transport of sodium and other solutes across the intestinal epithelium.', 'Pre-Council', '🎓', true),
(6016, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The majority of water absorbed from the GI tract each day is absorbed in the:', '["Small intestine", "Stomach", "Large intestine", "Esophagus"]'::jsonb, 0, 'Although the colon absorbs a substantial proportion of remaining fluid, the small intestine absorbs the great majority of the total daily fluid load (including secretions and ingested fluid) due to its large surface area.', 'Pre-Council', '🎓', true),
(6017, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Sodium absorption across the intestinal epithelium is closely linked to the absorption of which nutrients via cotransport mechanisms?', '["Glucose and amino acids", "Fatty acids only", "Fat-soluble vitamins", "Bile salts"]'::jsonb, 0, 'Sodium-dependent cotransporters such as SGLT1 and various amino acid transporters couple sodium movement to glucose and amino acid absorption, a principle underlying oral rehydration therapy.', 'Pre-Council', '🎓', true),
(6018, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Approximately what percentage of fluid entering the colon each day is normally absorbed, leaving only a small residual volume in the stool?', '["Approximately 90%", "Approximately 10%", "Approximately 50%", "Approximately 25%"]'::jsonb, 0, 'Of the roughly 1.5-2 liters of fluid that typically enters the colon daily, the colon absorbs about 90% of it, leaving only about 100-200 mL to be excreted in normal stool.', 'Pre-Council', '🎓', true),
(6019, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In critically ill patients receiving vasopressor therapy, enteral feeding intolerance and malabsorption may result from:', '["Reduced splanchnic blood flow causing mucosal ischemia and impaired villous function", "Increased bile salt production", "Enhanced motilin release", "Increased pancreatic enzyme secretion"]'::jsonb, 0, 'Vasopressors preferentially shunt blood away from the splanchnic circulation to preserve perfusion of vital organs, which can cause intestinal mucosal ischemia, impaired villous absorptive function, and feeding intolerance.', 'Pre-Council', '🎓', true),
(6020, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Prolonged bowel rest (fasting) in critically ill patients contributes to malabsorption upon reintroduction of enteral feeding primarily due to:', '["Villous atrophy and reduced brush border enzyme activity from lack of luminal nutrient stimulation", "Increased bile salt synthesis", "Hypertrophy of intestinal mucosa", "Increased gastric acid secretion"]'::jsonb, 0, 'Without luminal nutrients to stimulate mucosal turnover, prolonged fasting leads to villous atrophy and reduced brush border enzyme expression, impairing digestion and absorption when feeding resumes; this is a key rationale for early enteral nutrition in critical illness.', 'Pre-Council', '🎓', true),
(6021, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Refeeding syndrome, a risk when reintroducing nutrition to severely malnourished critically ill patients, is characterized primarily by:', '["A shift of phosphate, potassium, and magnesium into cells driven by insulin release upon carbohydrate reintroduction", "Excessive gastric acid secretion", "Bile duct obstruction", "Excess chylomicron formation"]'::jsonb, 0, 'Reintroducing carbohydrates stimulates insulin release, which drives phosphate, potassium, and magnesium intracellularly, producing potentially life-threatening hypophosphatemia, hypokalemia, and hypomagnesemia.', 'Pre-Council', '🎓', true),
(6022, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The migrating motor complex (MMC), a cyclic pattern of motility occurring between meals, functions primarily to:', '["Sweep undigested residue and bacteria toward the colon, preventing bacterial overgrowth", "Mix chyme with digestive enzymes during active meals", "Stimulate gallbladder emptying only", "Absorb nutrients directly"]'::jsonb, 0, 'The MMC is a housekeeping motility pattern occurring during fasting that clears residual debris, secretions, and bacteria from the stomach and small intestine, helping prevent small intestinal bacterial overgrowth.', 'Pre-Council', '🎓', true),
(6023, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Segmentation contractions in the small intestine primarily function to:', '["Mix chyme with digestive secretions and increase its contact with the absorptive mucosa", "Propel contents rapidly toward the colon", "Empty the stomach", "Concentrate bile within the gallbladder"]'::jsonb, 0, 'Segmentation consists of localized, rhythmic contractions of circular muscle that mix and churn chyme back and forth rather than propelling it forward, maximizing exposure to digestive enzymes and the absorptive surface.', 'Pre-Council', '🎓', true),
(6024, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Peristalsis is best described as:', '["Coordinated waves of circular and longitudinal muscle contraction that propel contents forward through the GI tract", "Stationary contractions that mix contents in place", "Reverse contractions that empty the stomach", "Contraction of only the longitudinal muscle layer"]'::jsonb, 0, 'Peristalsis involves sequential contraction of circular muscle behind the bolus and relaxation ahead of it, coordinated with longitudinal muscle activity, to propel luminal contents distally.', 'Pre-Council', '🎓', true),
(6025, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The primary site of absorption for most water-soluble vitamins, excluding vitamin B12, is the:', '["Proximal small intestine (duodenum and jejunum)", "Terminal ileum", "Stomach", "Large intestine"]'::jsonb, 0, 'Most water-soluble vitamins (e.g., thiamine, riboflavin, folate, vitamin C) are absorbed in the proximal small intestine, in contrast to vitamin B12, which requires the terminal ileum.', 'Pre-Council', '🎓', true),
(6026, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Iron absorption occurs predominantly in the duodenum and is enhanced by:', '["The acidic environment of the stomach, which helps convert ferric (Fe3+) iron to the more absorbable ferrous (Fe2+) form", "Alkaline pancreatic secretions", "Bile salts", "Intrinsic factor"]'::jsonb, 0, 'Gastric acid and reducing agents such as vitamin C help convert dietary ferric iron to the ferrous form, which is more readily transported into duodenal enterocytes via the divalent metal transporter.', 'Pre-Council', '🎓', true),
(6027, 'Integumentary and Gastro-Intestinal Systems', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Calcium absorption in the small intestine is enhanced by:', '["Active vitamin D (calcitriol), which upregulates calcium-binding proteins in enterocytes", "Bile salts alone", "Gastric acid alone", "Intrinsic factor"]'::jsonb, 0, 'Calcitriol, the active form of vitamin D, increases intestinal calcium absorption by inducing synthesis of calcium-binding protein (calbindin) and calcium channels in the enterocyte brush border.', 'Pre-Council', '🎓', true),
(6028, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which part of a multipolar neuron has the lowest threshold for action potential generation because of its high density of voltage-gated sodium channels?', '["Axon hillock", "Dendrite", "Cell body (soma)", "Presynaptic terminal"]'::jsonb, 0, 'The axon hillock (initial segment) has the highest density of voltage-gated Na+ channels, giving it the lowest threshold and making it the site where action potentials are normally triggered.', 'Pre-Council', '🎓', true),
(6029, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which neuroglial cell type is primarily responsible for forming the myelin sheath around axons in the central nervous system?', '["Astrocyte", "Oligodendrocyte", "Microglia", "Ependymal cell"]'::jsonb, 1, 'Oligodendrocytes myelinate multiple CNS axons simultaneously, in contrast to Schwann cells, which myelinate only one segment of one axon in the PNS.', 'Pre-Council', '🎓', true),
(6030, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient sustains a peripheral nerve injury. Which glial cell supports remyelination and regeneration of the injured axon?', '["Schwann cell", "Astrocyte", "Oligodendrocyte", "Microglia"]'::jsonb, 0, 'Schwann cells myelinate peripheral axons and form a regeneration pathway (band of Büngner) that supports axonal regrowth after peripheral nerve injury.', 'Pre-Council', '🎓', true),
(6031, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which glial cell forms tight junctions with capillary endothelial cells and contributes end-feet processes that help maintain the blood-brain barrier?', '["Microglia", "Ependymal cell", "Astrocyte", "Schwann cell"]'::jsonb, 2, 'Astrocyte end-feet surround brain capillaries and induce tight junction formation in endothelial cells, helping to maintain the selective permeability of the blood-brain barrier.', 'Pre-Council', '🎓', true),
(6032, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which CNS glial cell functions as the resident phagocyte and mediates the immune/inflammatory response to injury or infection?', '["Oligodendrocyte", "Microglia", "Astrocyte", "Ependymal cell"]'::jsonb, 1, 'Microglia are derived from monocyte precursors and act as the CNS''s resident macrophages, phagocytosing debris and pathogens and mediating neuroinflammation.', 'Pre-Council', '🎓', true),
(6033, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Ependymal cells lining the ventricles primarily function to', '["myelinate central axons", "produce and help circulate cerebrospinal fluid", "form the blood-brain barrier", "phagocytose cellular debris"]'::jsonb, 1, 'Ciliated ependymal cells, together with choroid plexus capillaries, produce CSF and their cilia help propel it through the ventricular system.', 'Pre-Council', '🎓', true),
(6034, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A neuron with a single dendrite and a single axon extending from opposite poles of the cell body, found in the retina and olfactory epithelium, is classified as', '["multipolar", "bipolar", "unipolar (pseudounipolar)", "anaxonic"]'::jsonb, 1, 'Bipolar neurons have exactly one dendrite and one axon and are characteristic of special sensory pathways such as the retina, olfactory epithelium, and vestibulocochlear ganglia.', 'Pre-Council', '🎓', true),
(6035, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Sensory neurons in the dorsal root ganglia, whose single process splits into a peripheral and a central branch, are classified structurally as', '["multipolar neurons", "bipolar neurons", "unipolar (pseudounipolar) neurons", "interneurons only"]'::jsonb, 2, 'Dorsal root ganglion sensory neurons are unipolar (pseudounipolar): a single process leaves the cell body and bifurcates into peripheral and central branches.', 'Pre-Council', '🎓', true),
(6036, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The most common structural type of neuron in the CNS, possessing many dendrites and a single axon, is the', '["bipolar neuron", "unipolar neuron", "multipolar neuron", "anaxonic neuron"]'::jsonb, 2, 'Multipolar neurons, which include most motor neurons and interneurons, have numerous dendrites and one axon and are the most abundant neuron type in the CNS.', 'Pre-Council', '🎓', true),
(6037, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'During the resting state, the neuronal membrane potential of approximately -70 mV is maintained mainly by which mechanism?', '["Voltage-gated Na+ channel opening", "K+ leak channels and the Na+/K+-ATPase pump", "Ca2+ influx through voltage-gated channels", "Cl- efflux through ligand-gated channels"]'::jsonb, 1, 'Resting membrane potential is established largely by K+ leak channels (K+ moving down its concentration gradient) and is maintained long-term by the Na+/K+-ATPase, which pumps 3 Na+ out for every 2 K+ in.', 'Pre-Council', '🎓', true),
(6038, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The rapid depolarization phase of a neuronal action potential is caused by', '["efflux of potassium ions", "influx of sodium ions through voltage-gated channels", "influx of chloride ions", "efflux of calcium ions"]'::jsonb, 1, 'When threshold is reached, voltage-gated Na+ channels open rapidly, allowing Na+ influx that drives the membrane potential toward a positive value (depolarization).', 'Pre-Council', '🎓', true),
(6039, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Repolarization of the neuronal membrane following an action potential occurs mainly because of', '["continued sodium influx", "potassium efflux as voltage-gated K+ channels open and Na+ channels inactivate", "chloride influx", "activation of the sodium-potassium pump alone"]'::jsonb, 1, 'As voltage-gated Na+ channels inactivate and voltage-gated K+ channels open, K+ moves out of the cell, returning the membrane potential toward resting levels.', 'Pre-Council', '🎓', true),
(6040, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'During the absolute refractory period of a neuron, a second action potential cannot be generated regardless of stimulus strength because', '["the membrane is hyperpolarized below resting potential", "voltage-gated sodium channels are inactivated", "potassium channels are closed", "the axon has run out of neurotransmitter"]'::jsonb, 1, 'During the absolute refractory period, voltage-gated Na+ channels are in an inactivated state and cannot reopen until the membrane repolarizes, making a new action potential impossible no matter how strong the stimulus.', 'Pre-Council', '🎓', true),
(6041, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Saltatory conduction, which allows an action potential to travel rapidly along a myelinated axon, occurs because the impulse', '["spreads continuously along the entire membrane", "jumps from one node of Ranvier to the next", "travels only in unmyelinated fibers", "is generated simultaneously at multiple points along the axon"]'::jsonb, 1, 'In myelinated axons, voltage-gated channels are concentrated at the nodes of Ranvier, so the action potential appears to jump node to node, greatly increasing conduction velocity while conserving energy.', 'Pre-Council', '🎓', true),
(6042, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which neurotransmitter is released at the neuromuscular junction to trigger skeletal muscle contraction?', '["Glutamate", "Gamma-aminobutyric acid (GABA)", "Acetylcholine", "Serotonin"]'::jsonb, 2, 'Acetylcholine is released from somatic motor neuron terminals and binds nicotinic receptors on the motor end plate, initiating skeletal muscle depolarization and contraction.', 'Pre-Council', '🎓', true),
(6043, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The principal excitatory neurotransmitter in the central nervous system is', '["glycine", "glutamate", "GABA", "dopamine"]'::jsonb, 1, 'Glutamate is the main excitatory neurotransmitter in the CNS, acting on ionotropic (AMPA, NMDA) and metabotropic receptors to depolarize postsynaptic neurons.', 'Pre-Council', '🎓', true),
(6044, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'GABA is the principal inhibitory neurotransmitter in the brain and produces its inhibitory effect primarily by', '["opening ligand-gated chloride channels that hyperpolarize the membrane", "opening sodium channels", "blocking acetylcholinesterase", "stimulating calcium influx at the presynaptic terminal"]'::jsonb, 0, 'GABA binding to GABA-A receptors opens chloride channels; Cl- influx hyperpolarizes the postsynaptic membrane, moving it farther from threshold and inhibiting firing.', 'Pre-Council', '🎓', true),
(6045, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Degeneration of dopaminergic neurons in the substantia nigra is most closely associated with which neurotransmitter deficiency disorder?', '["Alzheimer''s disease", "Parkinson''s disease", "Myasthenia gravis", "Huntington''s disease"]'::jsonb, 1, 'Parkinson''s disease results from progressive loss of dopamine-producing neurons in the substantia nigra pars compacta, leading to bradykinesia, rigidity, and tremor.', 'Pre-Council', '🎓', true),
(6046, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'An excitatory postsynaptic potential (EPSP) makes a neuron more likely to fire because it', '["hyperpolarizes the postsynaptic membrane", "depolarizes the postsynaptic membrane toward threshold", "blocks all sodium channels", "increases the refractory period"]'::jsonb, 1, 'An EPSP is a local depolarization of the postsynaptic membrane, typically produced by Na+ influx, that brings the membrane potential closer to the threshold needed to fire an action potential.', 'Pre-Council', '🎓', true),
(6047, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The summation of several subthreshold impulses arriving at a postsynaptic neuron from different presynaptic neurons at nearly the same time is called', '["temporal summation", "spatial summation", "saltatory summation", "reciprocal summation"]'::jsonb, 1, 'Spatial summation occurs when postsynaptic potentials from multiple different synapses combine simultaneously to reach threshold, as opposed to temporal summation from repeated impulses at one synapse.', 'Pre-Council', '🎓', true),
(6048, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The neural tube, from which the entire central nervous system develops, forms embryologically from which germ layer?', '["Endoderm", "Mesoderm", "Ectoderm (neuroectoderm)", "Trophoblast"]'::jsonb, 2, 'The neural tube forms by neurulation from the neuroectoderm, a specialized region of the embryonic ectoderm, giving rise to the entire CNS.', 'Pre-Council', '🎓', true),
(6049, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Neural crest cells, which migrate away from the closing neural tube, primarily give rise to', '["the cerebral cortex and cerebellum", "peripheral ganglia, Schwann cells, and the adrenal medulla", "the choroid plexus and ependyma", "the ventricular system"]'::jsonb, 1, 'Neural crest cells differentiate into structures of the peripheral nervous system (dorsal root and autonomic ganglia, Schwann cells) as well as the adrenal medulla and melanocytes.', 'Pre-Council', '🎓', true),
(6050, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'At the three-primary-vesicle stage of brain development, the prosencephalon, mesencephalon, and rhombencephalon later give rise respectively to the', '["forebrain, midbrain, and hindbrain", "spinal cord, cerebellum, and medulla", "cerebrum, pons, and spinal cord only", "hindbrain, forebrain, and midbrain"]'::jsonb, 0, 'The three primary brain vesicles correspond to the forebrain (prosencephalon), midbrain (mesencephalon), and hindbrain (rhombencephalon), which further subdivide into the five secondary vesicles.', 'Pre-Council', '🎓', true),
(6051, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The telencephalon, a secondary brain vesicle derived from the prosencephalon, develops into the', '["cerebral hemispheres", "medulla oblongata", "pons and cerebellum", "spinal cord"]'::jsonb, 0, 'The prosencephalon divides into the telencephalon, which becomes the cerebral hemispheres (cerebral cortex, basal ganglia), and the diencephalon, which becomes the thalamus and hypothalamus.', 'Pre-Council', '🎓', true),
(6052, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The myelencephalon, one of the five secondary brain vesicles, ultimately develops into the', '["cerebellum", "pons", "medulla oblongata", "thalamus"]'::jsonb, 2, 'The rhombencephalon divides into the metencephalon (pons and cerebellum) and the myelencephalon, which develops into the medulla oblongata.', 'Pre-Council', '🎓', true),
(6053, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A neural tube defect resulting from failure of the caudal neural tube to close is', '["anencephaly", "spina bifida", "hydrocephalus", "microcephaly"]'::jsonb, 1, 'Spina bifida results from incomplete closure of the caudal neural tube, whereas anencephaly results from failure of closure at the rostral (cranial) end; both are linked to maternal folic acid deficiency.', 'Pre-Council', '🎓', true),
(6054, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Gray matter of the central nervous system is composed mainly of', '["myelinated axons only", "neuron cell bodies, dendrites, and unmyelinated fibers", "connective tissue and blood vessels only", "Schwann cell sheaths"]'::jsonb, 1, 'Gray matter contains neuron cell bodies, dendrites, synapses, and unmyelinated or minimally myelinated processes, giving it a darker appearance than myelin-rich white matter.', 'Pre-Council', '🎓', true),
(6055, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In the peripheral nervous system, a cluster of neuron cell bodies located outside the CNS is called a', '["nucleus", "tract", "ganglion", "column"]'::jsonb, 2, 'A ganglion is a collection of neuron cell bodies in the PNS, analogous to a nucleus, which is a collection of cell bodies within the CNS.', 'Pre-Council', '🎓', true),
(6056, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A bundle of axons that carries information between two regions within the central nervous system is called a', '["nerve", "tract", "ganglion", "plexus"]'::jsonb, 1, 'A tract is a bundle of axons within the CNS; the equivalent bundle of axons in the PNS is called a nerve.', 'Pre-Council', '🎓', true),
(6057, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The blood-brain barrier restricts passage of most substances from the blood into brain tissue mainly because of', '["fenestrated capillaries in the brain", "tight junctions between cerebral capillary endothelial cells", "the presence of a thick basement membrane alone", "absence of capillaries in brain tissue"]'::jsonb, 1, 'Unlike capillaries elsewhere in the body, cerebral capillary endothelial cells are joined by continuous tight junctions, which sharply limit paracellular diffusion of substances into brain tissue.', 'Pre-Council', '🎓', true),
(6058, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'At a typical chemical synapse, neurotransmitter released from the presynaptic terminal must diffuse across the', '["myelin sheath", "synaptic cleft", "node of Ranvier", "axon hillock"]'::jsonb, 1, 'The synaptic cleft is the narrow space separating the presynaptic and postsynaptic membranes across which neurotransmitter diffuses to bind postsynaptic receptors.', 'Pre-Council', '🎓', true),
(6059, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Arranged from outermost to innermost, the correct order of the three meningeal layers surrounding the brain and spinal cord is', '["pia mater, arachnoid mater, dura mater", "arachnoid mater, dura mater, pia mater", "dura mater, arachnoid mater, pia mater", "dura mater, pia mater, arachnoid mater"]'::jsonb, 2, 'From outside in, the meninges are the dura mater (tough outer layer), arachnoid mater (middle, web-like layer), and pia mater (innermost, adheres directly to neural tissue).', 'Pre-Council', '🎓', true),
(6060, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cerebrospinal fluid circulates within the', '["epidural space", "subdural space", "subarachnoid space", "potential space between periosteum and dura"]'::jsonb, 2, 'CSF fills the subarachnoid space, located between the arachnoid mater and the pia mater, cushioning the brain and spinal cord.', 'Pre-Council', '🎓', true),
(6061, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'An epidural hematoma classically results from injury to which structure, located in the potential space between the skull and the dura mater?', '["A bridging vein", "The middle meningeal artery", "The superior sagittal sinus", "The internal carotid artery"]'::jsonb, 1, 'Epidural hematomas are most often arterial, classically from laceration of the middle meningeal artery after temporal bone fracture, producing rapid hematoma expansion in the epidural (extradural) space.', 'Pre-Council', '🎓', true),
(6062, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A subdural hematoma most commonly results from tearing of', '["bridging veins between the dura and arachnoid", "the middle meningeal artery", "the anterior communicating artery", "the vertebral artery"]'::jsonb, 0, 'Subdural hematomas typically arise from tearing of bridging veins that cross the subdural space, often after acceleration-deceleration injury, and tend to accumulate more slowly than epidural bleeds.', 'Pre-Council', '🎓', true),
(6063, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The dural fold that separates the two cerebral hemispheres is the', '["tentorium cerebelli", "falx cerebri", "falx cerebelli", "diaphragma sellae"]'::jsonb, 1, 'The falx cerebri is a sickle-shaped dural fold projecting into the longitudinal fissure, separating the right and left cerebral hemispheres.', 'Pre-Council', '🎓', true),
(6064, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which frontal lobe region, typically in the dominant (usually left) hemisphere, is responsible for the motor production of speech?', '["Wernicke''s area", "Broca''s area", "The primary somatosensory cortex", "The angular gyrus"]'::jsonb, 1, 'Broca''s area, located in the inferior frontal gyrus of the dominant hemisphere, governs the motor programming of speech; damage produces non-fluent (expressive) aphasia with preserved comprehension.', 'Pre-Council', '🎓', true),
(6065, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Damage to Wernicke''s area, located in the posterior superior temporal gyrus of the dominant hemisphere, characteristically produces', '["inability to produce any speech sounds", "fluent but nonsensical speech with impaired comprehension", "loss of voluntary limb movement", "loss of visual field on the opposite side"]'::jsonb, 1, 'Wernicke''s area is responsible for language comprehension; its damage causes fluent but meaningless (receptive/sensory) aphasia, with the patient often unaware their speech makes no sense.', 'Pre-Council', '🎓', true),
(6066, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The primary motor cortex, responsible for initiating voluntary movement, is located in the', '["precentral gyrus of the frontal lobe", "postcentral gyrus of the parietal lobe", "superior temporal gyrus", "occipital pole"]'::jsonb, 0, 'The precentral gyrus, immediately anterior to the central sulcus in the frontal lobe, contains the primary motor cortex, which controls contralateral voluntary skeletal muscle movement.', 'Pre-Council', '🎓', true),
(6067, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The primary somatosensory cortex, which processes touch, pressure, and proprioceptive information from the contralateral body, is located in the', '["precentral gyrus", "postcentral gyrus", "occipital lobe", "temporal lobe"]'::jsonb, 1, 'The postcentral gyrus of the parietal lobe is the primary somatosensory cortex, receiving somatosensory input relayed from the thalamus.', 'Pre-Council', '🎓', true),
(6068, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The occipital lobe is primarily responsible for', '["primary auditory processing", "primary visual processing", "expressive language", "voluntary motor initiation"]'::jsonb, 1, 'The occipital lobe contains the primary visual cortex around the calcarine sulcus and is responsible for processing visual input from the optic radiations.', 'Pre-Council', '🎓', true),
(6069, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The temporal lobe contains structures responsible for which combination of functions?', '["Primary vision and motor planning", "Primary hearing, memory (via the hippocampus), and olfaction", "Primary somatosensation and proprioception", "Autonomic regulation and pituitary control"]'::jsonb, 1, 'The temporal lobe houses the primary auditory cortex, the hippocampus (critical for memory consolidation), and structures involved in olfactory processing.', 'Pre-Council', '🎓', true),
(6070, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient develops a lesion affecting the substantia nigra and basal ganglia circuits. Which clinical feature is most expected?', '["Bradykinesia and rigidity", "Loss of pain sensation below a spinal level", "Expressive aphasia", "Homonymous hemianopia"]'::jsonb, 0, 'The basal ganglia regulate the initiation and smoothness of voluntary movement and muscle tone; degeneration of the substantia nigra dopaminergic pathway (as in Parkinson''s disease) produces bradykinesia and rigidity.', 'Pre-Council', '🎓', true),
(6071, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The thalamus is best described functionally as the', '["primary center for temperature and appetite regulation", "major relay and integration station for sensory information (except olfaction) en route to the cerebral cortex", "site of cardiac and respiratory vital centers", "coordination center for balance and fine motor control"]'::jsonb, 1, 'Nearly all sensory modalities except smell synapse in the thalamus before being relayed to the appropriate cortical area, making it the brain''s principal sensory relay station.', 'Pre-Council', '🎓', true),
(6072, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The hypothalamus links the nervous and endocrine systems and regulates all of the following EXCEPT', '["body temperature", "circadian rhythm and sleep-wake cycle", "hunger and thirst", "voluntary skeletal muscle coordination"]'::jsonb, 3, 'The hypothalamus regulates autonomic and endocrine functions (temperature, hunger, thirst, circadian rhythm, and pituitary control via the infundibulum); coordination of voluntary movement is a cerebellar function.', 'Pre-Council', '🎓', true),
(6073, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with cerebellar injury is most likely to present with which clinical findings?', '["Ataxia, intention tremor, and dysmetria", "Expressive aphasia and right-sided weakness", "Loss of pain and temperature sensation", "Fixed and dilated pupil"]'::jsonb, 0, 'The cerebellum coordinates the timing and force of movement and maintains balance; damage produces ataxia, intention tremor, dysmetria, and dysdiadochokinesia rather than paralysis.', 'Pre-Council', '🎓', true),
(6074, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which brainstem structure contains the superior and inferior colliculi, involved in visual and auditory reflexes respectively?', '["Medulla oblongata", "Pons", "Midbrain (mesencephalon)", "Diencephalon"]'::jsonb, 2, 'The midbrain''s tectum contains the superior colliculi (visual reflexes, e.g., tracking) and inferior colliculi (auditory reflexes); the midbrain also houses the nuclei of cranial nerves III and IV.', 'Pre-Council', '🎓', true),
(6075, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The pneumotaxic and apneustic centers, which help regulate the rhythm and depth of breathing, are located in the', '["medulla oblongata", "pons", "cerebellum", "hypothalamus"]'::jsonb, 1, 'The pons contains the pneumotaxic and apneustic centers, which modulate the basic respiratory rhythm generated by the medullary respiratory centers.', 'Pre-Council', '🎓', true),
(6076, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The medulla oblongata contains vital centers controlling all of the following EXCEPT', '["cardiac rate and force", "vasomotor tone", "basic respiratory rhythm", "voluntary motor planning"]'::jsonb, 3, 'The medulla houses the cardiac, vasomotor, and rhythmic respiratory centers essential for life; voluntary motor planning is a cortical (frontal lobe) function, not a medullary one.', 'Pre-Council', '🎓', true),
(6077, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The reticular activating system, which is essential for maintaining wakefulness and consciousness, is located primarily in the', '["cerebellum", "brainstem (extending into the thalamus)", "occipital lobe", "corpus callosum"]'::jsonb, 1, 'The reticular activating system spans the brainstem tegmentum and projects to the thalamus and cortex; its dysfunction, as from brainstem injury, produces altered levels of consciousness or coma.', 'Pre-Council', '🎓', true),
(6078, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'On the Glasgow Coma Scale, the three components assessed are', '["pupil reactivity, respiratory pattern, and reflexes", "eye opening, verbal response, and motor response", "heart rate, blood pressure, and temperature", "cranial nerve function, muscle strength, and gait"]'::jsonb, 1, 'The GCS scores eye opening (1-4), verbal response (1-5), and motor response (1-6), giving a total range of 3 (deep coma) to 15 (fully alert).', 'Pre-Council', '🎓', true),
(6079, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient presents with a Glasgow Coma Scale score of 7. Based on standard critical care practice, the priority nursing/medical concern is', '["discharge planning, as the score reflects mild injury", "airway protection, since a GCS of 8 or below indicates a need to consider intubation", "administering oral analgesics", "no intervention needed until GCS drops below 3"]'::jsonb, 1, 'A GCS of 8 or less is widely used as the threshold for severe impairment of consciousness at which airway protective reflexes are often lost, prompting consideration of intubation ("GCS 8, intubate").', 'Pre-Council', '🎓', true),
(6080, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cushing''s triad, a late and ominous sign of rising intracranial pressure, consists of', '["hypotension, tachycardia, and tachypnea", "hypertension with widened pulse pressure, bradycardia, and irregular respirations", "fever, tachycardia, and hypertension", "hypotension, bradycardia, and regular respirations"]'::jsonb, 1, 'As ICP rises and compresses the brainstem, the body raises systemic blood pressure to maintain cerebral perfusion (widened pulse pressure), while brainstem compression causes reflex bradycardia and an irregular respiratory pattern.', 'Pre-Council', '🎓', true),
(6081, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Uncal (transtentorial) herniation classically compresses which cranial nerve first, producing an ipsilateral fixed and dilated pupil?', '["Cranial nerve II (optic)", "Cranial nerve III (oculomotor)", "Cranial nerve VI (abducens)", "Cranial nerve VII (facial)"]'::jsonb, 1, 'As the uncus of the temporal lobe herniates over the tentorial edge, it compresses the oculomotor nerve (CN III), whose superficial parasympathetic pupillary fibers are affected first, causing ipsilateral pupillary dilation.', 'Pre-Council', '🎓', true),
(6082, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cerebral perfusion pressure (CPP) is calculated as', '["MAP + ICP", "MAP - ICP", "systolic BP - diastolic BP", "ICP - CVP"]'::jsonb, 1, 'CPP = mean arterial pressure (MAP) minus intracranial pressure (ICP); maintaining adequate CPP (generally above 60 mmHg) is a priority in managing patients with elevated ICP.', 'Pre-Council', '🎓', true),
(6083, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cerebrospinal fluid is produced mainly by the', '["dura mater", "choroid plexus", "arachnoid villi", "pia mater"]'::jsonb, 1, 'The choroid plexus, located within the ventricles, is a network of capillaries and specialized ependymal cells that produces the majority of CSF (roughly 500 mL per day).', 'Pre-Council', '🎓', true),
(6084, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The correct pathway of CSF circulation through the ventricular system is', '["fourth ventricle \u2192 third ventricle \u2192 lateral ventricles \u2192 subarachnoid space", "lateral ventricles \u2192 third ventricle \u2192 cerebral aqueduct \u2192 fourth ventricle \u2192 subarachnoid space", "lateral ventricles \u2192 fourth ventricle \u2192 third ventricle \u2192 central canal", "third ventricle \u2192 lateral ventricles \u2192 cerebral aqueduct \u2192 subarachnoid space"]'::jsonb, 1, 'CSF flows from the lateral ventricles through the interventricular foramina (of Monro) into the third ventricle, then through the cerebral aqueduct (of Sylvius) into the fourth ventricle, and finally through the foramina of Luschka and Magendie into the subarachnoid space.', 'Pre-Council', '🎓', true),
(6085, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'CSF is ultimately reabsorbed into the venous circulation primarily through the', '["choroid plexus", "arachnoid villi (granulations) into the dural venous sinuses", "ependymal lining of the central canal", "pia mater capillaries"]'::jsonb, 1, 'Arachnoid villi project into the dural venous sinuses, particularly the superior sagittal sinus, and allow bulk one-way reabsorption of CSF back into venous blood.', 'Pre-Council', '🎓', true),
(6086, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The Circle of Willis, an anastomotic ring at the base of the brain that provides collateral cerebral blood flow, is formed by branches of which arteries?', '["Only the vertebral arteries", "The internal carotid and vertebrobasilar systems", "Only the external carotid arteries", "The superior and inferior vena cavae"]'::jsonb, 1, 'The Circle of Willis is formed by anastomoses between the internal carotid artery system (anterior circulation) and the vertebrobasilar system (posterior circulation), providing collateral flow if one vessel is occluded.', 'Pre-Council', '🎓', true),
(6087, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient presents with contralateral face and arm weakness greater than leg weakness, plus aphasia. Occlusion of which artery is most likely, given a dominant-hemisphere lesion?', '["Anterior cerebral artery", "Middle cerebral artery", "Posterior cerebral artery", "Vertebral artery"]'::jsonb, 1, 'The middle cerebral artery supplies the lateral cerebral cortex, including the face and arm areas of the motor/sensory homunculus and, in the dominant hemisphere, Broca''s and Wernicke''s areas, producing this classic presentation when occluded.', 'Pre-Council', '🎓', true),
(6088, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Occlusion of the anterior cerebral artery classically produces', '["contralateral leg weakness greater than arm/face weakness", "contralateral homonymous hemianopia", "ipsilateral facial droop only", "bilateral deafness"]'::jsonb, 0, 'The anterior cerebral artery supplies the medial surface of the frontal and parietal lobes, including the leg area of the motor cortex, so its occlusion produces leg weakness disproportionate to arm/face weakness.', 'Pre-Council', '🎓', true),
(6089, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with a stroke presents with contralateral homonymous hemianopia and no motor weakness. Which cerebral artery territory is most likely affected?', '["Middle cerebral artery", "Anterior cerebral artery", "Posterior cerebral artery", "Anterior spinal artery"]'::jsonb, 2, 'The posterior cerebral artery supplies the occipital lobe (primary visual cortex); its occlusion classically produces contralateral homonymous hemianopia, often with macular sparing.', 'Pre-Council', '🎓', true),
(6090, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The limbic system structure most responsible for the consolidation of new long-term memories is the', '["amygdala", "hippocampus", "cingulate gyrus", "hypothalamus"]'::jsonb, 1, 'The hippocampus, located in the medial temporal lobe, is essential for consolidating short-term memories into long-term declarative memory; bilateral hippocampal damage produces anterograde amnesia.', 'Pre-Council', '🎓', true),
(6091, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The limbic structure most associated with processing fear and emotional responses is the', '["hippocampus", "amygdala", "corpus callosum", "thalamus"]'::jsonb, 1, 'The amygdala is central to emotional processing, particularly fear conditioning and the generation of the fight-or-flight emotional response.', 'Pre-Council', '🎓', true),
(6092, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The corpus callosum is a large white matter structure that primarily functions to', '["connect the cerebellum to the brainstem", "connect and allow communication between the two cerebral hemispheres", "carry motor fibers from the cortex to the spinal cord", "relay sensory information to the thalamus"]'::jsonb, 1, 'The corpus callosum is the largest commissural white matter tract, connecting corresponding areas of the right and left cerebral hemispheres and allowing interhemispheric communication.', 'Pre-Council', '🎓', true),
(6093, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The decussation of the pyramids, where most corticospinal fibers cross to the opposite side, occurs at the level of the', '["midbrain", "pons", "medulla oblongata", "cervical spinal cord"]'::jsonb, 2, 'Approximately 85-90% of corticospinal fibers cross to the contralateral side at the pyramidal decussation in the caudal medulla, which explains why cortical lesions cause contralateral motor deficits.', 'Pre-Council', '🎓', true),
(6094, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve I is responsible for the sense of smell and is tested clinically by', '["having the patient identify a familiar odor with each nostril tested separately, eyes closed", "asking the patient to read a Snellen chart", "checking pupillary response to light", "asking the patient to shrug the shoulders against resistance"]'::jsonb, 0, 'The olfactory nerve (CN I) is a purely sensory nerve for smell; it is tested by occluding one nostril at a time and having the patient identify a non-irritating, familiar scent.', 'Pre-Council', '🎓', true),
(6095, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Anosmia (loss of smell) following head trauma is most often caused by shearing of the olfactory nerve fibers as they pass through the', '["foramen magnum", "cribriform plate of the ethmoid bone", "internal acoustic meatus", "jugular foramen"]'::jsonb, 1, 'Olfactory nerve fibers pass through the cribriform plate to reach the olfactory bulb; traumatic shearing of these delicate fibers at this site is a common cause of post-traumatic anosmia.', 'Pre-Council', '🎓', true),
(6096, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve II carries visual information from the retina to the brain and is assessed clinically using', '["the whisper test", "visual acuity charts and visual field testing", "the corneal reflex", "taste identification on the tongue"]'::jsonb, 1, 'The optic nerve (CN II) is purely sensory for vision and is evaluated with visual acuity (e.g., Snellen chart) and confrontation visual field testing, as well as funduscopic examination of the optic disc.', 'Pre-Council', '🎓', true),
(6097, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a patient with sustained elevated intracranial pressure, funduscopic examination of the optic disc (via CN II) may reveal', '["papilledema (optic disc swelling)", "corneal clouding", "miosis unresponsive to light", "nystagmus on lateral gaze only"]'::jsonb, 0, 'Chronically raised ICP impairs axoplasmic flow and venous return along the optic nerve sheath, causing swelling of the optic disc (papilledema), a key finding on fundoscopy.', 'Pre-Council', '🎓', true),
(6098, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient presents with ptosis, a pupil that is fixed and dilated, and the eye deviated "down and out." Which cranial nerve palsy best explains this presentation?', '["Cranial nerve III (oculomotor)", "Cranial nerve IV (trochlear)", "Cranial nerve VI (abducens)", "Cranial nerve VII (facial)"]'::jsonb, 0, 'CN III supplies most extraocular muscles, the levator palpebrae superioris, and parasympathetic fibers to the pupillary constrictor; its palsy causes ptosis, a fixed dilated pupil, and a "down and out" eye position from unopposed lateral rectus (CN VI) and superior oblique (CN IV) action.', 'Pre-Council', '🎓', true),
(6099, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A compressive lesion such as a posterior communicating artery aneurysm classically causes early pupillary involvement in a CN III palsy because', '["motor fibers are located superficially and are compressed first", "parasympathetic pupillary fibers run superficially on the nerve and are compressed first", "the pupil has no autonomic innervation", "compressive lesions never affect the pupil"]'::jsonb, 1, 'The parasympathetic fibers controlling pupillary constriction travel on the outer surface of CN III, making them vulnerable to early compression (pupil-involving palsy), whereas ischemic causes (e.g., diabetes) tend to spare the pupil by affecting the internal somatic fibers first.', 'Pre-Council', '🎓', true),
(6100, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve IV (trochlear) innervates which extraocular muscle?', '["Lateral rectus", "Medial rectus", "Superior oblique", "Inferior oblique"]'::jsonb, 2, 'The trochlear nerve innervates the superior oblique muscle, which primarily depresses and intorts the adducted eye; it is unique among cranial nerves in decussating and exiting the brainstem dorsally.', 'Pre-Council', '🎓', true),
(6101, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with a trochlear nerve (CN IV) palsy would most likely report difficulty with which activity?', '["Reading, due to difficulty looking down and inward (e.g., going down stairs)", "Chewing food", "Hearing conversations in noisy rooms", "Smelling food aromas"]'::jsonb, 0, 'Because the superior oblique helps depress the adducted eye, CN IV palsy causes vertical/torsional diplopia that worsens on downward gaze, classically noticed when reading or descending stairs.', 'Pre-Council', '🎓', true),
(6102, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve VI innervates the lateral rectus muscle; a palsy of this nerve produces', '["an eye that cannot abduct, resulting in a medially deviated eye and horizontal diplopia", "ptosis and a fixed dilated pupil", "loss of facial sensation", "loss of taste on the anterior tongue"]'::jsonb, 0, 'CN VI (abducens) palsy paralyzes the lateral rectus, so the affected eye cannot abduct and rests in an adducted (medially deviated) position, causing horizontal diplopia that worsens on attempted lateral gaze.', 'Pre-Council', '🎓', true),
(6103, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Because of its long intracranial course along the skull base, cranial nerve VI palsy is often considered a', '["reliable localizing sign that always indicates a lesion at the nerve itself", "nonlocalizing (\"false localizing\") sign that can occur early with generalized raised intracranial pressure", "sign specific to cerebellar disease only", "normal finding in healthy adults"]'::jsonb, 1, 'Because the abducens nerve travels a long, vulnerable intracranial path, it can be stretched or compressed by raised ICP from any cause, making CN VI palsy a classic "false localizing sign" that does not necessarily indicate a lesion at the nerve''s actual location.', 'Pre-Council', '🎓', true),
(6104, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve V (trigeminal) is a mixed nerve responsible for', '["motor control of facial expression only", "sensation to the face and motor innervation of the muscles of mastication", "hearing and balance", "taste to the posterior third of the tongue"]'::jsonb, 1, 'The trigeminal nerve has three sensory divisions (ophthalmic, maxillary, mandibular) supplying facial sensation and a motor root supplying the muscles of mastication (masseter, temporalis, pterygoids).', 'Pre-Council', '🎓', true),
(6105, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In testing the corneal reflex, touching the cornea with a wisp of cotton produces a blink. This reflex tests the afferent limb via which cranial nerve and efferent limb via which cranial nerve?', '["Afferent CN VII, efferent CN V", "Afferent CN V, efferent CN VII", "Afferent CN IX, efferent CN X", "Afferent CN III, efferent CN VI"]'::jsonb, 1, 'The ophthalmic division of the trigeminal nerve (CN V) carries the sensory (afferent) signal from the cornea, while the facial nerve (CN VII) supplies the orbicularis oculi that produces the motor (efferent) blink response.', 'Pre-Council', '🎓', true),
(6106, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient presents with unilateral facial paralysis affecting both the upper and lower face, including inability to wrinkle the forehead on the affected side. This pattern is most consistent with', '["a stroke affecting the contralateral motor cortex", "a lower motor neuron (peripheral) facial nerve palsy, such as Bell''s palsy", "cranial nerve VIII palsy", "cranial nerve XII palsy"]'::jsonb, 1, 'Because the forehead receives bilateral cortical innervation, an upper motor neuron (cortical/stroke) lesion spares the forehead; a lower motor neuron facial nerve lesion (Bell''s palsy) paralyzes the entire ipsilateral face, including the forehead.', 'Pre-Council', '🎓', true),
(6107, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Besides motor control of facial expression, cranial nerve VII also provides', '["taste sensation to the anterior two-thirds of the tongue", "taste sensation to the posterior third of the tongue", "general sensation to the face", "motor control of the muscles of mastication"]'::jsonb, 0, 'The facial nerve carries special sensory taste fibers from the anterior two-thirds of the tongue via the chorda tympani, in addition to its motor supply to the muscles of facial expression and the stapedius muscle.', 'Pre-Council', '🎓', true),
(6108, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve VIII (vestibulocochlear) is responsible for which two functions?', '["Taste and facial movement", "Hearing and balance/equilibrium", "Swallowing and gag reflex", "Vision and pupillary constriction"]'::jsonb, 1, 'CN VIII has a cochlear division for hearing and a vestibular division for balance and spatial orientation; it is purely sensory.', 'Pre-Council', '🎓', true),
(6109, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The Weber and Rinne tuning fork tests are used to assess the function of which cranial nerve?', '["CN VII", "CN VIII", "CN IX", "CN X"]'::jsonb, 1, 'The Weber and Rinne tests differentiate conductive from sensorineural hearing loss and assess the cochlear division of the vestibulocochlear nerve (CN VIII).', 'Pre-Council', '🎓', true),
(6110, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'An acoustic neuroma (vestibular schwannoma) most commonly presents with unilateral hearing loss and tinnitus due to its origin from which cranial nerve?', '["CN V", "CN VII", "CN VIII", "CN IX"]'::jsonb, 2, 'Vestibular schwannomas arise from Schwann cells of the vestibular portion of CN VIII and commonly present with progressive unilateral sensorineural hearing loss, tinnitus, and imbalance.', 'Pre-Council', '🎓', true),
(6111, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve IX (glossopharyngeal) contributes sensory fibers for taste from which part of the tongue?', '["Anterior two-thirds", "Posterior third", "The entire tongue equally", "None; CN IX has no taste function"]'::jsonb, 1, 'The glossopharyngeal nerve provides taste and general sensation to the posterior third of the tongue, along with sensory input from the pharynx, carotid body, and carotid sinus.', 'Pre-Council', '🎓', true),
(6112, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The gag reflex, used to assess brainstem function and airway protection in critically ill patients, has its afferent limb carried by which cranial nerve and efferent limb by which cranial nerve?', '["Afferent CN IX, efferent CN X", "Afferent CN X, efferent CN IX", "Afferent CN VII, efferent CN XII", "Afferent CN V, efferent CN VII"]'::jsonb, 0, 'Stimulation of the posterior pharyngeal wall is sensed via the glossopharyngeal nerve (CN IX, afferent), while the resulting elevation of the palate and pharyngeal contraction is mediated by the vagus nerve (CN X, efferent).', 'Pre-Council', '🎓', true),
(6113, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve X (vagus) provides parasympathetic innervation to which of the following?', '["Skeletal muscles of the limbs only", "Thoracic and abdominal viscera, including the heart and most of the GI tract", "The lens of the eye only", "The adrenal cortex"]'::jsonb, 1, 'The vagus nerve is the primary parasympathetic supply to the heart, lungs, and abdominal viscera down to the splenic flexure of the colon, and also contributes to swallowing and phonation via pharyngeal and laryngeal branches.', 'Pre-Council', '🎓', true),
(6114, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Stimulation of the vagus nerve (CN X), for example during suctioning or straining, would be expected to cause which cardiovascular response?', '["Tachycardia and hypertension", "Bradycardia, and potentially hypotension", "No cardiovascular effect", "Isolated increase in respiratory rate"]'::jsonb, 1, 'Vagal stimulation increases parasympathetic tone to the SA node, slowing heart rate (bradycardia) and can be accompanied by a vasovagal drop in blood pressure, a clinically important consideration during airway suctioning.', 'Pre-Council', '🎓', true),
(6115, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cranial nerve XI (accessory) is tested clinically by asking the patient to', '["stick out the tongue", "shrug the shoulders and turn the head against resistance", "smile and show the teeth", "swallow a sip of water"]'::jsonb, 1, 'The spinal accessory nerve innervates the trapezius (shoulder elevation) and sternocleidomastoid (head rotation) muscles, tested by resisted shoulder shrug and head turning.', 'Pre-Council', '🎓', true),
(6116, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'On tongue protrusion testing, a lower motor neuron lesion of cranial nerve XII (hypoglossal) causes the tongue to', '["remain perfectly midline", "deviate toward the side of the lesion", "deviate away from the side of the lesion", "fasciculate but never deviate"]'::jsonb, 1, 'A hypoglossal nerve palsy weakens the genioglossus on the affected side; because the unopposed contralateral genioglossus pushes the tongue tip, the protruded tongue deviates toward the side of the lesion.', 'Pre-Council', '🎓', true),
(6117, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cranial nerve is the only one to exit the brainstem from its dorsal (posterior) surface and to decussate before doing so?', '["CN III (oculomotor)", "CN IV (trochlear)", "CN VI (abducens)", "CN VII (facial)"]'::jsonb, 1, 'The trochlear nerve (CN IV) is unique in that its fibers cross to the contralateral side within the midbrain and it emerges from the dorsal surface of the brainstem, just below the inferior colliculi.', 'Pre-Council', '🎓', true),
(6118, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A comatose patient''s brainstem reflexes are being assessed. Absence of a corneal reflex combined with a fixed, dilated pupil most strongly suggests dysfunction of which brainstem level?', '["Cervical spinal cord only", "Midbrain and pontine level", "Lumbar spinal cord", "Cerebellar vermis only"]'::jsonb, 1, 'The corneal reflex depends on CN V (pons) and CN VII (pons), while pupillary light response depends on CN III (midbrain); combined loss of these reflexes indicates severe midbrain-pontine dysfunction, a grave prognostic sign.', 'Pre-Council', '🎓', true),
(6119, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cranial nerve nuclei are located in the pons?', '["CN I and II", "CN V, VI, VII, and VIII", "CN IX, X, XI, and XII", "CN III and IV only"]'::jsonb, 1, 'The pons houses the nuclei of cranial nerves V (trigeminal), VI (abducens), VII (facial), and VIII (vestibulocochlear); CN III and IV nuclei are in the midbrain, and CN IX-XII nuclei are in the medulla.', 'Pre-Council', '🎓', true),
(6120, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Spinal accessory nerve (CN XI) palsy following radical neck dissection would most likely present with', '["difficulty swallowing only", "shoulder drop and weakness turning the head to the opposite side", "loss of taste", "hoarseness of voice"]'::jsonb, 1, 'Loss of trapezius function from CN XI injury causes ipsilateral shoulder drooping and winging of the scapula, along with weakness turning the head to the side opposite the lesion (since each SCM turns the head contralaterally).', 'Pre-Council', '🎓', true),
(6121, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The spinal cord in a typical adult terminates at approximately which vertebral level, forming the conus medullaris?', '["T12", "L1-L2", "L4-L5", "S1"]'::jsonb, 1, 'In adults, the spinal cord tapers into the conus medullaris at approximately the L1-L2 vertebral level; below this, the vertebral canal contains only nerve roots (cauda equina), not the cord itself.', 'Pre-Council', '🎓', true),
(6122, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The bundle of lumbar and sacral nerve roots that descend within the vertebral canal below the conus medullaris is called the', '["filum terminale", "cauda equina", "corticospinal tract", "dorsal root ganglion chain"]'::jsonb, 1, 'The cauda equina ("horse''s tail") is composed of the lumbar, sacral, and coccygeal nerve roots that continue to descend after the spinal cord itself has ended, exiting at their respective vertebral levels.', 'Pre-Council', '🎓', true),
(6123, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient presents with saddle anesthesia, bilateral leg weakness, and new urinary retention with overflow incontinence. This presentation is most consistent with', '["a single lumbar disc herniation affecting one nerve root", "cauda equina syndrome, a surgical emergency", "Bell''s palsy", "a simple stretch reflex abnormality"]'::jsonb, 1, 'Cauda equina syndrome results from compression of multiple lumbosacral nerve roots and presents with saddle anesthesia, bilateral leg weakness, and bowel/bladder dysfunction; it requires emergency surgical decompression to prevent permanent deficit.', 'Pre-Council', '🎓', true),
(6124, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In cross-section, the gray matter of the spinal cord is arranged in an H-shaped or butterfly pattern with the anterior (ventral) horn primarily containing', '["sensory neuron cell bodies", "motor neuron cell bodies", "only glial cells", "autonomic preganglionic neurons exclusively"]'::jsonb, 1, 'The anterior (ventral) horn of spinal gray matter contains the cell bodies of lower motor neurons whose axons exit via the ventral root to innervate skeletal muscle.', 'Pre-Council', '🎓', true),
(6125, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The posterior (dorsal) horn of the spinal cord gray matter is primarily concerned with', '["receiving and processing incoming sensory information", "generating outgoing motor commands", "autonomic outflow to viscera", "producing cerebrospinal fluid"]'::jsonb, 0, 'Sensory (afferent) fibers from the dorsal root ganglion enter and synapse in the posterior (dorsal) horn, which processes and relays incoming somatosensory information.', 'Pre-Council', '🎓', true),
(6126, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The lateral horn of the spinal cord gray matter, present from approximately T1 to L2, contains cell bodies of which neurons?', '["Lower motor neurons to skeletal muscle", "Preganglionic sympathetic neurons", "Dorsal column sensory relay neurons", "Cerebellar Purkinje cells"]'::jsonb, 1, 'The lateral horn, found in the thoracolumbar spinal segments (T1-L2), houses preganglionic sympathetic neuron cell bodies, reflecting the thoracolumbar origin of sympathetic outflow.', 'Pre-Council', '🎓', true),
(6127, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The dorsal column-medial lemniscus pathway (fasciculus gracilis and cuneatus) primarily carries which sensory modalities?', '["Pain and temperature", "Proprioception, vibration, and fine (discriminative) touch", "Crude touch and pressure only", "Taste and smell"]'::jsonb, 1, 'The dorsal columns carry proprioceptive, vibratory, and fine touch information ipsilaterally up the spinal cord, crossing in the medulla, in contrast to the spinothalamic tract, which crosses near the level of entry.', 'Pre-Council', '🎓', true),
(6128, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The lateral spinothalamic tract is primarily responsible for carrying which sensory information, and does so via which crossing pattern?', '["Fine touch and proprioception, crossing in the medulla", "Pain and temperature, crossing near the spinal level of entry", "Vibration only, remaining ipsilateral throughout", "Motor commands, crossing in the medulla"]'::jsonb, 1, 'The spinothalamic tract carries pain and temperature sensation; its fibers cross to the contralateral side within one or two spinal segments of entering the cord, unlike the dorsal columns, which cross much higher, in the medulla.', 'Pre-Council', '🎓', true),
(6129, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The lateral corticospinal tract, the major descending pathway for voluntary skeletal muscle movement, crosses to the contralateral side', '["at the level of the pyramidal decussation in the medulla", "within the spinal cord at each segmental level", "in the midbrain", "it does not cross; it remains entirely ipsilateral"]'::jsonb, 0, 'Approximately 85-90% of corticospinal fibers decussate at the pyramids in the caudal medulla before descending as the lateral corticospinal tract, which is why cerebral lesions cause contralateral limb weakness.', 'Pre-Council', '🎓', true),
(6130, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'How many pairs of spinal nerves arise from the human spinal cord?', '["12", "24", "31", "43"]'::jsonb, 2, 'There are 31 pairs of spinal nerves: 8 cervical, 12 thoracic, 5 lumbar, 5 sacral, and 1 coccygeal.', 'Pre-Council', '🎓', true),
(6131, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'There are 8 pairs of cervical spinal nerves despite there being only 7 cervical vertebrae because', '["two cervical nerves exit through the same foramen at C7", "the C1 nerve exits above the C1 vertebra and the C8 nerve exits below the C7 vertebra", "one cervical nerve is vestigial and does not actually exist", "cervical nerves are counted differently from other spinal levels"]'::jsonb, 1, 'Cervical spinal nerves C1-C7 exit above their correspondingly numbered vertebra, but because there is no C8 vertebra, the C8 nerve exits below the C7 vertebra, giving 8 cervical nerve pairs from only 7 vertebrae.', 'Pre-Council', '🎓', true),
(6132, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A specific area of skin supplied by sensory fibers from a single spinal nerve root is called a', '["myotome", "dermatome", "sclerotome", "plexus"]'::jsonb, 1, 'A dermatome is the area of skin innervated by the sensory fibers of a single spinal nerve; dermatome maps are used clinically to localize the level of a spinal cord or nerve root lesion.', 'Pre-Council', '🎓', true),
(6133, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The nipple line is a useful surface landmark corresponding approximately to which dermatome level when assessing the sensory level of a spinal cord injury?', '["C4", "T4", "T10", "L1"]'::jsonb, 1, 'The T4 dermatome corresponds approximately to the nipple line, a commonly used landmark in bedside sensory level assessment after suspected spinal cord injury.', 'Pre-Council', '🎓', true),
(6134, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The umbilicus is a commonly used surface landmark corresponding to which dermatome level?', '["T4", "T10", "L4", "S1"]'::jsonb, 1, 'The T10 dermatome corresponds to the level of the umbilicus, a useful landmark for identifying the sensory level in spinal cord injury or assessing epidural anesthesia spread.', 'Pre-Council', '🎓', true),
(6135, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The phrenic nerve, which innervates the diaphragm and is essential for spontaneous ventilation, arises from spinal cord levels', '["C3, C4, and C5", "T1 through T12", "L1 through L4", "S2 through S4"]'::jsonb, 0, 'The phrenic nerve arises from the C3-C5 nerve roots ("C3, 4, 5 keeps the diaphragm alive"); a complete spinal cord injury above this level typically causes respiratory arrest requiring mechanical ventilation.', 'Pre-Council', '🎓', true),
(6136, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with a complete spinal cord injury at the C2 level would be expected to require', '["no ventilatory support since the diaphragm is intact", "immediate mechanical ventilation due to loss of phrenic nerve function", "only intermittent oxygen by nasal cannula", "physical therapy alone with no respiratory concerns"]'::jsonb, 1, 'A complete injury above C3 disrupts the phrenic nerve outflow (C3-C5) needed to drive diaphragmatic breathing, resulting in immediate respiratory failure and the need for mechanical ventilation.', 'Pre-Council', '🎓', true),
(6137, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A complete spinal cord injury resulting in paralysis and sensory loss of the lower limbs and trunk, with the arms spared, is termed', '["tetraplegia (quadriplegia)", "paraplegia", "hemiplegia", "monoplegia"]'::jsonb, 1, 'Paraplegia refers to paralysis affecting the lower limbs and, depending on level, part of the trunk, typically resulting from spinal cord injury at or below the thoracic level, with upper limb function preserved.', 'Pre-Council', '🎓', true),
(6138, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A complete cervical spinal cord injury resulting in paralysis affecting all four limbs and the trunk is termed', '["paraplegia", "tetraplegia (quadriplegia)", "hemiparesis", "diplegia"]'::jsonb, 1, 'Tetraplegia (quadriplegia) results from a cervical spinal cord lesion and involves paralysis of all four extremities and the trunk, with the specific functional level determined by the exact injury level.', 'Pre-Council', '🎓', true),
(6139, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Immediately following a complete spinal cord injury, a patient may show flaccid paralysis and complete absence of reflexes below the level of injury. This temporary phenomenon is known as', '["neurogenic shock", "spinal shock", "autonomic dysreflexia", "decerebrate posturing"]'::jsonb, 1, 'Spinal shock is a temporary physiological state following acute spinal cord injury characterized by flaccid paralysis, areflexia, and loss of sensation below the injury level; reflexes typically return, often becoming hyperreflexic, over days to weeks.', 'Pre-Council', '🎓', true),
(6140, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Neurogenic shock following a high spinal cord injury (typically above T6) is characterized by which hemodynamic pattern?', '["Hypertension and tachycardia", "Hypotension and bradycardia due to loss of sympathetic tone", "Hypotension and tachycardia from hypovolemia", "Normal blood pressure with bradycardia only"]'::jsonb, 1, 'Loss of descending sympathetic control after high spinal cord injury leads to unopposed vagal (parasympathetic) tone, producing the characteristic combination of hypotension and bradycardia seen in neurogenic shock.', 'Pre-Council', '🎓', true),
(6141, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with a chronic spinal cord injury at T4 develops a sudden pounding headache, severe hypertension, profuse sweating and flushing above the injury level, and bradycardia after their urinary catheter becomes blocked. This presentation is most consistent with', '["spinal shock", "autonomic dysreflexia", "a simple tension headache", "Cushing''s triad from raised intracranial pressure"]'::jsonb, 1, 'Autonomic dysreflexia occurs in patients with SCI at or above T6, triggered by a noxious stimulus below the injury level (commonly bladder distention); it causes an unopposed sympathetic surge below the lesion, producing severe hypertension, reflex bradycardia, and flushing/sweating above the lesion, and is a medical emergency.', 'Pre-Council', '🎓', true),
(6142, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The most common trigger for autonomic dysreflexia in a patient with chronic spinal cord injury is', '["a distended bladder or bowel", "mild anxiety", "cold room temperature", "reading a book"]'::jsonb, 0, 'Bladder distention (e.g., from a blocked catheter) and bowel impaction are the most common noxious stimuli that trigger autonomic dysreflexia in patients with SCI at or above T6.', 'Pre-Council', '🎓', true),
(6143, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Brown-Séquard syndrome results from hemisection of the spinal cord and classically produces which pattern of deficits?', '["Bilateral loss of all sensation below the lesion", "Ipsilateral loss of motor function, proprioception, and vibration, with contralateral loss of pain and temperature below the lesion", "Contralateral loss of motor function only, with no sensory changes", "Isolated bilateral loss of pain and temperature"]'::jsonb, 1, 'Because the corticospinal and dorsal column tracts do not cross until higher levels (or not at all until the medulla), hemisection causes ipsilateral motor/proprioceptive loss, while the spinothalamic tract, which has already crossed near its level of entry, produces contralateral pain/temperature loss below the lesion.', 'Pre-Council', '🎓', true),
(6144, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The five components of a basic reflex arc, in sequential order, are', '["effector, efferent neuron, integration center, afferent neuron, receptor", "receptor, afferent (sensory) neuron, integration center, efferent (motor) neuron, effector", "receptor, effector, afferent neuron, efferent neuron, integration center", "integration center, receptor, effector, afferent neuron, efferent neuron"]'::jsonb, 1, 'A reflex arc begins with a receptor detecting a stimulus, transmits the signal via an afferent (sensory) neuron to an integration center (usually in the spinal cord or brainstem), which relays a response via an efferent (motor) neuron to an effector (muscle or gland).', 'Pre-Council', '🎓', true),
(6145, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The patellar (knee-jerk) reflex is a classic example of a', '["polysynaptic reflex involving multiple interneurons", "monosynaptic reflex with a single synapse between sensory and motor neuron", "visceral reflex mediated entirely by the autonomic nervous system", "learned (conditioned) reflex"]'::jsonb, 1, 'The patellar reflex is a monosynaptic stretch reflex: the sensory neuron from the muscle spindle synapses directly onto the motor neuron with no interneuron involved, producing a very rapid response.', 'Pre-Council', '🎓', true),
(6146, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The withdrawal (flexor) reflex, in which a limb is rapidly withdrawn from a painful stimulus, is classified as a', '["monosynaptic reflex", "polysynaptic reflex involving interneurons", "purely autonomic reflex", "reflex that requires no spinal cord involvement"]'::jsonb, 1, 'The withdrawal reflex is polysynaptic, involving interneurons that coordinate flexor muscle contraction and often simultaneously inhibit the antagonist extensor muscle.', 'Pre-Council', '🎓', true),
(6147, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The crossed extensor reflex, which typically accompanies a withdrawal reflex, functions to', '["cause both limbs to flex simultaneously", "extend the contralateral limb to maintain balance and support body weight", "inhibit all motor activity temporarily", "produce a purely sensory response with no motor output"]'::jsonb, 1, 'While one limb withdraws (flexes) from a painful stimulus, the crossed extensor reflex causes extension of the opposite limb, providing postural support so the person does not fall.', 'Pre-Council', '🎓', true),
(6148, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The sensory receptor that detects muscle stretch and initiates the monosynaptic stretch reflex is the', '["Golgi tendon organ", "muscle spindle", "Pacinian corpuscle", "Meissner''s corpuscle"]'::jsonb, 1, 'Muscle spindles, located within skeletal muscle, detect changes in muscle length (stretch) and trigger the stretch reflex to resist that stretch, as seen in deep tendon reflex testing.', 'Pre-Council', '🎓', true),
(6149, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The Golgi tendon organ, located at the muscle-tendon junction, functions to', '["initiate muscle contraction in response to stretch", "detect excessive muscle tension and trigger reflex inhibition of that muscle to protect against injury", "produce cerebrospinal fluid", "carry pain sensation from the skin"]'::jsonb, 1, 'The Golgi tendon organ senses muscle tension; when tension becomes excessive, it triggers autogenic inhibition (a polysynaptic reflex) that relaxes the muscle, protecting the tendon and muscle from damage.', 'Pre-Council', '🎓', true),
(6150, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Reciprocal inhibition during a reflex movement refers to the process by which', '["the agonist and antagonist muscles contract simultaneously with equal force", "the antagonist muscle is inhibited via an inhibitory interneuron while the agonist contracts", "both limbs withdraw from a stimulus at the same time", "the reflex bypasses the spinal cord entirely"]'::jsonb, 1, 'Reciprocal inhibition allows smooth, coordinated movement: as the agonist muscle contracts (e.g., quadriceps in the patellar reflex), an inhibitory interneuron simultaneously suppresses the antagonist (hamstrings) motor neuron.', 'Pre-Council', '🎓', true),
(6151, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'During deep tendon reflex testing, the patellar (knee) reflex primarily assesses the integrity of spinal cord segments', '["C5-C6", "C7-C8", "L2-L4 (primarily L3-L4)", "S1-S2"]'::jsonb, 2, 'The patellar reflex tests the femoral nerve and spinal segments L2-L4, with L3-L4 being the primary contributors, and is commonly used to assess lumbar spinal cord and nerve root integrity.', 'Pre-Council', '🎓', true),
(6152, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The Achilles (ankle jerk) deep tendon reflex primarily tests spinal cord segments', '["L2-L4", "S1-S2", "C5-C6", "T10-T12"]'::jsonb, 1, 'The Achilles reflex, elicited by tapping the Achilles tendon, tests the tibial nerve and spinal segments S1-S2.', 'Pre-Council', '🎓', true),
(6153, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The biceps deep tendon reflex primarily assesses spinal cord segments', '["C5-C6", "C7-C8", "L3-L4", "S1-S2"]'::jsonb, 0, 'The biceps reflex, elicited by tapping the biceps tendon, primarily tests the musculocutaneous nerve and spinal segments C5-C6.', 'Pre-Council', '🎓', true),
(6154, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The triceps deep tendon reflex primarily assesses spinal cord segments', '["C5-C6", "C7-C8", "L2-L4", "S1-S2"]'::jsonb, 1, 'The triceps reflex, elicited by tapping the triceps tendon with the elbow flexed, primarily tests the radial nerve and spinal segments C7-C8.', 'Pre-Council', '🎓', true),
(6155, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'On the standard 0 to 4+ deep tendon reflex grading scale, a grade of 2+ represents', '["absent reflex", "diminished but present reflex", "normal, average reflex response", "hyperactive reflex with clonus"]'::jsonb, 2, 'On the standard DTR scale, 0 = absent, 1+ = diminished, 2+ = normal/average, 3+ = brisk (possibly but not necessarily abnormal), and 4+ = hyperactive with clonus, often indicating an upper motor neuron lesion.', 'Pre-Council', '🎓', true),
(6156, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Eliciting the Babinski sign involves stroking the lateral sole of the foot; a positive (abnormal) response in an adult consists of', '["curling (flexion) of all toes downward", "dorsiflexion of the great toe with fanning of the other toes", "no movement of the toes at all", "rapid plantar flexion of the entire foot"]'::jsonb, 1, 'A positive Babinski sign, characterized by extension (dorsiflexion) of the great toe with fanning of the other toes, indicates an upper motor neuron lesion of the corticospinal tract in an adult.', 'Pre-Council', '🎓', true),
(6157, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A positive Babinski sign is considered a normal finding in which population, due to incomplete corticospinal tract myelination?', '["Healthy adults over age 65", "Infants younger than approximately 2 years", "Pregnant women", "Trained athletes"]'::jsonb, 1, 'In infants, the corticospinal tract is not yet fully myelinated, so an upgoing (positive) Babinski response is a normal finding until roughly age 2, after which it should become a normal plantar (downgoing) response.', 'Pre-Council', '🎓', true),
(6158, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Sympathetic preganglionic neurons originate from spinal cord segments described as', '["craniosacral outflow", "thoracolumbar outflow (T1-L2)", "cervical outflow only", "sacral outflow only"]'::jsonb, 1, 'The sympathetic nervous system is described as having thoracolumbar outflow, with preganglionic neuron cell bodies located in the lateral horn of spinal segments T1 through L2.', 'Pre-Council', '🎓', true),
(6159, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Parasympathetic outflow arises from the brainstem (via cranial nerves III, VII, IX, and X) and from which spinal cord segments?', '["T1-L2", "S2-S4", "C1-C4", "L4-S1"]'::jsonb, 1, 'Parasympathetic outflow is described as craniosacral, arising from four cranial nerve nuclei (III, VII, IX, X) and from the sacral spinal segments S2-S4.', 'Pre-Council', '🎓', true),
(6160, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A nurse assessing a patient''s spinal reflexes notes hyperreflexia (3+ to 4+) with clonus and a positive Babinski sign below a known spinal lesion. This pattern is most consistent with damage to', '["lower motor neurons only", "upper motor neurons (corticospinal tract)", "peripheral sensory nerves only", "skeletal muscle fibers directly"]'::jsonb, 1, 'Upper motor neuron lesions (affecting the corticospinal tract) classically produce hyperreflexia, clonus, spasticity, and a positive Babinski sign, in contrast to lower motor neuron lesions, which cause hyporeflexia/areflexia and flaccid weakness.', 'Pre-Council', '🎓', true),
(6161, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A lower motor neuron lesion (e.g., peripheral nerve or anterior horn cell damage) would be expected to produce which combination of findings?', '["Hyperreflexia, spasticity, and a positive Babinski sign", "Hyporeflexia or areflexia, flaccid paralysis, and muscle atrophy with fasciculations", "Normal reflexes with increased muscle tone", "No change in reflexes or muscle tone"]'::jsonb, 1, 'Lower motor neuron lesions interrupt the final common pathway to muscle, causing flaccid paralysis, diminished or absent reflexes, muscle atrophy, and fasciculations, in contrast to the hyperreflexic, spastic picture of upper motor neuron lesions.', 'Pre-Council', '🎓', true),
(6162, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which statement correctly differentiates the corneal reflex pathway from the pupillary light reflex pathway?', '["Both use CN II for afferent and CN III for efferent limbs", "The corneal reflex uses CN V afferent/CN VII efferent, while the pupillary light reflex uses CN II afferent/CN III efferent", "The corneal reflex uses CN III for both limbs", "The pupillary light reflex uses CN VII for both limbs"]'::jsonb, 1, 'The corneal reflex depends on trigeminal (CN V) sensory input and facial nerve (CN VII) motor output (blink), while the pupillary light reflex depends on optic nerve (CN II) sensory input and oculomotor nerve (CN III) parasympathetic motor output (pupil constriction).', 'Pre-Council', '🎓', true),
(6163, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A critically ill, unresponsive patient is assessed for brainstem reflexes as part of a coma evaluation. Testing the oculocephalic ("doll''s eyes") reflex primarily evaluates the integrity of which structures?', '["Only the cerebral cortex", "Brainstem pathways connecting cranial nerves III, VI, and VIII", "Only the spinal cord", "Peripheral sensory nerves of the limbs"]'::jsonb, 1, 'The oculocephalic reflex tests brainstem circuitry linking the vestibular system (CN VIII) with the nuclei controlling eye movement (CN III and CN VI); intact reflex eye movements indicate brainstem integrity is preserved.', 'Pre-Council', '🎓', true),
(6164, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Damage limited to the dorsal columns of the spinal cord, sparing the spinothalamic tract, would most likely produce which sensory deficit below the lesion?', '["Loss of pain and temperature sensation with preserved proprioception", "Loss of proprioception and vibration sense with preserved pain and temperature", "Complete loss of all sensory modalities", "No sensory deficit at all"]'::jsonb, 1, 'Because the dorsal columns carry proprioception, vibration, and fine touch separately from the spinothalamic tract (pain/temperature), an isolated dorsal column lesion spares pain and temperature sensation while impairing proprioception and vibration sense.', 'Pre-Council', '🎓', true),
(6165, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A nurse testing deep tendon reflexes in a patient uses the Jendrassik maneuver (patient interlocks fingers and pulls apart while the examiner taps the tendon). The purpose of this maneuver is to', '["decrease reflex sensitivity for a more accurate baseline", "reinforce and enhance an otherwise difficult-to-elicit reflex through distraction", "test cranial nerve function", "assess for autonomic dysreflexia"]'::jsonb, 1, 'The Jendrassik maneuver uses voluntary muscle contraction elsewhere in the body as a distraction technique that reinforces spinal reflex arcs, making an otherwise weak or difficult-to-elicit deep tendon reflex more apparent.', 'Pre-Council', '🎓', true),
(6166, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In assessing a patient with a suspected spinal cord injury, absent reflexes, flaccid paralysis, and loss of sensation below the level of injury occurring immediately after the trauma, followed by gradual return of reflexes over subsequent weeks, is best explained by', '["permanent lower motor neuron destruction with no expected recovery", "spinal shock, a temporary physiological suppression of reflex activity below the lesion", "an intact and fully functioning spinal cord", "a peripheral nerve injury unrelated to the spinal cord"]'::jsonb, 1, 'Spinal shock is a temporary state of depressed reflex activity below an acute spinal cord lesion; as it resolves over days to weeks, reflexes typically return and often become hyperreflexic due to loss of descending inhibitory control.', 'Pre-Council', '🎓', true),
(6167, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The vestibulospinal and rubrospinal tracts, which help regulate posture, balance, and muscle tone, are classified as part of the', '["dorsal column-medial lemniscus system", "extrapyramidal (indirect) motor system", "spinothalamic system", "special sensory system"]'::jsonb, 1, 'The extrapyramidal system includes tracts such as the vestibulospinal, rubrospinal, reticulospinal, and tectospinal tracts, which modulate posture, muscle tone, and involuntary/automatic movement, distinct from the pyramidal (corticospinal) tract that governs fine voluntary movement.', 'Pre-Council', '🎓', true),
(6168, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient''s spinal cord injury results in preserved diaphragmatic breathing but loss of intercostal muscle function and all function below the upper chest. This is most consistent with an injury at approximately which level?', '["C1-C2", "C6-C8/T1", "T12-L1", "S2-S4"]'::jsonb, 1, 'An injury around the lower cervical to upper thoracic level (C6-T1) spares the phrenic nerve (C3-C5) so diaphragmatic breathing continues, but intercostal muscle function (innervated by thoracic nerves) and function below the injury level are lost.', 'Pre-Council', '🎓', true),
(6169, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The tentorium cerebelli is the dural fold that', '["separates the two cerebral hemispheres", "separates the cerebrum (occipital lobes) from the cerebellum", "surrounds the pituitary gland", "lines the spinal canal"]'::jsonb, 1, 'The tentorium cerebelli is a dural fold that separates the occipital lobes of the cerebrum (supratentorial compartment) from the cerebellum and brainstem (infratentorial compartment), a distinction important in classifying brain lesions and herniation syndromes.', 'Pre-Council', '🎓', true),
(6170, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The total volume of cerebrospinal fluid in a healthy adult at any given time is approximately', '["15 mL", "150 mL", "1500 mL", "5000 mL"]'::jsonb, 1, 'Total CSF volume in an adult is approximately 150 mL, distributed between the ventricles and the subarachnoid space, even though roughly 500 mL is produced and reabsorbed daily.', 'Pre-Council', '🎓', true),
(6171, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Communicating hydrocephalus differs from non-communicating (obstructive) hydrocephalus in that communicating hydrocephalus results from', '["a physical blockage within the ventricular system itself", "impaired CSF reabsorption at the arachnoid villi with free flow through the ventricles", "overproduction of CSF exclusively", "complete absence of CSF production"]'::jsonb, 1, 'In communicating hydrocephalus, CSF can flow freely between the ventricles and subarachnoid space, but reabsorption at the arachnoid villi is impaired; in non-communicating hydrocephalus, an obstruction within the ventricular system itself blocks CSF flow.', 'Pre-Council', '🎓', true),
(6172, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which statement about the sympathetic and parasympathetic divisions of the autonomic nervous system, as they relate to spinal cord organization, is correct?', '["Both divisions originate exclusively from the spinal cord", "Sympathetic fibers arise from thoracolumbar spinal segments, while parasympathetic fibers arise mainly from cranial nerve nuclei and sacral spinal segments", "Parasympathetic fibers arise only from the cervical spinal cord", "Sympathetic fibers arise only from the sacral spinal cord"]'::jsonb, 1, 'This thoracolumbar (sympathetic) versus craniosacral (parasympathetic) organization is a foundational concept explaining why sympathetic outflow is limited to T1-L2 while parasympathetic outflow comes from specific cranial nerves and S2-S4.', 'Pre-Council', '🎓', true),
(6173, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with a C6 complete spinal cord injury would be expected to retain which of the following functions?', '["Full lower limb motor function", "Some shoulder, elbow flexion, and wrist extension, but impaired hand function and no lower limb function", "Complete independence in all activities of daily living without assistive devices", "Normal bowel and bladder control"]'::jsonb, 1, 'A C6 level injury typically preserves shoulder movement, elbow flexion, and wrist extension (allowing some tenodesis grasp), but hand intrinsic muscle function, trunk control, and lower limb function are lost, along with bowel/bladder control.', 'Pre-Council', '🎓', true),
(6174, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In assessing a patient for signs of increased intracranial pressure, a change in pupil size and reactivity is often an early and critical sign because it reflects compression of which structure?', '["The optic chiasm", "Cranial nerve III as it is compressed against the tentorial edge", "The spinal accessory nerve", "The facial nerve"]'::jsonb, 1, 'As a mass lesion or edema causes herniation, the oculomotor nerve (CN III) is compressed against the free edge of the tentorium, producing early ipsilateral pupillary changes (initially sluggish, then fixed and dilated) that are closely monitored in critical care.', 'Pre-Council', '🎓', true),
(6175, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient exhibits decorticate posturing (flexion of the arms toward the core with extension of the legs) in response to a painful stimulus. This posturing suggests a lesion at or above which level?', '["The cerebral hemispheres/above the level of the red nucleus in the midbrain", "The lumbar spinal cord only", "The peripheral nerves only", "The neuromuscular junction"]'::jsonb, 0, 'Decorticate posturing indicates a lesion above the level of the red nucleus (cerebral hemispheres or diencephalon), disrupting corticospinal pathways while rubrospinal influence remains intact, producing arm flexion; decerebrate posturing (arm extension) suggests a lower, more severe midbrain/pontine lesion.', 'Pre-Council', '🎓', true),
(6176, 'Central Nervous System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Decerebrate posturing, characterized by extension and internal rotation of both the arms and legs in response to a painful stimulus, generally indicates a lesion at which level and carries what prognostic implication compared to decorticate posturing?', '["A lesion at the level of the midbrain/pons, generally indicating a worse prognosis than decorticate posturing", "A lesion in the peripheral nerves, generally a better prognosis", "No prognostic significance whatsoever", "A lesion limited to the cerebellum with excellent prognosis"]'::jsonb, 0, 'Decerebrate posturing reflects a more caudal brainstem lesion (midbrain/pons) than decorticate posturing and is generally associated with a worse prognosis, as it indicates more extensive brainstem involvement.', 'Pre-Council', '🎓', true),
(6177, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which structure links the nervous system to the endocrine system and directly controls the anterior pituitary via releasing and inhibiting hormones?', '["Hypothalamus", "Pineal gland", "Thalamus", "Posterior pituitary"]'::jsonb, 0, 'The hypothalamus secretes releasing/inhibiting hormones into the hypophyseal portal system, which regulate anterior pituitary hormone secretion.', 'Pre-Council', '🎓', true),
(6178, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The hypothalamus communicates with the anterior pituitary primarily through which pathway?', '["Direct neural synapses", "The hypophyseal portal venous system", "Systemic arterial circulation only", "Cerebrospinal fluid diffusion through the third ventricle"]'::jsonb, 1, 'Hypothalamic releasing/inhibiting hormones travel a short distance via the hypophyseal portal veins directly to the anterior pituitary, allowing high local concentrations.', 'Pre-Council', '🎓', true),
(6179, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Oxytocin and antidiuretic hormone (ADH) are synthesized in the hypothalamus and stored/released from which structure?', '["Anterior pituitary", "Posterior pituitary", "Adrenal medulla", "Pineal gland"]'::jsonb, 1, 'Oxytocin and ADH are made in hypothalamic neurons (supraoptic and paraventricular nuclei) and transported down axons to be stored and released from the posterior pituitary (neurohypophysis).', 'Pre-Council', '🎓', true),
(6180, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which hypothalamic nucleus is primarily responsible for producing antidiuretic hormone (ADH)?', '["Arcuate nucleus", "Suprachiasmatic nucleus", "Supraoptic nucleus", "Ventromedial nucleus"]'::jsonb, 2, 'The supraoptic nucleus (along with the paraventricular nucleus) synthesizes ADH, which is then transported along axons to the posterior pituitary for storage and release.', 'Pre-Council', '🎓', true),
(6181, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Corticotropin-releasing hormone (CRH) from the hypothalamus acts on the anterior pituitary to stimulate release of which hormone?', '["Thyroid-stimulating hormone (TSH)", "Adrenocorticotropic hormone (ACTH)", "Growth hormone (GH)", "Prolactin"]'::jsonb, 1, 'CRH stimulates corticotrophs in the anterior pituitary to secrete ACTH, which in turn stimulates cortisol release from the adrenal cortex.', 'Pre-Council', '🎓', true),
(6182, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which hypothalamic hormone exerts an inhibitory (rather than stimulatory) effect on anterior pituitary hormone release?', '["Thyrotropin-releasing hormone (TRH)", "Gonadotropin-releasing hormone (GnRH)", "Somatostatin", "Corticotropin-releasing hormone (CRH)"]'::jsonb, 2, 'Somatostatin (growth hormone-inhibiting hormone) suppresses growth hormone and TSH release from the anterior pituitary, unlike the mostly stimulatory releasing hormones.', 'Pre-Council', '🎓', true),
(6183, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Dopamine released by the hypothalamus into the hypophyseal portal system primarily inhibits secretion of which anterior pituitary hormone?', '["Prolactin", "Growth hormone", "ACTH", "Luteinizing hormone"]'::jsonb, 0, 'Dopamine acts as prolactin-inhibiting hormone (PIH); tonic dopamine release keeps prolactin secretion suppressed, explaining hyperprolactinemia with dopamine-blocking drugs or pituitary stalk lesions.', 'Pre-Council', '🎓', true),
(6184, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with a pituitary stalk lesion that disrupts hypothalamic-pituitary portal flow would most likely show which hormonal change?', '["Decreased prolactin due to loss of releasing hormone", "Increased prolactin due to loss of tonic dopamine inhibition", "Increased cortisol due to unopposed CRH", "Decreased growth hormone with normal prolactin"]'::jsonb, 1, 'Because dopamine normally inhibits prolactin, disruption of the pituitary stalk removes this inhibition and causes ''stalk effect'' hyperprolactinemia, while most other anterior pituitary hormones fall.', 'Pre-Council', '🎓', true),
(6185, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The hypothalamus regulates body temperature, hunger, thirst, and circadian rhythm in addition to its endocrine roles. Which hypothalamic nucleus is the primary driver of circadian rhythm?', '["Suprachiasmatic nucleus", "Paraventricular nucleus", "Supraoptic nucleus", "Dorsomedial nucleus"]'::jsonb, 0, 'The suprachiasmatic nucleus is the master circadian pacemaker, receiving direct retinal input and regulating melatonin release from the pineal gland.', 'Pre-Council', '🎓', true),
(6186, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Negative feedback in the hypothalamic-pituitary-adrenal (HPA) axis primarily occurs when rising levels of which hormone suppress CRH and ACTH release?', '["Aldosterone", "Cortisol", "Epinephrine", "DHEA"]'::jsonb, 1, 'Cortisol exerts negative feedback at both the hypothalamus (suppressing CRH) and anterior pituitary (suppressing ACTH), maintaining homeostatic control of the HPA axis.', 'Pre-Council', '🎓', true),
(6187, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The pituitary gland is located in which bony structure at the base of the skull?', '["Sella turcica of the sphenoid bone", "Foramen magnum of the occipital bone", "Cribriform plate of the ethmoid bone", "Petrous portion of the temporal bone"]'::jsonb, 0, 'The pituitary gland sits in the sella turcica, a saddle-shaped depression in the sphenoid bone, just below the hypothalamus and optic chiasm.', 'Pre-Council', '🎓', true),
(6188, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The anterior pituitary (adenohypophysis) develops embryologically from which structure?', '["Neural ectoderm of the diencephalon", "Rathke''s pouch, an outpouching of oral ectoderm", "Neural crest cells", "Mesodermal somites"]'::jsonb, 1, 'The adenohypophysis arises from Rathke''s pouch, an upward invagination of oral (buccal) ectoderm, which explains its glandular (non-neural) tissue composition.', 'Pre-Council', '🎓', true),
(6189, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following is NOT one of the classic hormones secreted by the anterior pituitary?', '["Follicle-stimulating hormone (FSH)", "Thyroid-stimulating hormone (TSH)", "Antidiuretic hormone (ADH)", "Growth hormone (GH)"]'::jsonb, 2, 'ADH is produced by the hypothalamus and released from the posterior pituitary, not synthesized by the anterior pituitary.', 'Pre-Council', '🎓', true),
(6190, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient presents with excessive urination and dilute urine after a traumatic brain injury damaging the posterior pituitary. Which hormone deficiency is most likely responsible?', '["Antidiuretic hormone (ADH)", "Oxytocin", "Aldosterone", "Growth hormone"]'::jsonb, 0, 'Loss of ADH secretion causes central diabetes insipidus, characterized by polyuria with dilute urine due to the kidneys'' inability to concentrate urine without ADH acting on the collecting ducts.', 'Pre-Council', '🎓', true),
(6191, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Growth hormone (GH) exerts many of its growth-promoting effects indirectly through stimulation of which mediator produced mainly by the liver?', '["Insulin-like growth factor-1 (IGF-1)", "Somatostatin", "Erythropoietin", "Angiotensinogen"]'::jsonb, 0, 'GH stimulates hepatic (and peripheral) production of IGF-1, which mediates most of the anabolic and growth-promoting actions of GH on bone and soft tissue.', 'Pre-Council', '🎓', true),
(6192, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which anterior pituitary hormone is a direct precursor molecule that is cleaved to produce both ACTH and melanocyte-stimulating hormone (MSH)?', '["Pro-opiomelanocortin (POMC)", "Pro-thyrotropin", "Pro-gonadotropin", "Pro-somatotropin"]'::jsonb, 0, 'POMC is a large precursor peptide cleaved into ACTH, MSH, and beta-endorphin, which explains why states of very high ACTH (e.g., primary adrenal insufficiency) can cause skin hyperpigmentation via MSH-like activity.', 'Pre-Council', '🎓', true),
(6193, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In critically ill patients, chronic critical illness is often associated with a blunted or altered growth hormone axis. Which statement best describes GH physiology in prolonged critical illness?', '["GH pulsatility is increased with preserved IGF-1 response", "GH levels rise but hepatic responsiveness is reduced, leading to low IGF-1 (GH resistance)", "GH secretion is completely absent", "GH and IGF-1 both rise proportionally, worsening catabolism"]'::jsonb, 1, 'In prolonged critical illness, GH secretion becomes irregular and the liver develops relative GH resistance, so IGF-1 remains low despite adequate or elevated GH, contributing to catabolism.', 'Pre-Council', '🎓', true),
(6194, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Oxytocin, released from the posterior pituitary, causes which physiologic effect?', '["Uterine smooth muscle contraction and milk ejection", "Renal water reabsorption", "Increased blood glucose", "Vasodilation of renal afferent arterioles"]'::jsonb, 0, 'Oxytocin stimulates uterine contractions during labor and myoepithelial cell contraction for milk let-down; it is structurally similar to ADH but functionally distinct.', 'Pre-Council', '🎓', true),
(6195, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A pituitary adenoma compressing the optic chiasm classically produces which visual field defect?', '["Bitemporal hemianopia", "Homonymous hemianopia", "Central scotoma only", "Complete unilateral blindness"]'::jsonb, 0, 'The optic chiasm lies just above the pituitary gland; an expanding pituitary mass compresses the crossing nasal retinal fibers, producing bitemporal (outer field) visual loss.', 'Pre-Council', '🎓', true),
(6196, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A 28-year-old woman presents with galactorrhea and amenorrhea. Laboratory testing reveals markedly elevated prolactin. Which mechanism is the most likely underlying cause?', '["A prolactin-secreting pituitary adenoma (prolactinoma)", "Primary hypothyroidism suppressing TRH", "Excess dopamine secretion from the hypothalamus", "Adrenal medullary tumor"]'::jsonb, 0, 'Prolactinomas are the most common functioning pituitary adenomas and classically present with galactorrhea and amenorrhea due to prolactin''s suppression of GnRH pulsatility.', 'Pre-Council', '🎓', true),
(6197, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The posterior pituitary (neurohypophysis) is best described embryologically and functionally as which of the following?', '["Glandular tissue that synthesizes its own hormones", "An extension of neural tissue that stores and releases hormones synthesized in the hypothalamus", "A vestigial structure with no active hormone release", "A portal vascular structure only"]'::jsonb, 1, 'The neurohypophysis is neural tissue derived from the diencephalon; it does not synthesize hormones itself but stores and releases ADH and oxytocin transported down hypothalamic axons.', 'Pre-Council', '🎓', true),
(6198, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Panhypopituitarism following postpartum pituitary infarction (Sheehan syndrome) most classically presents first with failure of which function?', '["Lactation (failure to lactate postpartum)", "Uterine involution", "Renal concentrating ability", "Cardiac output"]'::jsonb, 0, 'Sheehan syndrome results from ischemic pituitary necrosis after severe postpartum hemorrhage; failure to lactate due to prolactin deficiency is often the earliest recognized clue.', 'Pre-Council', '🎓', true),
(6199, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following anterior pituitary hormones acts on the adrenal cortex to stimulate cortisol synthesis?', '["ACTH", "TSH", "FSH", "GH"]'::jsonb, 0, 'ACTH binds melanocortin 2 receptors on adrenocortical cells, stimulating cholesterol conversion to cortisol primarily in the zona fasciculata.', 'Pre-Council', '🎓', true),
(6200, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A critically ill patient develops sudden severe hyponatremia with concentrated urine despite normal renal, adrenal, and thyroid function, following a subarachnoid hemorrhage. Which posterior pituitary-related condition is most consistent?', '["Syndrome of inappropriate antidiuretic hormone secretion (SIADH)", "Central diabetes insipidus", "Nephrogenic diabetes insipidus", "Primary polydipsia"]'::jsonb, 0, 'SIADH causes excess ADH release (often from CNS insults like subarachnoid hemorrhage), leading to water retention, dilutional hyponatremia, and inappropriately concentrated urine.', 'Pre-Council', '🎓', true),
(6201, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'What is the primary trigger for physiologic ADH release from the posterior pituitary?', '["Increased plasma osmolality detected by hypothalamic osmoreceptors", "Decreased plasma osmolality", "Rising blood glucose", "Falling serum potassium"]'::jsonb, 0, 'Hypothalamic osmoreceptors sense rising plasma osmolality (as little as 1-2%) and trigger ADH release to promote water reabsorption and dilute the plasma back toward normal.', 'Pre-Council', '🎓', true),
(6202, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which anterior pituitary cell type secretes growth hormone?', '["Somatotrophs", "Lactotrophs", "Corticotrophs", "Thyrotrophs"]'::jsonb, 0, 'Somatotrophs are the most numerous anterior pituitary cell type and secrete growth hormone in response to hypothalamic GHRH, with somatostatin providing inhibitory tone.', 'Pre-Council', '🎓', true),
(6203, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Central diabetes insipidus is distinguished from nephrogenic diabetes insipidus primarily by which finding?', '["Response of urine osmolality to administered desmopressin (DDAVP)", "Presence of glucosuria", "Serum sodium level alone", "Presence of ketonuria"]'::jsonb, 0, 'In central DI, the kidneys respond normally to exogenous desmopressin with increased urine concentration because the defect is inadequate ADH secretion; in nephrogenic DI, the kidneys fail to respond because the defect is renal ADH resistance.', 'Pre-Council', '🎓', true),
(6204, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The thyroid gland is located in which anatomical position?', '["Anterior neck, straddling the trachea below the cricoid cartilage", "Posterior mediastinum behind the esophagus", "Superior pole of each kidney", "Base of the skull within the sella turcica"]'::jsonb, 0, 'The thyroid is a butterfly-shaped gland in the anterior neck, with two lobes connected by an isthmus overlying the second to fourth tracheal rings.', 'Pre-Council', '🎓', true),
(6205, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The functional unit of the thyroid gland that stores colloid and synthesizes thyroid hormone is called the:', '["Follicle", "Acinus", "Nephron", "Islet"]'::jsonb, 0, 'Thyroid follicles are spherical structures lined by follicular epithelial cells surrounding a lumen filled with colloid (thyroglobulin), the site of thyroid hormone synthesis and storage.', 'Pre-Council', '🎓', true),
(6206, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cells within the thyroid gland secrete calcitonin?', '["Parafollicular (C) cells", "Follicular epithelial cells", "Oxyphil cells", "Chief cells"]'::jsonb, 0, 'Parafollicular cells, also called C cells, lie between thyroid follicles and secrete calcitonin, which lowers serum calcium by inhibiting osteoclastic bone resorption.', 'Pre-Council', '🎓', true),
(6207, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which trace element is essential for thyroid hormone synthesis and must be adequately consumed in the diet?', '["Iodine", "Selenium alone is sufficient without iodine", "Zinc", "Chromium"]'::jsonb, 0, 'Iodine is trapped by the thyroid follicular cells via the sodium-iodide symporter and is an essential structural component of T3 and T4.', 'Pre-Council', '🎓', true),
(6208, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which enzyme, located at the apical membrane of thyroid follicular cells, catalyzes iodide oxidation and coupling of iodotyrosines to form T3 and T4?', '["Thyroid peroxidase (TPO)", "5''-deiodinase", "Thyroglobulin synthetase", "Sodium-iodide symporter"]'::jsonb, 0, 'Thyroid peroxidase oxidizes iodide and catalyzes both the iodination of tyrosine residues on thyroglobulin and the coupling reaction that forms T3 and T4; it is also the major autoantigen in Hashimoto thyroiditis.', 'Pre-Council', '🎓', true),
(6209, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The majority of circulating thyroid hormone released by the thyroid gland is in which form?', '["Thyroxine (T4)", "Triiodothyronine (T3)", "Reverse T3 (rT3)", "Thyroglobulin"]'::jsonb, 0, 'The thyroid gland secretes predominantly T4 (about 90% of secreted hormone), which is then peripherally converted to the more biologically active T3 by deiodinase enzymes in tissues such as the liver and kidney.', 'Pre-Council', '🎓', true),
(6210, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following is the more biologically potent and active thyroid hormone at the cellular receptor level?', '["T3 (triiodothyronine)", "T4 (thyroxine)", "Thyroglobulin", "Calcitonin"]'::jsonb, 0, 'T3 binds nuclear thyroid hormone receptors with much higher affinity than T4 and is considered the active hormone; most circulating T4 is converted peripherally to T3.', 'Pre-Council', '🎓', true),
(6211, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient has an elevated TSH with a low free T4. This laboratory pattern is most consistent with which condition?', '["Primary hypothyroidism", "Primary hyperthyroidism", "Secondary (central) hypothyroidism", "Subclinical hyperthyroidism"]'::jsonb, 0, 'In primary hypothyroidism, the thyroid gland itself fails, so free T4 falls while the pituitary appropriately increases TSH in an attempt to stimulate the failing gland.', 'Pre-Council', '🎓', true),
(6212, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which mechanism best explains why TSH acts on thyroid follicular cells?', '["TSH binds a G-protein coupled receptor, activating adenylate cyclase and increasing intracellular cAMP", "TSH diffuses through the cell membrane and binds a nuclear receptor directly", "TSH activates receptor tyrosine kinase signaling exclusively", "TSH opens ligand-gated calcium channels"]'::jsonb, 0, 'TSH is a peptide hormone that binds a cell-surface G-protein coupled receptor on follicular cells, activating the Gs-adenylate cyclase-cAMP pathway to stimulate iodide uptake, hormone synthesis, and gland growth.', 'Pre-Council', '🎓', true),
(6213, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Unlike most peptide hormones that act via cell-surface receptors, thyroid hormone (T3) exerts its major effects through which mechanism?', '["Binding intracellular/nuclear receptors that alter gene transcription", "Binding a membrane G-protein coupled receptor exclusively", "Activating second messenger cAMP only", "Direct enzymatic activity in the cytoplasm without receptor binding"]'::jsonb, 0, 'T3 is lipophilic and enters the cell to bind nuclear thyroid hormone receptors, forming a complex that binds thyroid response elements on DNA to regulate gene transcription, producing widespread metabolic effects.', 'Pre-Council', '🎓', true),
(6214, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best describes the overall metabolic effect of thyroid hormone on the body?', '["Increases basal metabolic rate, oxygen consumption, and heat production in most tissues", "Decreases basal metabolic rate and oxygen consumption", "Has no effect on metabolic rate but only affects growth", "Selectively decreases cardiac output while increasing metabolism elsewhere"]'::jsonb, 0, 'Thyroid hormone increases basal metabolic rate by stimulating Na+/K+-ATPase activity and mitochondrial oxidative metabolism across most tissues, increasing oxygen consumption and heat production.', 'Pre-Council', '🎓', true),
(6215, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A critically ill patient presents with severe tachycardia, fever, agitation, and altered mental status after recent thyroid surgery. Which life-threatening endocrine emergency should be suspected?', '["Thyroid storm (thyrotoxic crisis)", "Myxedema coma", "Addisonian crisis", "Hypoparathyroid tetany"]'::jsonb, 0, 'Thyroid storm is a life-threatening exacerbation of hyperthyroidism, often precipitated by surgery, infection, or trauma, presenting with hyperthermia, tachyarrhythmia, agitation/delirium, and can progress to cardiovascular collapse.', 'Pre-Council', '🎓', true),
(6216, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'First-line pharmacologic management of thyroid storm typically includes which combination of agents?', '["Beta-blockers, thionamides (e.g., propylthiouracil or methimazole), and iodine solution", "Insulin infusion and dextrose only", "Levothyroxine and glucocorticoids only", "Calcium gluconate and vitamin D"]'::jsonb, 0, 'Thyroid storm management includes beta-blockade (usually propranolol) to control adrenergic symptoms, thionamides to block new hormone synthesis, iodine (given after thionamide) to block hormone release, and often glucocorticoids to reduce T4-to-T3 conversion.', 'Pre-Council', '🎓', true),
(6217, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Myxedema coma is a life-threatening complication of severe, prolonged hypothyroidism. Which clinical presentation is most characteristic?', '["Hypothermia, bradycardia, hypoventilation, and altered mental status", "Hyperthermia, tachycardia, and agitation", "Severe hypertension with flushing", "Polyuria with hypernatremia"]'::jsonb, 0, 'Myxedema coma presents with profound hypothyroid effects: hypothermia, bradycardia, hypoventilation with CO2 retention, hyponatremia, and decreased level of consciousness, requiring urgent IV levothyroxine and stress-dose glucocorticoids.', 'Pre-Council', '🎓', true),
(6218, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which physical examination finding, caused by autoimmune stimulation of orbital tissue, is relatively specific to Graves disease rather than other causes of hyperthyroidism?', '["Exophthalmos (proptosis) and periorbital edema", "Diffuse nontender goiter", "Fine resting tremor", "Warm, moist skin"]'::jsonb, 0, 'Graves ophthalmopathy, causing exophthalmos, results from autoimmune inflammation and glycosaminoglycan deposition in retro-orbital tissues and is specific to Graves disease, distinguishing it from other hyperthyroid causes such as toxic multinodular goiter.', 'Pre-Council', '🎓', true),
(6219, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Graves disease is caused by which underlying pathophysiologic mechanism?', '["Autoantibodies (TSH receptor-stimulating immunoglobulins) that mimic TSH and continuously stimulate the thyroid", "Autoimmune destruction of thyroid follicular cells", "A TSH-secreting pituitary adenoma", "Iodine deficiency"]'::jsonb, 0, 'In Graves disease, thyroid-stimulating immunoglobulins bind and activate the TSH receptor, causing unregulated overproduction of thyroid hormone independent of normal feedback control.', 'Pre-Council', '🎓', true),
(6220, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which thyroid hormone abnormality pattern is classically seen in euthyroid sick syndrome (nonthyroidal illness syndrome) in critically ill ICU patients?', '["Low T3 with normal or low T4 and normal or low TSH", "High T3 and high T4 with suppressed TSH", "Low TSH with high free T4 only", "Elevated TSH with elevated T4"]'::jsonb, 0, 'In critical illness, decreased peripheral conversion of T4 to T3 (and increased reverse T3) leads to low T3 syndrome; TSH and T4 are usually normal or low, and this is generally an adaptive response, not true thyroid disease, so treatment is usually not indicated.', 'Pre-Council', '🎓', true),
(6221, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which laboratory test is generally considered the most sensitive initial screening test for primary thyroid dysfunction?', '["Serum TSH", "Total T4", "Free T3", "Thyroglobulin"]'::jsonb, 0, 'Because of the logarithmic inverse relationship between free T4 and TSH, even small changes in thyroid hormone produce large, easily detectable changes in TSH, making it the most sensitive screening test for primary thyroid disease.', 'Pre-Council', '🎓', true),
(6222, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Calcitonin, secreted by thyroid parafollicular cells, has which primary physiologic effect?', '["Lowers serum calcium by inhibiting osteoclast activity", "Raises serum calcium by stimulating osteoclast activity", "Increases renal phosphate reabsorption", "Stimulates vitamin D activation in the kidney"]'::jsonb, 0, 'Calcitonin opposes parathyroid hormone by inhibiting osteoclastic bone resorption, thereby lowering serum calcium, although its physiologic role in humans is relatively minor compared to PTH.', 'Pre-Council', '🎓', true),
(6223, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cell type within the parathyroid gland is primarily responsible for secreting parathyroid hormone (PTH)?', '["Chief cells", "Oxyphil cells", "Follicular cells", "Parafollicular cells"]'::jsonb, 0, 'Chief cells are the predominant secretory cell type in the parathyroid gland and synthesize and release parathyroid hormone in response to changes in serum ionized calcium.', 'Pre-Council', '🎓', true),
(6224, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'What is the primary physiologic trigger for parathyroid hormone (PTH) secretion?', '["A decrease in serum ionized calcium detected by calcium-sensing receptors", "An increase in serum phosphate", "A decrease in serum magnesium only", "An increase in serum calcium"]'::jsonb, 0, 'Calcium-sensing receptors on chief cells detect falling ionized calcium and respond by increasing PTH secretion; PTH secretion is inversely related to serum calcium under normal physiology.', 'Pre-Council', '🎓', true),
(6225, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Parathyroid hormone raises serum calcium through which combination of actions?', '["Increased bone resorption, increased renal calcium reabsorption, and increased renal activation of vitamin D", "Decreased bone resorption and decreased renal calcium reabsorption", "Increased renal phosphate reabsorption and decreased vitamin D activation", "Direct intestinal calcium absorption without involving vitamin D"]'::jsonb, 0, 'PTH raises serum calcium by stimulating osteoclastic bone resorption, enhancing distal renal tubular calcium reabsorption, and stimulating renal 1-alpha-hydroxylase to convert vitamin D to its active form (calcitriol), which increases intestinal calcium absorption.', 'Pre-Council', '🎓', true),
(6226, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient develops severe hypocalcemia with perioral tingling, muscle cramps, and a positive Chvostek sign after total thyroidectomy. Which complication is most likely?', '["Inadvertent removal or devascularization of the parathyroid glands", "Thyroid storm", "Recurrent laryngeal nerve injury", "Adrenal insufficiency"]'::jsonb, 0, 'The parathyroid glands are small and closely adherent to the thyroid; they can be inadvertently removed or have their blood supply disrupted during thyroidectomy, causing acute hypoparathyroidism and hypocalcemia.', 'Pre-Council', '🎓', true),
(6227, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Trousseau sign, used to assess for latent tetany in hypocalcemia, is elicited by which maneuver?', '["Inflating a blood pressure cuff above systolic pressure for several minutes, causing carpal spasm", "Tapping the facial nerve anterior to the ear", "Passive neck flexion causing hip flexion", "Percussing the patellar tendon"]'::jsonb, 0, 'Trousseau sign is induced by inflating a BP cuff above systolic pressure for roughly 3 minutes, causing ischemia-induced neuromuscular irritability that produces carpopedal spasm in hypocalcemic patients.', 'Pre-Council', '🎓', true),
(6228, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Chvostek sign, used to assess for hypocalcemia-induced neuromuscular irritability, is elicited by which maneuver?', '["Tapping the facial nerve just anterior to the ear, causing facial muscle twitching", "Inflating a blood pressure cuff on the arm", "Flexing the neck while supine", "Palpating the thyroid gland"]'::jsonb, 0, 'Chvostek sign is positive when tapping over the facial nerve near the parotid gland causes ipsilateral twitching of the facial muscles, reflecting increased neuromuscular excitability from hypocalcemia.', 'Pre-Council', '🎓', true),
(6229, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Primary hyperparathyroidism, most commonly caused by a solitary parathyroid adenoma, classically presents with which laboratory pattern?', '["Elevated serum calcium with elevated or inappropriately normal PTH", "Low serum calcium with elevated PTH", "Elevated serum calcium with suppressed PTH", "Low serum calcium with low PTH"]'::jsonb, 0, 'In primary hyperparathyroidism, autonomous PTH secretion (usually from an adenoma) causes hypercalcemia, and PTH is either frankly elevated or inappropriately normal despite the elevated calcium, distinguishing it from other causes of hypercalcemia.', 'Pre-Council', '🎓', true),
(6230, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Secondary hyperparathyroidism, commonly seen in chronic kidney disease, develops through which mechanism?', '["Chronic hypocalcemia and hyperphosphatemia from impaired renal vitamin D activation drive compensatory PTH elevation", "A parathyroid adenoma autonomously secreting excess PTH", "Autoimmune destruction of parathyroid tissue", "Excess dietary calcium intake"]'::jsonb, 0, 'In chronic kidney disease, reduced renal 1-alpha-hydroxylase activity lowers active vitamin D and calcium absorption, and phosphate retention further lowers calcium; the parathyroid glands compensate by chronically increasing PTH secretion, which can eventually become autonomous (tertiary hyperparathyroidism).', 'Pre-Council', '🎓', true),
(6231, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A critically ill patient with hypercalcemic crisis (severe hypercalcemia) is treated with which first-line intervention?', '["Aggressive isotonic saline hydration followed by consideration of calcitonin and bisphosphonates", "Immediate calcium gluconate infusion", "Fluid restriction and diuretic-free management", "High-dose oral calcium carbonate"]'::jsonb, 0, 'Severe hypercalcemia is treated first with aggressive IV isotonic saline to restore volume and promote renal calcium excretion, followed by calcitonin for rapid but short-lived effect and bisphosphonates for sustained lowering of calcium via osteoclast inhibition.', 'Pre-Council', '🎓', true),
(6232, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which ECG change is classically associated with hypercalcemia?', '["Shortened QT interval", "Prolonged QT interval", "Peaked T waves", "Prominent U waves"]'::jsonb, 0, 'Hypercalcemia shortens the cardiac action potential plateau phase, producing a shortened QT interval on ECG, in contrast to hypocalcemia, which prolongs the QT interval.', 'Pre-Council', '🎓', true),
(6233, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The adrenal glands are located in which anatomical position?', '["Superior to each kidney, retroperitoneally", "Inferior to each kidney", "Anterior to the pancreas within the peritoneal cavity", "Within the renal medulla itself"]'::jsonb, 0, 'Each adrenal (suprarenal) gland sits atop the superior pole of the corresponding kidney within the retroperitoneum, enclosed within the renal (Gerota''s) fascia.', 'Pre-Council', '🎓', true),
(6234, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The adrenal gland is composed of two functionally and embryologically distinct regions. What are they?', '["An outer cortex derived from mesoderm and an inner medulla derived from neural crest", "An outer medulla and an inner cortex, both derived from ectoderm", "Two identical cortical layers with no medulla", "An outer capsule of neural tissue surrounding a mesodermal core"]'::jsonb, 0, 'The adrenal cortex arises from mesoderm and produces steroid hormones, while the adrenal medulla arises from neural crest cells (modified sympathetic postganglionic neurons) and produces catecholamines.', 'Pre-Council', '🎓', true),
(6235, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'From outermost to innermost, what is the correct order of the three zones of the adrenal cortex?', '["Zona glomerulosa, zona fasciculata, zona reticularis", "Zona fasciculata, zona glomerulosa, zona reticularis", "Zona reticularis, zona fasciculata, zona glomerulosa", "Zona glomerulosa, zona reticularis, zona fasciculata"]'::jsonb, 0, 'A helpful mnemonic is ''GFR'' (salt, sugar, sex) from outside in: zona Glomerulosa (mineralocorticoids), zona Fasciculata (glucocorticoids), zona Reticularis (androgens).', 'Pre-Council', '🎓', true),
(6236, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which zone of the adrenal cortex is primarily responsible for secreting aldosterone?', '["Zona glomerulosa", "Zona fasciculata", "Zona reticularis", "Adrenal medulla"]'::jsonb, 0, 'The outermost zona glomerulosa uniquely expresses aldosterone synthase, allowing it to produce the mineralocorticoid aldosterone in response to angiotensin II and serum potassium.', 'Pre-Council', '🎓', true),
(6237, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which zone of the adrenal cortex is primarily responsible for secreting cortisol?', '["Zona fasciculata", "Zona glomerulosa", "Zona reticularis", "Adrenal medulla"]'::jsonb, 0, 'The middle zona fasciculata is the thickest cortical layer and, under ACTH stimulation, is the primary site of glucocorticoid (cortisol) synthesis.', 'Pre-Council', '🎓', true),
(6238, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Aldosterone acts on the renal distal tubule and collecting duct to produce which net effect?', '["Sodium and water reabsorption with potassium and hydrogen ion excretion", "Sodium excretion with potassium retention", "Water excretion without affecting sodium or potassium", "Calcium reabsorption with phosphate excretion"]'::jsonb, 0, 'Aldosterone upregulates epithelial sodium channels (ENaC) and Na+/K+-ATPase in principal cells, promoting sodium (and secondarily water) reabsorption while enhancing potassium and hydrogen ion secretion, which raises blood pressure and can cause hypokalemic alkalosis when in excess.', 'Pre-Council', '🎓', true),
(6239, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following is a well-recognized physiologic effect of cortisol?', '["Stimulation of hepatic gluconeogenesis and insulin resistance in peripheral tissues", "Direct stimulation of insulin secretion from pancreatic beta cells", "Lowering of blood glucose", "Suppression of gluconeogenesis"]'::jsonb, 0, 'Cortisol is a counter-regulatory hormone that raises blood glucose by stimulating hepatic gluconeogenesis, promoting peripheral insulin resistance, and mobilizing amino acids and fatty acids as gluconeogenic substrates.', 'Pre-Council', '🎓', true),
(6240, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In the physiologic stress response of critical illness, cortisol plays which essential role?', '["It permits and potentiates the vasoconstrictive effects of catecholamines and supports vascular tone", "It suppresses catecholamine receptor expression, worsening hypotension", "It has no cardiovascular role and acts only on glucose metabolism", "It directly increases parasympathetic tone"]'::jsonb, 0, 'Cortisol has a permissive effect on catecholamines, upregulating and maintaining adrenergic receptor responsiveness in vascular smooth muscle; this is why relative adrenal insufficiency in critical illness can manifest as vasopressor-refractory shock.', 'Pre-Council', '🎓', true),
(6241, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A critically ill patient in septic shock remains hypotensive despite adequate fluid resuscitation and high-dose vasopressors. Which endocrine abnormality should be considered and evaluated?', '["Critical illness-related corticosteroid insufficiency (relative adrenal insufficiency)", "Primary hyperaldosteronism", "Hyperthyroidism", "Growth hormone excess"]'::jsonb, 0, 'Critical illness-related corticosteroid insufficiency can occur in septic shock due to impaired cortisol synthesis/release or tissue resistance; vasopressor-refractory shock is a classic clinical clue, and stress-dose hydrocortisone may improve hemodynamics.', 'Pre-Council', '🎓', true),
(6242, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Addison disease (primary adrenal insufficiency) is characterized by deficiency of which hormones?', '["Both cortisol and aldosterone, due to destruction of the entire adrenal cortex", "Cortisol only, with normal aldosterone", "Aldosterone only, with normal cortisol", "Catecholamines only"]'::jsonb, 0, 'Primary adrenal insufficiency (Addison disease) most often results from autoimmune destruction of the entire adrenal cortex, causing combined glucocorticoid and mineralocorticoid deficiency, unlike secondary adrenal insufficiency (pituitary/ACTH failure), which spares aldosterone.', 'Pre-Council', '🎓', true),
(6243, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which electrolyte abnormality pattern is classically associated with primary adrenal insufficiency due to combined cortisol and aldosterone deficiency?', '["Hyponatremia and hyperkalemia", "Hypernatremia and hypokalemia", "Hyponatremia and hypokalemia", "Normal sodium with hyperkalemia only"]'::jsonb, 0, 'Aldosterone deficiency causes renal sodium wasting and potassium retention (hyponatremia, hyperkalemia), while cortisol deficiency contributes to hyponatremia via impaired free water clearance and loss of cortisol''s normal permissive vascular effects.', 'Pre-Council', '🎓', true),
(6244, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Acute adrenal (Addisonian) crisis is a life-threatening emergency best managed with immediate administration of which agent, alongside aggressive fluid resuscitation?', '["IV hydrocortisone", "Oral fludrocortisone only", "IV insulin", "IV levothyroxine"]'::jsonb, 0, 'Adrenal crisis requires immediate IV stress-dose hydrocortisone (which also has mineralocorticoid activity at high doses) plus aggressive isotonic saline and dextrose administration to correct hypotension and hypoglycemia; delay in treatment can be fatal.', 'Pre-Council', '🎓', true),
(6245, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Cushing syndrome results from chronic excess exposure to which hormone?', '["Cortisol", "Aldosterone", "Growth hormone", "Thyroid hormone"]'::jsonb, 0, 'Cushing syndrome refers to the clinical state of chronic glucocorticoid excess, whether from a pituitary ACTH-secreting adenoma (Cushing disease), ectopic ACTH, an adrenal tumor, or exogenous corticosteroid use.', 'Pre-Council', '🎓', true),
(6246, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following distinguishes Cushing disease from Cushing syndrome?', '["Cushing disease specifically refers to Cushing syndrome caused by an ACTH-secreting pituitary adenoma", "Cushing disease refers only to exogenous steroid use", "Cushing syndrome and Cushing disease are interchangeable terms with no distinction", "Cushing disease refers to primary adrenal tumors only"]'::jsonb, 0, 'Cushing syndrome is the umbrella term for any cause of glucocorticoid excess; Cushing disease is specifically the subset caused by a pituitary corticotroph adenoma that hypersecretes ACTH.', 'Pre-Council', '🎓', true),
(6247, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Primary hyperaldosteronism (Conn syndrome) classically presents with which combination of findings?', '["Hypertension, hypokalemia, and metabolic alkalosis with suppressed plasma renin", "Hypotension, hyperkalemia, and metabolic acidosis with elevated renin", "Normal blood pressure with hyperkalemia", "Hypertension with elevated renin and elevated aldosterone"]'::jsonb, 0, 'Autonomous aldosterone excess causes sodium/water retention (hypertension), renal potassium wasting (hypokalemia), and hydrogen ion loss (metabolic alkalosis), while the elevated aldosterone suppresses renin via negative feedback, producing a low renin-to-aldosterone ratio.', 'Pre-Council', '🎓', true),
(6248, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The adrenal medulla is functionally equivalent to which type of tissue?', '["A modified sympathetic ganglion that secretes catecholamines directly into the bloodstream", "Parasympathetic ganglion tissue", "Endocrine tissue unrelated to the autonomic nervous system", "Somatic motor neuron tissue"]'::jsonb, 0, 'The adrenal medulla consists of chromaffin cells that are essentially modified postganglionic sympathetic neurons lacking axons, releasing epinephrine and norepinephrine directly into systemic circulation upon sympathetic (preganglionic) stimulation.', 'Pre-Council', '🎓', true),
(6249, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A pheochromocytoma, a catecholamine-secreting tumor of the adrenal medulla, classically presents with which triad of symptoms?', '["Episodic headache, palpitations, and diaphoresis with paroxysmal hypertension", "Chronic fatigue, weight gain, and cold intolerance", "Polyuria, polydipsia, and weight loss", "Bone pain, kidney stones, and abdominal pain"]'::jsonb, 0, 'Pheochromocytoma classically causes episodic catecholamine surges producing the triad of headache, palpitations, and sweating, often with paroxysmal severe hypertension, due to excess epinephrine and norepinephrine release.', 'Pre-Council', '🎓', true),
(6250, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Why is high local cortisol concentration from the adrenal cortex physiologically important to the adjacent adrenal medulla?', '["It induces the enzyme PNMT, which converts norepinephrine to epinephrine", "It directly inhibits catecholamine synthesis", "It stimulates aldosterone synthase in the medulla", "It has no functional relationship to the medulla"]'::jsonb, 0, 'The unique corticomedullary portal blood flow exposes the medulla to high local cortisol concentrations from the cortex, which induces PNMT expression, explaining why the adrenal medulla (unlike extra-adrenal sympathetic tissue) preferentially produces epinephrine.', 'Pre-Council', '🎓', true),
(6251, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which mechanism describes how catecholamines (epinephrine and norepinephrine) exert their rapid cellular effects?', '["Binding cell-surface adrenergic receptors coupled to G-proteins, triggering second messenger cascades", "Binding intracellular nuclear receptors that alter gene transcription", "Direct diffusion across the cell membrane to act on mitochondria", "Binding receptor tyrosine kinases like insulin"]'::jsonb, 0, 'Catecholamines are hydrophilic amines that cannot cross the cell membrane; they act via cell-surface alpha- and beta-adrenergic G-protein coupled receptors, producing rapid effects through second messengers such as cAMP or IP3/calcium.', 'Pre-Council', '🎓', true),
(6252, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The endocrine portion of the pancreas responsible for hormone secretion is organized into clusters of cells called:', '["Islets of Langerhans", "Acini", "Alveoli", "Follicles"]'::jsonb, 0, 'The islets of Langerhans are scattered clusters of hormone-secreting cells embedded within the predominantly exocrine pancreatic tissue, comprising only about 1-2% of total pancreatic mass.', 'Pre-Council', '🎓', true),
(6253, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which pancreatic islet cell type secretes insulin?', '["Beta cells", "Alpha cells", "Delta cells", "PP cells (F cells)"]'::jsonb, 0, 'Beta cells, the most numerous islet cell type and typically located centrally within the islet, synthesize and secrete insulin in response to rising blood glucose.', 'Pre-Council', '🎓', true),
(6254, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which pancreatic islet cell type secretes glucagon?', '["Alpha cells", "Beta cells", "Delta cells", "PP cells"]'::jsonb, 0, 'Alpha cells, located peripherally within the islet, secrete glucagon in response to falling blood glucose, opposing the action of insulin to raise blood glucose.', 'Pre-Council', '🎓', true),
(6255, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which pancreatic islet cell type secretes somatostatin, which locally inhibits both insulin and glucagon secretion?', '["Delta cells", "Alpha cells", "Beta cells", "PP cells"]'::jsonb, 0, 'Delta cells secrete somatostatin, which acts in a paracrine fashion within the islet to suppress both insulin and glucagon release, helping to fine-tune the overall hormonal response.', 'Pre-Council', '🎓', true),
(6256, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'What is the primary physiologic stimulus for insulin secretion from pancreatic beta cells?', '["Rising blood glucose concentration", "Falling blood glucose concentration", "Rising blood glucagon", "Falling serum calcium"]'::jsonb, 0, 'Elevated blood glucose enters beta cells via GLUT2 transporters, is metabolized to raise intracellular ATP, closes ATP-sensitive potassium channels, depolarizes the cell membrane, opens voltage-gated calcium channels, and triggers insulin exocytosis.', 'Pre-Council', '🎓', true),
(6257, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which intracellular mechanism directly triggers insulin exocytosis from pancreatic beta cells after glucose metabolism raises ATP levels?', '["Closure of ATP-sensitive potassium (K-ATP) channels, membrane depolarization, and calcium influx", "Opening of ATP-sensitive potassium channels causing hyperpolarization", "Direct binding of glucose to insulin granules", "Activation of the sodium-iodide symporter"]'::jsonb, 0, 'Rising intracellular ATP from glucose metabolism closes K-ATP channels, causing membrane depolarization that opens voltage-gated calcium channels; the resulting calcium influx triggers fusion of insulin-containing granules with the cell membrane.', 'Pre-Council', '🎓', true),
(6258, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Sulfonylurea medications lower blood glucose in type 2 diabetes through which mechanism?', '["Closing ATP-sensitive potassium channels on beta cells to stimulate insulin release independent of glucose levels", "Increasing peripheral insulin sensitivity", "Inhibiting hepatic gluconeogenesis", "Delaying carbohydrate absorption in the gut"]'::jsonb, 0, 'Sulfonylureas bind the SUR1 subunit of the K-ATP channel, directly closing it and triggering beta-cell depolarization and insulin release regardless of ambient glucose, which is why they carry a risk of hypoglycemia.', 'Pre-Council', '🎓', true),
(6259, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Insulin binds which type of cell-surface receptor to exert its effects?', '["A receptor tyrosine kinase", "A G-protein coupled receptor", "An intracellular nuclear receptor", "A ligand-gated ion channel"]'::jsonb, 0, 'The insulin receptor is a receptor tyrosine kinase; insulin binding triggers autophosphorylation and activation of downstream signaling cascades (including PI3K-Akt) that mediate glucose uptake and metabolic effects.', 'Pre-Council', '🎓', true),
(6260, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which glucose transporter is primarily responsible for insulin-stimulated glucose uptake into skeletal muscle and adipose tissue?', '["GLUT4", "GLUT1", "GLUT2", "GLUT3"]'::jsonb, 0, 'GLUT4 is the insulin-responsive glucose transporter; insulin signaling causes translocation of GLUT4-containing vesicles to the cell membrane in skeletal muscle and adipose tissue, increasing glucose uptake.', 'Pre-Council', '🎓', true),
(6261, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'What is the overall metabolic effect of insulin on the body?', '["An anabolic hormone that promotes glucose uptake, glycogen synthesis, lipogenesis, and protein synthesis while lowering blood glucose", "A catabolic hormone that raises blood glucose", "A hormone that has no effect on lipid metabolism", "A hormone that solely regulates calcium homeostasis"]'::jsonb, 0, 'Insulin is the primary anabolic hormone, lowering blood glucose by promoting cellular glucose uptake and simultaneously stimulating glycogen, protein, and fat synthesis while inhibiting their breakdown.', 'Pre-Council', '🎓', true),
(6262, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Glucagon''s primary physiologic effects on the liver include which of the following?', '["Stimulation of glycogenolysis and gluconeogenesis to raise blood glucose", "Stimulation of glycogen synthesis to lower blood glucose", "Inhibition of gluconeogenesis", "Direct stimulation of peripheral glucose uptake"]'::jsonb, 0, 'Glucagon acts on hepatocytes via a G-protein coupled receptor to activate cAMP-dependent pathways that stimulate glycogen breakdown and new glucose synthesis, raising blood glucose during fasting or hypoglycemia.', 'Pre-Council', '🎓', true),
(6263, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In diabetic ketoacidosis (DKA), the combination of absolute insulin deficiency and excess counter-regulatory hormones (glucagon, catecholamines, cortisol) leads to which metabolic derangement?', '["Unrestrained lipolysis with hepatic ketogenesis, causing hyperglycemia, ketonemia, and metabolic acidosis", "Excess insulin action causing hypoglycemia and lactic acidosis", "Isolated hyperglycemia without ketone production", "Primary respiratory alkalosis without metabolic derangement"]'::jsonb, 0, 'Without insulin to suppress lipolysis, free fatty acids flood the liver and are converted to ketone bodies (beta-hydroxybutyrate, acetoacetate) via unopposed glucagon-driven ketogenesis, producing the hyperglycemia, ketosis, and anion-gap metabolic acidosis that define DKA.', 'Pre-Council', '🎓', true),
(6264, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Why does diabetic ketoacidosis typically occur in type 1 diabetes but is less common (though possible) in type 2 diabetes?', '["Type 1 diabetes involves near-total beta-cell destruction and absolute insulin deficiency, removing the residual insulin needed to suppress lipolysis and ketogenesis", "Type 2 diabetics have higher glucagon levels that prevent ketosis", "Type 1 diabetics have excess residual insulin", "Ketogenesis requires functioning beta cells"]'::jsonb, 0, 'Type 2 diabetes usually retains some residual endogenous insulin secretion, which is enough to suppress excessive lipolysis and ketogenesis even amid insulin resistance and hyperglycemia, whereas type 1 diabetes involves absolute insulin deficiency that removes this protective effect.', 'Pre-Council', '🎓', true),
(6265, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient in DKA is treated with an IV insulin infusion. Which electrolyte requires close monitoring and often supplementation because insulin drives it intracellularly, risking severe hypokalemia despite normal or high initial serum levels?', '["Potassium", "Sodium", "Calcium", "Chloride"]'::jsonb, 0, 'Insulin stimulates Na+/K+-ATPase activity, driving potassium into cells; although total body potassium is often depleted in DKA from osmotic diuresis, serum potassium may initially appear normal or elevated, and insulin therapy can precipitate dangerous hypokalemia if not corrected proactively.', 'Pre-Council', '🎓', true),
(6266, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Hyperosmolar hyperglycemic state (HHS) differs from DKA primarily in which way?', '["HHS typically features more severe hyperglycemia with minimal or absent ketosis/acidosis, usually in type 2 diabetes with some residual insulin", "HHS always presents with severe ketoacidosis", "HHS occurs exclusively in type 1 diabetes", "HHS is characterized by hypoglycemia"]'::jsonb, 0, 'HHS occurs mainly in type 2 diabetes where residual insulin secretion is sufficient to suppress ketogenesis but not to prevent severe hyperglycemia and profound osmotic dehydration, distinguishing it from the ketotic, acidotic picture of DKA.', 'Pre-Council', '🎓', true),
(6267, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Incretin hormones such as GLP-1, secreted by the gut in response to oral nutrient intake, enhance insulin secretion through which phenomenon?', '["The incretin effect, where oral glucose provokes a greater insulin response than an equivalent IV glucose load", "Direct destruction of pancreatic alpha cells", "Suppression of all pancreatic hormone secretion", "Inhibition of the K-ATP channel independent of glucose"]'::jsonb, 0, 'The incretin effect describes how gut-derived hormones like GLP-1 and GIP amplify glucose-stimulated insulin secretion after oral intake compared to the same glucose level achieved intravenously, a principle exploited by GLP-1 receptor agonist medications.', 'Pre-Council', '🎓', true),
(6268, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Stress hyperglycemia commonly observed in critically ill, nondiabetic ICU patients is primarily driven by which mechanism?', '["Elevated counter-regulatory stress hormones (cortisol, catecholamines, glucagon) causing insulin resistance and increased hepatic glucose production", "Absolute insulin deficiency from beta-cell destruction", "Excess GLP-1 secretion", "Primary hypothyroidism"]'::jsonb, 0, 'Acute illness triggers a surge in cortisol, catecholamines, and glucagon, which increase hepatic gluconeogenesis/glycogenolysis and induce peripheral insulin resistance, producing hyperglycemia even in patients without pre-existing diabetes.', 'Pre-Council', '🎓', true),
(6269, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cells within the testes are primarily responsible for testosterone synthesis?', '["Leydig (interstitial) cells", "Sertoli cells", "Spermatogonia", "Germ cells"]'::jsonb, 0, 'Leydig cells, located in the interstitial tissue between seminiferous tubules, produce testosterone in response to luteinizing hormone (LH) stimulation.', 'Pre-Council', '🎓', true),
(6270, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which testicular cells support spermatogenesis and secrete inhibin, which provides negative feedback on FSH?', '["Sertoli cells", "Leydig cells", "Interstitial cells", "Chief cells"]'::jsonb, 0, 'Sertoli cells line the seminiferous tubules, nourish developing sperm, form the blood-testis barrier, and secrete inhibin, which selectively suppresses FSH secretion from the anterior pituitary.', 'Pre-Council', '🎓', true),
(6271, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In the male hypothalamic-pituitary-gonadal axis, LH primarily stimulates which testicular process?', '["Testosterone production by Leydig cells", "Spermatogenesis directly by acting on Sertoli cells", "Inhibin secretion", "Sperm maturation in the epididymis"]'::jsonb, 0, 'LH binds receptors on Leydig cells to stimulate testosterone synthesis; FSH, in contrast, acts on Sertoli cells to support spermatogenesis, with testosterone also required locally for full spermatogenic support.', 'Pre-Council', '🎓', true),
(6272, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which cells within the ovary primarily secrete estrogen during the follicular phase of the menstrual cycle?', '["Granulosa cells (with theca cell cooperation)", "Corpus luteum cells exclusively", "Oocytes themselves", "Ovarian stromal cells only"]'::jsonb, 0, 'Under the two-cell, two-gonadotropin model, LH stimulates theca cells to produce androgens, which are transferred to granulosa cells and converted to estrogen (via aromatase) under FSH stimulation.', 'Pre-Council', '🎓', true),
(6273, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'After ovulation, the ruptured follicle transforms into the corpus luteum, which primarily secretes which hormone to support early pregnancy or the luteal phase?', '["Progesterone", "FSH", "Estrogen exclusively without progesterone", "Oxytocin"]'::jsonb, 0, 'The corpus luteum secretes progesterone (along with some estrogen) under LH support, maintaining the endometrium for potential implantation; if pregnancy occurs, hCG from the developing placenta sustains the corpus luteum.', 'Pre-Council', '🎓', true),
(6274, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which mechanism describes how sex steroid hormones (testosterone, estrogen, progesterone) exert their primary cellular effects?', '["Binding intracellular/nuclear steroid receptors that regulate gene transcription", "Binding cell-surface G-protein coupled receptors exclusively", "Acting as ligand-gated ion channels", "Binding receptor tyrosine kinases"]'::jsonb, 0, 'As lipophilic steroid hormones, sex steroids diffuse across the cell membrane and bind intracellular nuclear receptors, and the hormone-receptor complex acts as a transcription factor to regulate target gene expression.', 'Pre-Council', '🎓', true),
(6275, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Negative feedback in the hypothalamic-pituitary-gonadal axis in men occurs when rising testosterone levels suppress which hypothalamic/pituitary hormones?', '["GnRH and LH", "TRH and TSH", "CRH and ACTH", "GHRH and GH"]'::jsonb, 0, 'Rising testosterone feeds back to suppress hypothalamic GnRH pulsatility and pituitary LH secretion, maintaining testosterone within a physiologic range, while inhibin from Sertoli cells selectively suppresses FSH.', 'Pre-Council', '🎓', true),
(6276, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Testosterone plays which of the following roles in male physiology beyond reproductive function?', '["Promotes protein anabolism, muscle mass, bone density, and secondary sexual characteristics", "Primarily promotes fat storage and decreases muscle mass", "Has no effect on bone metabolism", "Solely regulates spermatogenesis with no systemic effects"]'::jsonb, 0, 'Beyond its reproductive role, testosterone is anabolic, promoting skeletal muscle protein synthesis, bone mineral density, and development/maintenance of secondary sexual characteristics such as voice deepening and facial hair.', 'Pre-Council', '🎓', true),
(6277, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Estrogen''s effects on bone metabolism are best described by which statement, relevant to postmenopausal osteoporosis risk?', '["Estrogen inhibits osteoclast activity, and its decline after menopause accelerates bone resorption and bone loss", "Estrogen stimulates osteoclast activity, protecting against fractures", "Estrogen has no role in bone metabolism", "Estrogen only affects bone growth in adolescence, not adult bone turnover"]'::jsonb, 0, 'Estrogen normally restrains osteoclast-mediated bone resorption; the sharp decline in estrogen after menopause removes this restraint, accelerating bone loss and significantly increasing osteoporosis and fracture risk.', 'Pre-Council', '🎓', true),
(6278, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which gonadotropin surge directly triggers ovulation at approximately day 14 of a typical 28-day menstrual cycle?', '["A surge in luteinizing hormone (LH)", "A surge in FSH alone without LH involvement", "A surge in progesterone", "A surge in GnRH from the ovary"]'::jsonb, 0, 'Rising estrogen from the dominant follicle eventually exerts positive feedback on the hypothalamic-pituitary axis, triggering a mid-cycle LH surge (with a smaller FSH surge) that induces final oocyte maturation and ovulation.', 'Pre-Council', '🎓', true),
(6279, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'The pineal gland is located in which anatomical position?', '["Deep within the brain, near the posterior aspect of the third ventricle", "Within the sella turcica alongside the pituitary", "In the anterior neck alongside the thyroid", "Retroperitoneally above the kidney"]'::jsonb, 0, 'The pineal gland is a small, midline structure located near the posterior wall of the third ventricle, between the two thalami, and is part of the epithalamus.', 'Pre-Council', '🎓', true),
(6280, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which hormone is primarily secreted by the pineal gland?', '["Melatonin", "Oxytocin", "Cortisol", "Somatostatin"]'::jsonb, 0, 'The pineal gland synthesizes and secretes melatonin from serotonin, primarily during darkness, playing a central role in regulating circadian rhythm and sleep-wake cycles.', 'Pre-Council', '🎓', true),
(6281, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Melatonin secretion by the pineal gland is regulated by which of the following?', '["Light exposure, via a pathway from the retina to the suprachiasmatic nucleus that suppresses secretion during light and permits it during darkness", "TSH stimulation, similar to thyroid hormone regulation", "Direct stimulation by ACTH", "Serum calcium levels"]'::jsonb, 0, 'Environmental light detected by the retina is relayed via the retinohypothalamic tract to the suprachiasmatic nucleus, which inhibits pineal melatonin secretion during light exposure and permits its rise during darkness, entraining circadian rhythm.', 'Pre-Council', '🎓', true),
(6282, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following is a recognized physiologic role of melatonin?', '["Regulation of sleep-wake cycles and circadian rhythm entrainment", "Direct regulation of blood glucose as a primary counter-regulatory hormone", "Stimulation of adrenal cortisol secretion", "Direct regulation of serum calcium"]'::jsonb, 0, 'Melatonin''s best-established role is synchronizing the body''s internal circadian clock with the external light-dark cycle, promoting sleep onset as levels rise in the evening and influencing other rhythmic physiologic processes.', 'Pre-Council', '🎓', true),
(6283, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Critically ill ICU patients frequently experience disrupted sleep-wake cycles and delirium, which has been linked in part to disturbance of which endocrine rhythm?', '["Disrupted melatonin secretion due to continuous lighting, noise, and altered environmental cues", "Excess parathyroid hormone secretion", "Suppressed insulin secretion", "Excess aldosterone secretion"]'::jsonb, 0, 'The ICU environment (continuous lighting, frequent interruptions, critical illness itself) disrupts normal light-dark cues needed for pineal melatonin rhythm, contributing to circadian disruption, sleep deprivation, and delirium risk.', 'Pre-Council', '🎓', true),
(6284, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Historically, the pineal gland was philosophically speculated by René Descartes to be the seat of the soul, in part because of which anatomical feature?', '["It is a single midline (unpaired) structure in the brain, unlike most paired cerebral structures", "It is the largest structure in the brain", "It lies outside the blood-brain barrier only", "It contains no glandular tissue"]'::jsonb, 0, 'Descartes was intrigued that the pineal gland, unlike most brain structures which are bilaterally paired, is a solitary midline structure, leading him to propose it as a unique point of interaction between mind and body.', 'Pre-Council', '🎓', true),
(6285, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Peptide and protein hormones (such as insulin, ACTH, and TSH) generally exert their effects through which mechanism, given their inability to cross the lipid cell membrane?', '["Binding cell-surface receptors that trigger intracellular second messenger systems", "Diffusing freely into the cell to bind nuclear receptors", "Direct covalent modification of intracellular enzymes without a receptor", "Binding directly to DNA"]'::jsonb, 0, 'Because peptide hormones are hydrophilic and cannot cross the lipid bilayer, they bind specific cell-surface receptors (often G-protein coupled or receptor tyrosine kinases), initiating intracellular signaling cascades such as cAMP or calcium-based second messengers.', 'Pre-Council', '🎓', true),
(6286, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Steroid hormones (such as cortisol, aldosterone, and sex steroids) share which common mechanism of action distinct from peptide hormones?', '["They diffuse across the cell membrane and bind intracellular/nuclear receptors to directly regulate gene transcription", "They exclusively use cell-surface receptors and cAMP", "They require binding to ion channels to function", "They act only through paracrine signaling, never entering the bloodstream"]'::jsonb, 0, 'Steroid hormones are lipophilic, allowing them to diffuse through the plasma membrane and bind intracellular receptors; the hormone-receptor complex then acts within the nucleus as a transcription factor, generally producing slower but more sustained effects than peptide hormones.', 'Pre-Council', '🎓', true),
(6287, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which statement best differentiates the onset and duration of action typically seen with steroid hormones compared to peptide/catecholamine hormones?', '["Steroid hormones generally have a slower onset but longer duration of action due to requiring new protein synthesis, while catecholamines act rapidly via existing signaling proteins", "Steroid hormones act within seconds and catecholamines take hours", "Both hormone classes have identical onset and duration profiles", "Peptide hormones always outlast steroid hormone effects"]'::jsonb, 0, 'Because steroid hormones alter gene transcription and require new protein synthesis, their effects have a slower onset (hours) but tend to be longer-lasting, whereas catecholamines acting through pre-existing receptor-signaling pathways produce effects within seconds to minutes.', 'Pre-Council', '🎓', true),
(6288, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Negative feedback is the predominant regulatory mechanism in most endocrine axes. Which best describes this concept?', '["Rising levels of the hormone (or downstream effect) suppress further secretion of the stimulating hormone, maintaining homeostasis", "Rising levels of a hormone always further stimulate its own secretion", "Feedback loops exist only at the level of the target organ, never the pituitary or hypothalamus", "Negative feedback applies only to steroid hormones, not peptide hormones"]'::jsonb, 0, 'Negative feedback is the fundamental self-regulating mechanism of most endocrine axes (e.g., HPA, HPT, HPG axes), where rising hormone or effector levels inhibit upstream stimulating hormones to prevent overproduction and maintain physiologic set points.', 'Pre-Council', '🎓', true),
(6289, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best describes ''positive feedback'' as it applies to endocrine physiology, using the menstrual cycle as an example?', '["Rising estrogen near ovulation stimulates further LH release rather than suppressing it, amplifying the response until ovulation occurs", "Positive feedback is synonymous with negative feedback in endocrinology", "Positive feedback never occurs physiologically and only reflects pathology", "Positive feedback describes a hormone inhibiting its own further release"]'::jsonb, 0, 'Positive feedback loops are less common but occur physiologically, such as the estrogen-driven LH surge preceding ovulation and oxytocin-driven uterine contractions during labor, where the response amplifies rather than dampens the initiating signal.', 'Pre-Council', '🎓', true),
(6290, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Down-regulation of hormone receptors, such as decreased insulin receptor sensitivity in states of chronic hyperinsulinemia, is best described as which phenomenon?', '["A reduction in receptor number or sensitivity in response to prolonged high hormone concentrations", "An increase in receptor number in response to low hormone levels", "A phenomenon unique to steroid hormone receptors only", "An irreversible, permanent loss of receptor function"]'::jsonb, 0, 'Down-regulation is an adaptive, generally reversible reduction in receptor number or sensitivity that occurs with chronically elevated hormone levels, functioning as a protective mechanism against receptor overstimulation, as seen in insulin resistance with chronic hyperinsulinemia.', 'Pre-Council', '🎓', true),
(6291, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which term describes a hormone or chemical messenger acting on nearby cells without entering the systemic circulation, such as somatostatin acting within the pancreatic islet?', '["Paracrine signaling", "Autocrine signaling", "Endocrine signaling", "Neurocrine signaling exclusively"]'::jsonb, 0, 'Paracrine signaling involves local diffusion of a signaling molecule to affect neighboring cells, as exemplified by somatostatin from pancreatic delta cells locally suppressing adjacent alpha and beta cell hormone secretion.', 'Pre-Council', '🎓', true),
(6292, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In critical illness, the acute stress response involves activation of multiple endocrine axes simultaneously. Which combination best reflects the classic acute neuroendocrine stress response?', '["Increased cortisol, catecholamines, and glucagon, with insulin resistance and often suppressed gonadal/thyroid axes", "Decreased cortisol and catecholamines with increased insulin sensitivity", "Isolated increase in aldosterone with no other hormonal changes", "Increased thyroid hormone and decreased cortisol"]'::jsonb, 0, 'The acute stress response is characterized by activation of the HPA axis (cortisol) and sympathoadrenal system (catecholamines) along with glucagon, promoting catabolism and hyperglycemia, while the hypothalamic-pituitary-gonadal and, in prolonged illness, thyroid axes are often suppressed (sick euthyroid, hypogonadism of illness).', 'Pre-Council', '🎓', true),
(6293, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best explains why measuring ''free'' hormone levels (e.g., free T4, ionized calcium) is often more clinically meaningful than total hormone levels in critically ill patients?', '["Only the unbound, free fraction of a hormone is biologically active, and binding protein levels (e.g., albumin, TBG) are frequently altered in critical illness", "Total hormone levels are always more accurate regardless of clinical context", "Binding proteins have no influence on hormone activity", "Free hormone levels are only relevant for steroid hormones, not thyroid hormones"]'::jsonb, 0, 'Because only unbound hormone can interact with receptors, and critical illness commonly alters binding protein concentrations (e.g., low albumin, altered TBG), total hormone levels can be misleading, making free hormone measurement more clinically reliable.', 'Pre-Council', '🎓', true),
(6294, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A hormone''s mechanism of action via a G-protein coupled receptor linked to adenylate cyclase ultimately increases intracellular concentration of which second messenger?', '["Cyclic AMP (cAMP)", "Diacylglycerol (DAG) exclusively", "Nitric oxide", "Cyclic GMP exclusively"]'::jsonb, 0, 'Gs-coupled receptors activate adenylate cyclase, converting ATP to cAMP, which then activates protein kinase A to phosphorylate target proteins and mediate the hormone''s downstream effects, as seen with ACTH, TSH, glucagon, and ADH (V2 receptor) signaling.', 'Pre-Council', '🎓', true),
(6295, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following hormone axes is characterized by a ''long loop'' negative feedback where the peripheral gland hormone feeds back on both the hypothalamus and the pituitary?', '["The hypothalamic-pituitary-thyroid axis, where T3/T4 suppress both TRH and TSH", "A reflex arc involving only spinal cord pathways", "A purely local paracrine loop within a single gland", "A feedback loop that only involves the target organ, bypassing the brain entirely"]'::jsonb, 0, 'Classic endocrine axes such as HPT, HPA, and HPG demonstrate long-loop feedback, where the distal gland''s hormone (T3/T4, cortisol, sex steroids) circulates back to suppress both hypothalamic releasing hormone and pituitary tropic hormone secretion.', 'Pre-Council', '🎓', true),
(6296, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best describes the physiologic ''permissive effect'' of one hormone on another, using cortisol and catecholamines as an example?', '["Cortisol itself does not directly cause vasoconstriction but must be present at adequate levels for catecholamines to exert their full vasoconstrictive effect", "Permissive effect means cortisol directly binds catecholamine receptors", "Permissive effect describes cortisol completely replacing catecholamine function", "Permissive effect only applies to reproductive hormones"]'::jsonb, 0, 'A permissive effect occurs when one hormone, though not directly producing an effect itself, is required in the background for another hormone to exert its full physiologic action; cortisol''s permissive effect on catecholamine-induced vasoconstriction explains vasopressor-refractory hypotension in adrenal insufficiency.', 'Pre-Council', '🎓', true),
(6297, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best describes the general difference in speed of onset between neural (autonomic) control and endocrine (hormonal) control of body functions?', '["Neural control acts within milliseconds via direct synaptic transmission, while endocrine control acts more slowly (seconds to hours) via hormones traveling through the bloodstream", "Endocrine control is always faster than neural control", "Both systems have identical response times in all circumstances", "Neural control cannot influence endocrine glands"]'::jsonb, 0, 'Neural signals travel rapidly via direct synaptic connections producing near-instantaneous effects, whereas hormones must be synthesized, released, and travel through the bloodstream to reach target tissues, generally producing slower but often more sustained and widespread effects; the two systems are also tightly integrated, as in hypothalamic control of the pituitary.', 'Pre-Council', '🎓', true),
(6298, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with poorly controlled diabetes presents with fruity breath odor, Kussmaul respirations, and severe hyperglycemia. Kussmaul respirations occur as a compensatory response to which acid-base disturbance?', '["Metabolic acidosis, with deep rapid breathing to blow off CO2 and raise pH", "Respiratory acidosis", "Metabolic alkalosis", "Respiratory alkalosis"]'::jsonb, 0, 'In DKA, accumulation of ketoacids causes a high anion gap metabolic acidosis; Kussmaul respirations (deep, rapid breathing) are the respiratory system''s compensatory attempt to lower PaCO2 and partially correct the acidemia.', 'Pre-Council', '🎓', true),
(6299, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which hormone deficiency, if unrecognized preoperatively in a patient with chronic exogenous corticosteroid use, places the patient at risk for perioperative adrenal crisis?', '["Cortisol, due to HPA axis suppression from chronic exogenous glucocorticoid therapy", "Insulin", "Thyroid hormone", "Growth hormone"]'::jsonb, 0, 'Chronic exogenous glucocorticoid use suppresses the HPA axis via negative feedback, impairing the adrenal cortex''s ability to mount an appropriate stress response; abrupt discontinuation or major physiologic stress (surgery) without stress-dose steroid coverage can precipitate adrenal crisis.', 'Pre-Council', '🎓', true),
(6300, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with syndrome of inappropriate ADH secretion (SIADH) causing symptomatic hyponatremia is treated with fluid restriction. Which additional mechanism-based therapy directly antagonizes ADH''s renal action?', '["Vasopressin receptor antagonists (vaptans)", "Exogenous desmopressin (DDAVP)", "IV isotonic saline as first-line for all severities", "Loop diuretics as monotherapy without sodium replacement"]'::jsonb, 0, 'Vaptans (e.g., tolvaptan, conivaptan) selectively block V2 receptors in the renal collecting duct, directly antagonizing ADH''s water-retaining effect and promoting aquaresis (electrolyte-free water excretion) to correct hyponatremia in SIADH.', 'Pre-Council', '🎓', true),
(6301, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'How does cerebral salt wasting (CSW) differ from SIADH in a neurocritical care patient with hyponatremia, despite both presenting with concentrated urine and natriuresis?', '["CSW is associated with true volume depletion/hypovolemia, whereas SIADH occurs in a euvolemic or mildly hypervolemic state", "CSW causes hypervolemia while SIADH causes severe hypovolemia", "CSW and SIADH have identical volume status and are managed identically", "CSW never occurs with natriuresis"]'::jsonb, 0, 'Distinguishing volume status is key: cerebral salt wasting involves renal sodium and volume loss producing true hypovolemia (managed with salt and volume replacement), whereas SIADH is a euvolemic or slightly hypervolemic state managed with fluid restriction; misdiagnosis can lead to inappropriate fluid restriction in a volume-depleted CSW patient.', 'Pre-Council', '🎓', true),
(6302, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which statement best describes the role of insulin and counter-regulatory hormones in maintaining glucose homeostasis during prolonged fasting?', '["Falling insulin and rising glucagon, cortisol, and growth hormone promote glycogenolysis, gluconeogenesis, and lipolysis to maintain blood glucose", "Rising insulin alone maintains blood glucose during fasting", "Glucagon is suppressed while insulin rises during fasting", "Only catecholamines regulate glucose during fasting, with no role for insulin or glucagon"]'::jsonb, 0, 'During fasting, falling glucose reduces insulin secretion while stimulating glucagon, cortisol, growth hormone, and catecholamines, which together mobilize glycogen stores, stimulate gluconeogenesis from amino acids/glycerol, and promote lipolysis to sustain blood glucose and provide alternative fuel sources.', 'Pre-Council', '🎓', true),
(6303, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with long-standing type 1 diabetes develops recurrent severe hypoglycemia with reduced awareness of warning symptoms. Which pathophysiologic change most likely underlies this ''hypoglycemia unawareness''?', '["Impaired counter-regulatory glucagon and epinephrine responses from recurrent hypoglycemic episodes blunting the autonomic warning response", "Excess residual insulin secretion from the pancreas", "Increased cortisol secretion masking symptoms", "Increased glucagon secretion causing symptom suppression"]'::jsonb, 0, 'Recurrent hypoglycemia progressively blunts both the glucagon and epinephrine counter-regulatory responses and lowers the glycemic threshold for autonomic (adrenergic) warning symptoms, creating a vicious cycle of impaired awareness and increased risk of severe hypoglycemia.', 'Pre-Council', '🎓', true),
(6304, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which hormonal mechanism explains the polyuria seen in uncontrolled hyperglycemia (e.g., in diabetes mellitus), distinct from the ADH-related polyuria of diabetes insipidus?', '["Osmotic diuresis, where glucose exceeds the renal reabsorptive threshold and remains in the tubule, obligating water excretion", "Excess ADH secretion causing water loss", "Primary aldosterone deficiency", "Direct glucose-induced destruction of renal tubular cells"]'::jsonb, 0, 'When serum glucose exceeds the renal threshold (~180 mg/dL), glucose spills into the urine and acts as an osmotic agent, drawing water with it (osmotic diuresis) and producing polyuria, distinct from the ADH-deficiency mechanism of diabetes insipidus.', 'Pre-Council', '🎓', true),
(6305, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'In a critically ill patient, which combination of clinical and laboratory findings would most strongly suggest thyroid storm rather than simple sinus tachycardia from another cause?', '["Hyperthermia, markedly suppressed TSH with elevated free T4/T3, tachyarrhythmia, and altered mental status", "Normal TSH with normal free T4 and isolated tachycardia", "Elevated TSH with low free T4 and bradycardia", "Hypothermia with elevated TSH"]'::jsonb, 0, 'Thyroid storm is a clinical diagnosis supported by severe hyperthyroid biochemistry (suppressed TSH, markedly elevated free T4/T3) combined with systemic decompensation: hyperthermia, tachyarrhythmia (often atrial fibrillation), and CNS effects such as agitation or coma, often using scoring systems like the Burch-Wartofsky point scale.', 'Pre-Council', '🎓', true),
(6306, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best explains the physiologic rationale for administering high-dose iodine (e.g., Lugol''s solution) in the management of thyroid storm, and why it must be given after (not before) a thionamide?', '["High-dose iodine acutely blocks thyroid hormone release (Wolff-Chaikoff effect) but can transiently increase new hormone synthesis if given before a thionamide blocks synthesis", "Iodine has no direct effect on the thyroid gland", "Iodine is given only to replace losses from diaphoresis", "Iodine directly antagonizes peripheral thyroid hormone receptors"]'::jsonb, 0, 'High-dose iodine acutely inhibits thyroid hormone release via the Wolff-Chaikoff effect, but iodine is also a substrate for hormone synthesis; giving it before a thionamide (which blocks synthesis) can paradoxically fuel further hormone production, so thionamide is administered first.', 'Pre-Council', '🎓', true),
(6307, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best describes why critically ill patients with adrenal insufficiency are at risk for both hyperkalemia and hypoglycemia simultaneously?', '["Aldosterone deficiency impairs renal potassium excretion while cortisol deficiency impairs gluconeogenesis and glycogen mobilization", "Excess aldosterone causes hyperkalemia while excess cortisol causes hypoglycemia", "Hyperkalemia and hypoglycemia are unrelated to adrenal hormone deficiency", "Cortisol deficiency causes hyperkalemia directly through renal tubular effects"]'::jsonb, 0, 'In primary adrenal insufficiency, aldosterone deficiency reduces renal potassium excretion (hyperkalemia), while cortisol deficiency impairs the counter-regulatory hepatic gluconeogenic and glycogenolytic response, predisposing to hypoglycemia, especially during physiologic stress.', 'Pre-Council', '🎓', true),
(6308, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best describes the clinical significance of an elevated anion gap in a patient later found to have diabetic ketoacidosis?', '["The elevated anion gap reflects accumulation of unmeasured ketoacid anions (beta-hydroxybutyrate and acetoacetate) in the blood", "The elevated anion gap reflects loss of bicarbonate from diarrhea", "An elevated anion gap always indicates renal failure regardless of ketones", "The anion gap is unrelated to ketoacidosis"]'::jsonb, 0, 'In DKA, the accumulating ketoacids dissociate into hydrogen ions and unmeasured anions (beta-hydroxybutyrate, acetoacetate), consuming bicarbonate buffer and widening the anion gap, a hallmark of this high anion gap metabolic acidosis.', 'Pre-Council', '🎓', true),
(6309, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best describes the action of ADH (vasopressin) at the V2 receptor within the renal collecting duct at the cellular level?', '["Activation of adenylate cyclase and cAMP leads to insertion of aquaporin-2 water channels into the apical membrane, increasing water permeability and reabsorption", "Direct opening of sodium channels without involving water channels", "Inhibition of aquaporin-2 channel insertion", "Direct stimulation of potassium secretion only"]'::jsonb, 0, 'ADH binding to V2 receptors activates a Gs-cAMP-protein kinase A pathway that promotes translocation of aquaporin-2 water channels to the apical membrane of collecting duct principal cells, increasing water permeability and allowing water reabsorption driven by the medullary osmotic gradient.', 'Pre-Council', '🎓', true),
(6310, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best describes why nephrogenic diabetes insipidus does not respond to exogenous desmopressin, unlike central diabetes insipidus?', '["In nephrogenic DI, the renal collecting duct is resistant to ADH due to receptor or aquaporin channel dysfunction, so exogenous ADH cannot correct the defect", "Nephrogenic DI patients lack functioning kidneys entirely", "Desmopressin is destroyed by renal enzymes only in nephrogenic DI", "Nephrogenic DI reflects excess ADH secretion rather than a renal defect"]'::jsonb, 0, 'Nephrogenic DI results from renal resistance to ADH (e.g., V2 receptor mutations, lithium toxicity, hypercalcemia) rather than a deficiency of the hormone itself, so administering more ADH (as desmopressin) fails to improve urine concentration, distinguishing it from central DI.', 'Pre-Council', '🎓', true),
(6311, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which of the following best characterizes acromegaly, a condition caused by excess growth hormone in adults after epiphyseal plate closure?', '["Progressive enlargement of hands, feet, and facial features (coarsening) along with soft tissue and organ overgrowth, without an increase in height", "Increased linear height growth similar to gigantism", "Decreased soft tissue growth with bone shrinkage", "No physical changes, only laboratory abnormalities"]'::jsonb, 0, 'Because epiphyseal growth plates have fused in adults, excess GH (usually from a pituitary adenoma) cannot cause increased height as in childhood gigantism; instead it causes acral (hands, feet) and soft tissue overgrowth, coarsened facial features, and organomegaly, often with associated insulin resistance.', 'Pre-Council', '🎓', true),
(6312, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best explains the physiologic basis for using dexamethasone suppression testing in the diagnostic workup of suspected Cushing syndrome?', '["Exogenous dexamethasone normally suppresses ACTH and cortisol via negative feedback in healthy individuals, but this suppression is characteristically blunted or absent in Cushing syndrome", "Dexamethasone directly measures adrenal gland size", "Dexamethasone stimulates cortisol production in normal individuals for comparison", "Dexamethasone suppression testing evaluates thyroid function, not adrenal function"]'::jsonb, 0, 'In normal physiology, exogenous glucocorticoid (dexamethasone) suppresses hypothalamic CRH and pituitary ACTH via negative feedback, lowering cortisol; in Cushing syndrome, autonomous cortisol/ACTH production (from a tumor) fails to be adequately suppressed, forming the basis of the low-dose dexamethasone suppression test.', 'Pre-Council', '🎓', true),
(6313, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'A patient with an insulinoma (insulin-secreting pancreatic tumor) is most likely to present with which classic finding, described by Whipple''s triad?', '["Symptomatic hypoglycemia with a low plasma glucose documented during symptoms, relieved by glucose administration", "Symptomatic hyperglycemia relieved by insulin administration", "Recurrent DKA episodes", "Hypertension with paroxysmal flushing"]'::jsonb, 0, 'Whipple''s triad (symptoms of hypoglycemia, a documented low plasma glucose concurrent with symptoms, and relief of symptoms after glucose administration) supports the diagnosis of an insulin-secreting tumor causing inappropriate, unregulated insulin release.', 'Pre-Council', '🎓', true),
(6314, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best describes why SGLT2 inhibitors (e.g., empagliflozin) lower blood glucose in type 2 diabetes, and a key associated risk in critically ill or fasting patients?', '["They block renal proximal tubule glucose reabsorption causing glucosuria, and can precipitate euglycemic diabetic ketoacidosis during illness or fasting", "They stimulate insulin secretion directly from beta cells, risking hypoglycemia", "They block glucagon receptors, risking hyperkalemia", "They have no associated risk in acute illness"]'::jsonb, 0, 'SGLT2 inhibitors block the SGLT2 transporter in the proximal renal tubule, reducing glucose reabsorption and promoting glucosuria; in the setting of illness, surgery, or fasting, they carry a recognized risk of euglycemic DKA, where ketoacidosis develops despite only mildly elevated or even normal blood glucose, which can delay diagnosis.', 'Pre-Council', '🎓', true),
(6315, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best describes the relationship between magnesium and parathyroid hormone (PTH) secretion, relevant to refractory hypocalcemia in critically ill patients?', '["Severe hypomagnesemia impairs PTH secretion and can cause functional hypoparathyroidism, so hypocalcemia may not correct until magnesium is repleted", "Magnesium has no relationship to PTH secretion", "Hypermagnesemia is required to stimulate PTH secretion", "Magnesium replacement always worsens hypocalcemia"]'::jsonb, 0, 'Severe hypomagnesemia both impairs PTH release from the parathyroid glands and induces peripheral PTH resistance, producing a functional hypoparathyroid state; hypocalcemia in this setting is often refractory to calcium replacement alone and requires correction of magnesium first.', 'Pre-Council', '🎓', true),
(6316, 'Endocrine System', 'CCN Curriculum — Applied Human Anatomy & Physiology', 'Which best describes the rationale for moderate (rather than tight) glycemic control targets in most critically ill ICU patients, based on landmark clinical trial evidence?', '["Tight glycemic control (e.g., targeting near-normal glucose) has been associated with increased risk of severe hypoglycemia without a consistent mortality benefit compared to moderate glucose targets", "Tight glycemic control has never been studied in critically ill patients", "Hyperglycemia has no adverse effects in critical illness, so glucose control is unnecessary", "Moderate glucose targets always worsen outcomes compared to tight control"]'::jsonb, 0, 'Landmark trials (such as NICE-SUGAR) demonstrated that intensive/tight glycemic control increased the incidence of severe hypoglycemia and was associated with increased mortality compared with more moderate glucose targets, leading most critical care guidelines to recommend moderate glycemic targets rather than strict normoglycemia.', 'Pre-Council', '🎓', true);
